window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
window.COURSE_REGISTRY["nicet-fire-alarm"] = [
  {id:1, block:1, sec:"Detection Principles & Fire Science", q:"The fire tetrahedron adds a fourth element to the classic fire triangle. What is that fourth element?", opts:["Light (radiant) energy","Smoke production","A self-sustaining chemical chain reaction","Carbon monoxide gas"], correct:2, re:"The fire tetrahedron is fuel, heat, oxygen, plus the self-sustaining chemical chain reaction. Source: fire-science fundamentals (WFCA Fire Tetrahedron; NFPA 72 detection background)."},
  {id:2, block:1, sec:"Detection Principles & Fire Science", q:"Which three elements make up the basic fire triangle?", opts:["Smoke, heat, and flame","Ignition, ventilation, and fuel","Carbon, hydrogen, and oxygen","Fuel, oxygen, and heat"], correct:3, re:"The fire triangle is fuel, oxygen (oxidizer), and heat; removing any one extinguishes the fire. Source: fire-science fundamentals (Firesafe.org.uk; WFCA)."},
  {id:3, block:1, sec:"Detection Principles & Fire Science", q:"In the early stage of a typical fire, which detectable product usually appears FIRST?", opts:["Open flame","High heat","Invisible combustion particles / smoke","Structural collapse"], correct:2, re:"In the incipient stage, invisible aerosols and combustion particles appear before visible smoke, flame, or significant heat, which is why early-warning smoke detection responds first. Source: NFPA 72 detection principles; fire-stage fundamentals."},
  {id:4, block:1, sec:"Detection Principles & Fire Science", q:"A slow-developing fire that produces large smoke particles but little flame is best described as a:", opts:["Flashover fire","Flaming fire","Backdraft","Smoldering fire"], correct:3, re:"A smoldering fire burns slowly without flame and yields larger smoke particles; photoelectric detection responds best to it. Source: NFPA Smoke Alarm guidance; combustion fundamentals."},
  {id:5, block:1, sec:"Detection Principles & Fire Science", q:"Compared with smoldering fires, fast-flaming fires typically produce smoke particles that are:", opts:["Always invisible to all detectors","Larger in size","Smaller in size","Identical in size"], correct:2, re:"Flaming fires generate smaller smoke/combustion particles, to which ionization detection responds best; smoldering fires make larger particles. Source: NFPA smoke alarm technology guidance."},
  {id:6, block:1, sec:"Detection Principles & Fire Science", q:"The four general stages of fire development are usually listed as:", opts:["Flashover, smoldering, flaming, decay","Decay, incipient, growth, flashover","Incipient, growth, fully developed, decay","Ignition, flashover, suppression, overhaul"], correct:2, re:"Fire develops through incipient, growth, fully developed, and decay stages. Source: fire-behavior fundamentals (Phoenix Fire reference; NFPA detection background)."},
  {id:7, block:1, sec:"Detection Principles & Fire Science", q:"Heat from a fire is transferred by three modes. Which list correctly names all three?", opts:["Combustion, oxidation, pyrolysis","Ionization, photoelectric, beam","Conduction, convection, radiation","Ignition, propagation, extinguishment"], correct:2, re:"Heat transfer occurs by conduction, convection, and radiation; convection (rising hot gases) drives smoke to ceiling detectors. Source: fire-science fundamentals."},
  {id:8, block:1, sec:"Detection Principles & Fire Science", q:"Why are most spot-type smoke and heat detectors mounted on or near the ceiling?", opts:["To keep them out of reach of occupants","To reduce wiring length only","Because code prohibits wall mounting entirely","Because hot smoke and gases rise by convection and collect at the ceiling"], correct:3, re:"Buoyant hot smoke rises and forms a ceiling layer, so ceiling-area placement gives the earliest response. Source: NFPA 72 spot-detector placement rationale."},
  {id:9, block:1, sec:"Detection Principles & Fire Science", q:"The process in which a solid fuel is chemically decomposed by heat, releasing flammable vapors, is called:", opts:["Convection","Oxidation","Sublimation","Pyrolysis"], correct:3, re:"Pyrolysis is thermal decomposition of a fuel that releases combustible gases which then ignite. Source: fire-science fundamentals."},
  {id:10, block:1, sec:"Detection Principles & Fire Science", q:"Carbon monoxide (CO) is produced by a fire primarily as a result of:", opts:["Electrical arcing only","Complete combustion with excess oxygen","Incomplete combustion of carbon-based fuels","Water reacting with fuel"], correct:2, re:"CO is a product of incomplete combustion when oxygen is limited; it is a colorless, odorless toxic gas. Source: fire-chemistry fundamentals; CO detection background (NFPA 720/72)."},
  {id:11, block:1, sec:"Detection Principles & Fire Science", q:"The rapid, near-simultaneous ignition of most exposed combustible surfaces in a compartment is known as:", opts:["Backdraft","Pyrolysis","Rollover","Flashover"], correct:3, re:"Flashover is the transition when radiant heat ignites nearly all combustibles in a room almost at once. Source: fire-behavior fundamentals."},
  {id:12, block:1, sec:"Detection Principles & Fire Science", q:"Detection technologies generally sense one of three fire signatures. Which set lists those signatures?", opts:["Voltage, current, resistance","Speed, pressure, mass","Smoke (aerosols), heat, and radiant energy (flame)","Color, odor, and taste"], correct:2, re:"Automatic fire detectors respond to smoke/aerosols, heat, or radiant energy (flame) — the three principal fire signatures. Source: NFPA 72 detector classifications."},
  {id:13, block:1, sec:"Detection Principles & Fire Science", q:"In which order do the detectable fire signatures most commonly become available in a typical smoldering-then-flaming fire?", opts:["Heat, then flame, then smoke","Flame, then heat, then smoke","Heat, then smoke, then flame","Smoke, then flame, then high heat"], correct:3, re:"Smoke aerosols usually appear earliest, followed by flame and then significant heat as the fire grows; this drives the choice of detector for early warning. Source: NFPA 72 detection principles."},
  {id:14, block:1, sec:"Detection Principles & Fire Science", q:"Which statement about oxygen and combustion is correct?", opts:["Oxygen plays no role in fire","Combustion requires pure 100% oxygen","Normal air (about 21% oxygen) readily supports flaming combustion","Reducing oxygen always speeds up a fire"], correct:2, re:"Ordinary air (~21% O2) supports combustion; lowering the oxidizer concentration tends to suppress fire. Source: fire-science fundamentals."},
  {id:15, block:1, sec:"Detection Principles & Fire Science", q:"The lowest temperature at which a fuel gives off enough vapor to form an ignitable mixture in air is its:", opts:["Autoignition temperature","Boiling point","Flash point","Curie point"], correct:2, re:"Flash point is the minimum temperature at which a liquid produces enough vapor to flash when an ignition source is present. Source: fire-chemistry fundamentals."},
  {id:16, block:1, sec:"Detection Principles & Fire Science", q:"Which fire signature would a SMOKE detector NOT directly respond to?", opts:["Visible smoke particles","Invisible combustion aerosols","Radiant heat from a clean-burning flame producing little smoke","Smoldering combustion products"], correct:2, re:"Smoke detectors respond to airborne combustion particles; a clean, fast flame producing little smoke is better caught by a flame (radiant-energy) detector. Source: NFPA 72 detector selection."},
  {id:17, block:1, sec:"Detection Principles & Fire Science", q:"Selecting the proper detector type for a hazard depends mainly on:", opts:["The expected fire signature and the environment of the protected space","The color of the wall","The brand of control panel only","The day of the week installed"], correct:0, re:"Detector selection is based on the anticipated fire signature (smoke, heat, flame) and ambient conditions of the space. Source: NFPA 72 Chapter 17 detector selection guidance."},
  {id:18, block:1, sec:"Smoke Detectors", q:"An ionization smoke detector generally responds FASTEST to which type of fire?", opts:["Fast-flaming fires","Slow-smoldering fires","CO leaks without combustion","Overheated wiring without smoke"], correct:0, re:"Ionization detectors respond best to fast-flaming fires that produce small smoke particles. Source: NFPA smoke alarm technology guidance."},
  {id:19, block:1, sec:"Smoke Detectors", q:"A photoelectric smoke detector generally responds FASTEST to which type of fire?", opts:["Fast-flaming fires","Radiant flame only","Pure heat with no smoke","Slow-smoldering fires"], correct:3, re:"Photoelectric (light-scattering) detectors respond best to slow-smoldering fires that produce larger smoke particles. Source: NFPA smoke alarm technology guidance."},
  {id:20, block:1, sec:"Smoke Detectors", q:"The radioactive source used in a typical ionization smoke detector is:", opts:["Cobalt-60","Radium-226","Americium-241","Cesium-137"], correct:2, re:"Ionization smoke detectors use a small americium-241 alpha source (about 1 microcurie in residential units) to ionize air in the chamber. Source: ORAU/World Nuclear Association; ionization-detector references."},
  {id:21, block:1, sec:"Smoke Detectors", q:"How does smoke entering an ionization chamber trigger an alarm?", opts:["It increases the chamber current sharply","It heats the chamber to a set point","It generates a magnetic field","It attaches to ions and reduces the chamber current"], correct:3, re:"Smoke particles attach to the ionized air molecules, reducing the small steady current; the detector senses that drop and alarms. Source: ionization-detector operating principle (ORAU)."},
  {id:22, block:1, sec:"Smoke Detectors", q:"A photoelectric (light-scattering) smoke detector alarms when:", opts:["Smoke particles scatter light from the source onto the photosensor","Smoke cools the internal heater","A radioactive source decays faster","The chamber voltage drops to zero"], correct:0, re:"In a light-scattering photoelectric detector, smoke entering the chamber scatters the LED light onto a photosensor that is normally shielded from the beam, triggering the alarm. Source: photoelectric-detector operating principle."},
  {id:23, block:1, sec:"Smoke Detectors", q:"For best overall life-safety protection, NFPA guidance recommends:", opts:["Only ionization alarms","Removing smoke alarms from bedrooms","Only heat detectors","Both photoelectric and ionization technologies (or a combination unit)"], correct:3, re:"NFPA recommends using both ionization and photoelectric technologies, or combination alarms, because each responds better to different fire types. Source: NFPA Smoke Alarm guidance."},
  {id:24, block:1, sec:"Smoke Detectors", q:"A common nuisance-alarm source for IONIZATION detectors placed too close to a kitchen is:", opts:["Cooking aerosols and steam","Radiant heat only","Low humidity","Carbon monoxide alone"], correct:0, re:"Ionization units are prone to nuisance alarms from cooking vapors/steam, so they should be kept away from cooking appliances. Source: NFPA 72 placement guidance; smoke-alarm references."},
  {id:25, block:1, sec:"Smoke Detectors", q:"Under NFPA 72, the nominal (commonly accepted) spacing used as a guide for spot-type smoke detectors on smooth ceilings is about:", opts:["10 ft","20 ft","30 ft","75 ft"], correct:2, re:"Smoke detectors are not listed for spacing but are commonly applied at a nominal 30 ft spacing on smooth ceilings as a starting guide. Source: NFPA 72; ECMag detector-spacing article."},
  {id:26, block:1, sec:"Smoke Detectors", q:"A smoke detector mounted on a sidewall (not the ceiling) should generally have its top located:", opts:["Within 12 in. of the ceiling","At least 36 in. below the ceiling","On the floor","Exactly at mid-wall height only"], correct:0, re:"Wall-mounted spot smoke detectors are placed with the top within 12 in. of the ceiling so they reach the rising smoke layer. Source: NFPA 72 spot-detector mounting (UpCodes 907 / 17.7)."},
  {id:27, block:1, sec:"Smoke Detectors", q:"A ceiling-mounted spot smoke detector should be kept a minimum distance from a sidewall of at least:", opts:["1 in.","2 in.","4 in.","18 in."], correct:2, re:"NFPA 72 requires ceiling-mounted spot detectors to be at least 4 in. from a sidewall. Source: NFPA 72 spot-detector mounting (getsafeandsound; UpCodes)."},
  {id:28, block:1, sec:"Smoke Detectors", q:"Which detector type is BEST suited where very early warning of slow, smoldering electronics fires is needed in a data center?", opts:["Photoelectric or air-aspirating smoke detection","Fixed-temperature heat detector only","Single-action pull station","Rate-of-rise heat detector only"], correct:0, re:"Smoldering, low-energy fires produce larger particles and little heat early on, so photoelectric or high-sensitivity air-aspirating smoke detection is preferred over heat detectors. Source: NFPA 72 detector selection; VESDA application guidance."},
  {id:29, block:1, sec:"Smoke Detectors", q:"A 'combination' smoke detector commonly refers to a unit that:", opts:["Uses both ionization and photoelectric sensing","Combines a pull station and a horn","Detects only carbon dioxide","Has two power cords"], correct:0, re:"A combination smoke alarm incorporates both ionization and photoelectric sensing to respond well to both flaming and smoldering fires. Source: NFPA smoke alarm guidance."},
  {id:30, block:1, sec:"Smoke Detectors", q:"Which statement about ionization detectors is TRUE under current listings?", opts:["They are banned by NFPA 72 in all buildings","They require no maintenance ever","They detect only heat, not smoke","They are UL 268 listed and accepted under NFPA 72 for commercial use"], correct:3, re:"Ionization smoke detectors meet UL 268 and are accepted under NFPA 72; like all smoke detectors they require periodic functional and sensitivity testing. Source: NFPA 72; UL 268."},
  {id:31, block:1, sec:"Smoke Detectors", q:"Mounting a spot smoke detector directly in the high-velocity airflow of an HVAC supply diffuser is a problem because:", opts:["It looks unattractive","It converts it to a heat detector","It increases the radioactive source strength","Moving air can dilute or divert smoke away from the detector, delaying response"], correct:3, re:"Strong airflow near diffusers can keep smoke from reaching the sensing chamber, so detectors should be kept clear of direct supply airflow. Source: NFPA 72 location guidance."},
  {id:32, block:1, sec:"Smoke Detectors", q:"Smoke detectors used in a fire alarm SYSTEM (versus stand-alone alarms) are typically:", opts:["Powered only by a 9V battery with no monitoring","Prohibited from initiating notification","Required to contain no electronics","Connected to and monitored by a fire alarm control unit"], correct:3, re:"System smoke detectors connect to a fire alarm control unit that monitors them and initiates notification; stand-alone alarms are self-contained. Source: NFPA 72 system fundamentals."},
  {id:33, block:1, sec:"Smoke Detectors", q:"A duct smoke detector's PRIMARY purpose in an HVAC system is to:", opts:["Replace all area smoke detectors in the building","Provide general area coverage for occupants","Measure duct temperature for comfort","Detect smoke in the air handler and shut down/control the HVAC to limit smoke spread"], correct:3, re:"Duct smoke detectors sample air in HVAC ducts to detect smoke and shut down or control the system, preventing smoke distribution; they are not a substitute for area detection. Source: NFPA 72 / NFPA 90A duct-detector requirements."},
  {id:34, block:1, sec:"Smoke Detectors", q:"Sensitivity drift caused by dust accumulation in a smoke detector chamber is addressed by:", opts:["Periodic sensitivity testing and cleaning per NFPA 72","Painting over the detector","Disconnecting the detector permanently","Ignoring it until the unit fails"], correct:0, re:"NFPA 72 requires periodic functional testing and sensitivity testing/cleaning so detectors stay within their listed sensitivity range. Source: NFPA 72 inspection, testing, and maintenance."},
  {id:35, block:1, sec:"Heat Detectors", q:"A fixed-temperature heat detector operates when:", opts:["The temperature rises faster than a set rate","Carbon monoxide reaches 70 ppm","Smoke obscures a light beam","The sensing element reaches a predetermined temperature"], correct:3, re:"A fixed-temperature heat detector activates when its operating element reaches a preset temperature (e.g., 135 F). Source: NFPA 72 heat-detector definitions; FM Approvals."},
  {id:36, block:1, sec:"Heat Detectors", q:"A rate-of-rise (ROR) heat detector operates when the air temperature:", opts:["Reaches a fixed set point only","Stays constant for one hour","Falls rapidly","Rises at more than a predetermined rate, commonly about 15 F per minute"], correct:3, re:"ROR detectors respond when the temperature rises faster than a set rate, commonly about 15 F (≈8.3 C) per minute. Source: NFPA 72; FM Approvals heat-detector criteria."},
  {id:37, block:1, sec:"Heat Detectors", q:"A common standard fixed-temperature rating for ordinary-temperature heat detectors is approximately:", opts:["55 F","32 F","500 F","135 F"], correct:3, re:"Ordinary-temperature fixed heat detectors commonly operate near 135 F (and 200 F for intermediate ratings). Source: NFPA 72 heat-detector temperature classifications."},
  {id:38, block:1, sec:"Heat Detectors", q:"A rate-of-rise heat detector may FAIL to alarm in which scenario?", opts:["A very slowly developing fire whose temperature creeps up below the rate threshold","A flash fire raising temperature quickly","Any fire producing rapid heat","A fire directly under the detector"], correct:0, re:"A slowly smoldering fire can raise temperature below the rate-of-rise threshold and not trip the ROR element; this is why ROR is often combined with a fixed-temperature element. Source: NFPA 72 heat-detector operation."},
  {id:39, block:1, sec:"Heat Detectors", q:"A combination fixed-temperature/rate-of-rise heat detector provides:", opts:["Only smoke detection","Beam alignment","Carbon monoxide sensing","Response to both rapidly and slowly developing fires"], correct:3, re:"The ROR element catches fast fires while the fixed-temperature element catches slow ones, covering both fire-growth patterns. Source: NFPA 72; FM Approvals combination heat detectors."},
  {id:40, block:1, sec:"Heat Detectors", q:"A rate-compensation heat detector is best described as a detector that:", opts:["Responds when surrounding air reaches a set temperature with minimal thermal lag","Counts smoke particles","Detects UV radiation","Measures duct airflow"], correct:0, re:"A rate-compensation detector responds when the surrounding air reaches a predetermined temperature with little effect from the rate of rise (low thermal lag), behaving like a fast fixed-temperature detector. Source: NFPA 72 definitions; FM Approvals."},
  {id:41, block:1, sec:"Heat Detectors", q:"Compared with smoke detectors, heat detectors generally:", opts:["Give earlier warning of a fire","Are more prone to nuisance alarms","Respond later but with fewer nuisance alarms","Detect invisible aerosols"], correct:2, re:"Heat detectors respond later (heat builds after smoke) but are far less prone to nuisance alarms, making them suitable for dirty or harsh areas. Source: NFPA 72 detector selection."},
  {id:42, block:1, sec:"Heat Detectors", q:"In which environment is a HEAT detector typically preferred over a smoke detector?", opts:["A clean office","A hospital sleeping room","A dusty, dirty, or fume-laden area like a boiler room or garage","A computer server room needing very early warning"], correct:2, re:"Heat detectors are chosen for dusty, dirty, fumey, or high-humidity spaces where smoke detectors would nuisance-alarm. Source: NFPA 72 detector-selection guidance."},
  {id:43, block:1, sec:"Heat Detectors", q:"A 'non-restorable' fixed-temperature heat detector (e.g., a fusible-link or eutectic type) must be:", opts:["Reset with a key after each test","Recharged electrically","Painted to restore function","Replaced after it operates"], correct:3, re:"Non-restorable detectors use a melting (eutectic) element that is destroyed on operation and must be replaced; restorable types reset automatically. Source: NFPA 72 heat-detector types."},
  {id:44, block:1, sec:"Heat Detectors", q:"NFPA 72 spacing of spot heat detectors uses a 'listed spacing.' A key rule for coverage is that every point on the ceiling must be within:", opts:["0.7 times the listed spacing of a detector","2.0 times the listed spacing","exactly 100 ft","the building width"], correct:0, re:"The '0.7 rule' requires every point on the ceiling to be within 0.7 × the listed spacing of a heat detector. Source: NFPA 72 heat-detector spacing (NTC 'Point 7 Rule')."},
  {id:45, block:1, sec:"Heat Detectors", q:"As ceiling height increases, the required spacing of spot heat detectors generally must be:", opts:["Increased","Set to zero","Left unchanged","Reduced (multiplied by a factor less than 1)"], correct:3, re:"NFPA 72 applies a height-based reduction factor (<1) to listed heat-detector spacing as ceilings get higher, because heat stratifies before reaching distant detectors. Source: NFPA 72 Table 17.6.3.5.1."},
  {id:46, block:1, sec:"Heat Detectors", q:"A line-type heat detector commonly uses:", opts:["A single radioactive source","An ultrasonic transducer","A photoelectric chamber","A continuous cable whose insulation breaks down at a set temperature, completing a circuit"], correct:3, re:"Linear (line-type) heat detection uses a continuous heat-sensitive cable; at the rated temperature the insulation breaks down and the conductors short, signaling the location of heat. Source: NFPA 72 line-type heat detection."},
  {id:47, block:1, sec:"Heat Detectors", q:"A higher temperature-rated heat detector (e.g., 190-200 F instead of 135 F) would be selected for a location that:", opts:["Normally stays very cold","Has no fire risk","Is a clean office","Has a high normal ambient temperature, to avoid false operation"], correct:3, re:"Heat detectors are rated above the maximum expected normal ambient temperature; hot areas (attics, boiler rooms) use higher-rated detectors to prevent nuisance operation. Source: NFPA 72 temperature classification."},
  {id:48, block:1, sec:"Heat Detectors", q:"The term 'thermal lag' in heat detection refers to:", opts:["The delay before the sensing element reaches the actual air temperature","The time to wire the detector","The alarm horn delay","The smoke obscuration percentage"], correct:0, re:"Thermal lag is the difference between actual air temperature and the detector element temperature; rate-compensation detectors are designed to minimize it. Source: NFPA 72 heat-detector principles."},
  {id:49, block:1, sec:"Heat Detectors", q:"Which heat detector type RESTORES (resets) itself after the heat source is removed, without replacement?", opts:["A fusible-link (eutectic) non-restorable type","A meltable-pellet type","A frangible glass-bulb type","A bimetallic restorable spot type"], correct:3, re:"Bimetallic restorable detectors flex with temperature and return to normal when cooled; fusible/eutectic and glass-bulb types are destroyed on operation. Source: NFPA 72 restorable vs. non-restorable detectors."},
  {id:50, block:1, sec:"Heat Detectors", q:"Why are heat detectors NOT recommended as the primary life-safety detector in sleeping areas?", opts:["They cost too much","They only work outdoors","They cannot be wired to a panel","They respond too late to protect sleeping occupants from smoke and toxic gases"], correct:3, re:"Because heat builds after smoke and CO, heat detectors warn too late for life safety in sleeping areas, where smoke detection is required instead. Source: NFPA 72 detector selection; NFPA life-safety guidance."},
  {id:51, block:1, sec:"Heat Detectors", q:"A pneumatic rate-of-rise spot heat detector works by:", opts:["Sensing alpha particles","Melting a metal pellet","Scattering infrared light","Air in a sealed chamber expanding faster than a calibrated vent can relieve, flexing a diaphragm to close contacts"], correct:3, re:"Pneumatic ROR detectors use a sealed air chamber with a small vent; rapid heating expands the air faster than it can bleed off, flexing a diaphragm that closes the alarm contacts. Source: NFPA 72 rate-of-rise operating principle."},
  {id:52, block:1, sec:"Manual Pull Stations", q:"Under NFPA 72, the operable part of a manual pull station must be mounted not less than ___ and not more than ___ above the finished floor.", opts:["24 in. / 36 in.","12 in. / 24 in.","60 in. / 72 in.","42 in. / 48 in."], correct:3, re:"NFPA 72 (17.14) requires the operable part of a manual fire alarm box to be 42 in. minimum to 48 in. maximum above the finished floor. Source: NFPA 72 §17.14; NFPA pull-station height blog."},
  {id:53, block:1, sec:"Manual Pull Stations", q:"A 'double-action' manual pull station requires the user to:", opts:["Perform two distinct actions, such as lift a cover or flap and then pull","Pull twice in the same direction","Push a single button once","Insert a coin"], correct:0, re:"Double-action (dual-action) stations need two separate motions (e.g., lift/push a cover, then pull), reducing accidental or malicious activation. Source: NFPA 72 manual fire alarm box guidance."},
  {id:54, block:1, sec:"Manual Pull Stations", q:"A 'single-action' manual pull station is activated by:", opts:["Two separate steps","A remote signal only","One motion, typically a single pull of the handle","Heat reaching 135 F"], correct:2, re:"Single-action stations operate with one motion (a single pull), giving the fastest manual activation. Source: NFPA 72 manual fire alarm box types."},
  {id:55, block:1, sec:"Manual Pull Stations", q:"NFPA 72 requires a manual pull station to be located within how far of each exit doorway?", opts:["Within 60 in. (5 ft) of the exit","Within 50 ft of the exit","Anywhere on the floor","Within 200 ft only"], correct:0, re:"A manual fire alarm box must be located within 60 in. (5 ft) of the exit doorway opening at each exit. Source: NFPA 72 §17.14 pull-station placement."},
  {id:56, block:1, sec:"Manual Pull Stations", q:"On a large floor, NFPA 72 limits horizontal travel distance to the nearest manual pull station to no more than about:", opts:["50 ft","100 ft","200 ft","500 ft"], correct:2, re:"Travel distance to a manual fire alarm box must not exceed 200 ft on the same floor; additional stations are added to meet this. Source: NFPA 72 §17.14."},
  {id:57, block:1, sec:"Manual Pull Stations", q:"The standard color required for manual fire alarm pull stations is:", opts:["Green","Blue","Red","Yellow"], correct:2, re:"Manual fire alarm boxes are required to be red. Source: NFPA 72 §17.14 manual fire alarm box requirements."},
  {id:58, block:1, sec:"Manual Pull Stations", q:"Where are manual pull stations typically located along an egress path?", opts:["In the natural exit access, near the doors people use to leave","Only inside locked closets","Only on the roof","Hidden behind furniture"], correct:0, re:"Stations are placed in the natural path of egress near exits so a leaving occupant passes one. Source: NFPA 72 §17.14 placement intent."},
  {id:59, block:1, sec:"Manual Pull Stations", q:"A primary reason to choose DOUBLE-action (or covered) pull stations in a school or other high-traffic area is to:", opts:["Reduce malicious or accidental false alarms","Make them harder for firefighters to find","Eliminate the need for smoke detectors","Lower the mounting height"], correct:0, re:"The extra step (and protective covers) on double-action stations cuts down nuisance and malicious activations in high-traffic occupancies. Source: NFPA 72 manual fire alarm box guidance."},
  {id:60, block:1, sec:"Manual Pull Stations", q:"A manual pull station is classified within a fire alarm system as a(n):", opts:["Notification appliance","Power supply","Initiating device","Annunciator"], correct:2, re:"A manual pull station is a manually actuated initiating device that signals the control unit. Source: NFPA 72 initiating-device definitions."},
  {id:61, block:1, sec:"Manual Pull Stations", q:"After a conventional break-glass or latching pull station is activated, restoring it to normal usually requires:", opts:["Painting it red again","Waiting for it to cool below 135 F","Using a key or tool to reset (and replacing a glass rod if so equipped)","Cycling building power only"], correct:2, re:"Latching pull stations stay tripped until reset with the proper key/tool; break-rod types also need the glass/plastic rod replaced. Source: manufacturer/NFPA 72 manual fire alarm box operation."},
  {id:62, block:1, sec:"Manual Pull Stations", q:"A clear operating instruction such as the word 'PULL' on a manual station serves to:", opts:["Decorate the device","Indicate the wire gauge","Tell occupants how to operate it during an emergency","Mark the radioactive source"], correct:2, re:"Manual fire alarm boxes carry clear operating instructions (e.g., PULL) so occupants can activate them under stress. Source: NFPA 72 manual fire alarm box marking."},
  {id:63, block:1, sec:"Manual Pull Stations", q:"A key-operated 'test' position on some pull stations allows a technician to:", opts:["Permanently disable the system","Increase notification volume","Operate the station for testing without breaking a rod or glass","Change the detector sensitivity"], correct:2, re:"A keyed test feature lets the station be operated and reset for periodic testing without consuming a break element. Source: NFPA 72 ITM; manufacturer documentation."},
  {id:64, block:1, sec:"Manual Pull Stations", q:"Mounting all manual pull stations within the 42-48 in. window primarily supports:", opts:["Consistent, accessible operation including by persons in wheelchairs (ADA)","Reducing wire length","Hiding them from view","Heat detection"], correct:0, re:"The 42-48 in. range provides consistent reach and accessibility, aligning with ADA reach ranges. Source: NFPA 72 §17.14; ADA reach-range coordination."},
  {id:65, block:1, sec:"Manual Pull Stations", q:"When a manual pull station is activated, the fire alarm control unit should:", opts:["Ignore it for 5 minutes","Initiate the fire alarm condition and notification appliances","Silence all detectors","Reset itself automatically"], correct:1, re:"Operating an initiating device such as a pull station places the panel into the alarm condition and activates notification per the system program. Source: NFPA 72 system operation."},
  {id:66, block:1, sec:"Manual Pull Stations", q:"In an addressable fire alarm system, a manual pull station typically:", opts:["Reports its specific address/location to the panel","Cannot be identified at all","Only works without any wiring","Functions solely as a horn"], correct:0, re:"Addressable pull stations report a unique address so the panel can display the exact device/location that was activated. Source: NFPA 72 addressable system fundamentals."},
  {id:67, block:1, sec:"Manual Pull Stations", q:"Which is NOT an appropriate location consideration for a manual pull station?", opts:["Adjacent to each exit","In the path of egress","Behind a locked door inaccessible to occupants","At a consistent 42-48 in. height"], correct:2, re:"Pull stations must be readily accessible in the egress path near exits; placing one behind a locked, inaccessible door defeats its purpose. Source: NFPA 72 §17.14 placement."},
  {id:68, block:1, sec:"Manual Pull Stations", q:"A manual pull station differs from an automatic detector in that it:", opts:["Requires human action to initiate an alarm","Senses smoke automatically","Senses heat automatically","Detects CO automatically"], correct:0, re:"Manual stations are human-actuated initiating devices, whereas automatic detectors sense a fire signature without human action. Source: NFPA 72 initiating-device classifications."},
  {id:69, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A projected-beam smoke detector senses smoke by:", opts:["Counting alpha particles","Measuring the reduction in light (obscuration) along a beam from a transmitter to a receiver","Detecting heat at 135 F","Sampling CO concentration"], correct:1, re:"Projected-beam detectors measure obscuration of an infrared beam between a transmitter and receiver; smoke crossing the beam attenuates the light. Source: NFPA 72 projected-beam detection; optical-beam references."},
  {id:70, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"Projected-beam smoke detectors are especially well suited for:", opts:["Small closets","Large open areas with high ceilings, such as atriums and warehouses","Inside HVAC ducts only","Sealed electrical cabinets"], correct:1, re:"Beam detectors efficiently protect large, high, open spaces (atriums, warehouses, gyms) that would otherwise need many spot detectors. Source: NFPA 72 projected-beam application; ORR/Hochiki references."},
  {id:71, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"On smooth ceilings, NFPA 72 gives a guideline horizontal spacing between adjacent projected beams of not more than about:", opts:["10 ft","30 ft","60 ft","300 ft"], correct:2, re:"NFPA 72 uses a guideline of not more than 60 ft between beams (and half that to a parallel sidewall) on smooth ceilings. Source: NFPA 72 §17.7 projected-beam spacing (UpCodes)."},
  {id:72, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A 'reflective' (single-ended) projected-beam detector uses:", opts:["Two radioactive sources","A transmitter/receiver in one unit aimed at a remote reflector","Only a heat element","A sampling pipe network"], correct:1, re:"Reflective beam detectors combine the transmitter and receiver in one housing and bounce the beam off a remote reflector, simplifying installation. Source: NFPA 72; beam-detector application guides."},
  {id:73, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A sudden TOTAL blockage of a projected-beam detector's path (e.g., an object placed over the receiver) typically produces:", opts:["A fire alarm immediately","A trouble (fault) signal rather than a fire alarm","No response at all","A reset of the panel"], correct:1, re:"Full beam blockage is treated as a fault/trouble condition (loss of beam), distinguishing it from the gradual obscuration of smoke. Source: NFPA 72 projected-beam operation; manufacturer listings."},
  {id:74, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"An air-aspirating (air-sampling) smoke detection system such as VESDA works by:", opts:["Waiting for smoke to drift into a spot chamber","Continuously drawing air through a pipe network to a highly sensitive detection chamber","Melting a fusible link","Detecting only carbon monoxide"], correct:1, re:"Aspirating systems use a fan/aspirator to continuously pull air samples through sampling pipes to a sensitive laser/optical chamber, giving very early warning. Source: NFPA 72 §17.7 air-sampling; Xtralis VESDA references."},
  {id:75, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A key advantage of air-aspirating (VESDA-type) detection over standard spot detectors is:", opts:["It needs no power","Very early warning / very high sensitivity to minute smoke levels","It detects heat faster","It eliminates the need for a control panel"], correct:1, re:"Air-aspirating systems offer very early warning by detecting extremely low smoke concentrations, ideal for high-value or mission-critical spaces. Source: NFPA 72 §17.7; VESDA application guidance."},
  {id:76, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"In NFPA 72, each sampling port of an air-aspirating system is generally treated, for location and spacing, as:", opts:["A notification appliance","A spot-type smoke detector","A manual pull station","A heat detector"], correct:1, re:"NFPA 72 (17.7) requires each sampling port to be treated as a spot-type smoke detector for location and spacing unless a performance-based design is used. Source: NFPA 72 §17.7.3.6.1."},
  {id:77, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A flame detector senses a fire by responding to:", opts:["Radiant energy (UV and/or IR) emitted by flames","Smoke particle count","Air temperature only","Carbon monoxide concentration"], correct:0, re:"Flame detectors are radiant-energy detectors that sense the UV and/or IR emissions of flames. Source: NFPA 72 radiant-energy (flame) detector definition."},
  {id:78, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A UV/IR flame detector improves reliability over a single-sensor unit by:", opts:["Using two different spectral bands to confirm a flame and reject false sources","Adding a radioactive source","Sampling duct air","Melting at 135 F"], correct:0, re:"Combining ultraviolet and infrared sensing requires both bands to confirm a flame, improving false-alarm immunity. Source: flame-detector operating principles (AZoSensors; MSA)."},
  {id:79, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"The IR sensor in many hydrocarbon flame detectors targets the emission near 4.3-4.4 microns because that band corresponds to:", opts:["Visible light from lamps","Hot carbon dioxide (CO2) produced by burning hydrocarbons","Water vapor only","Radio waves"], correct:1, re:"Burning hydrocarbons emit a strong IR signature near 4.3 microns from hot CO2; IR flame detectors key on this band. Source: flame-detector spectral references (AZoSensors)."},
  {id:80, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A flame detector is a good choice where:", opts:["A fire may erupt as open flame with little smoke, such as fuel-handling or hangar areas","Only slow smoldering is expected with no flame","No fire risk exists","CO monitoring is the sole need"], correct:0, re:"Flame detectors excel where fast-flaming, high-energy fires (flammable liquids, gases) can occur with little early smoke. Source: NFPA 72 radiant-energy detector application."},
  {id:81, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A flame detector generally requires:", opts:["Direct line of sight to the potential flame","No view of the protected area","Contact with the fuel","Immersion in water"], correct:0, re:"Because they sense radiant energy, flame detectors must have an unobstructed line of sight to the area where flames may appear. Source: NFPA 72 radiant-energy detector placement."},
  {id:82, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"A carbon monoxide (CO) detector commonly uses which sensing technology?", opts:["Ionization chamber","Electrochemical sensor","Bimetallic strip","Infrared beam across a room"], correct:1, re:"Residential/commercial CO detectors typically use an electrochemical cell that reacts with CO to produce a measurable current. Source: CO-detection references (NFPA 720/72; Kidde)."},
  {id:83, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"Which statement about CO detectors is correct?", opts:["A CO detector is the same as a smoke detector","A CO detector senses the toxic gas carbon monoxide, not smoke or flame","CO detectors detect heat at 135 F","CO is a visible, sweet-smelling gas"], correct:1, re:"CO detectors sense carbon monoxide, a colorless and odorless toxic gas; they do not replace smoke or heat detectors. Source: NFPA 720/72 CO-detection requirements."},
  {id:84, block:1, sec:"Special Detectors (Beam/Aspirating/Flame/CO)", q:"In dwellings, CO alarms/detectors are generally required to be located:", opts:["Only in the attic","Outside each separate sleeping area and on each level of the dwelling","Inside the firebox of a fireplace","Only in the garage"], correct:1, re:"Codes require CO alarms outside each separate sleeping area and on every level of a dwelling so occupants are warned of CO. Source: NFPA 720/72; IRC CO-alarm placement."},
  {id:85, block:1, sec:"Initiating Device Circuits (IDC)", q:"An initiating device circuit (IDC) is best described as a circuit that:", opts:["Powers notification horns and strobes","Connects initiating devices (such as pull stations and detectors) to the control unit","Supplies utility power to the building","Carries the telephone line only"], correct:1, re:"An IDC interconnects initiating devices (manual stations, detectors, waterflow switches) to the fire alarm control unit. Source: NFPA 72 circuit definitions."},
  {id:86, block:1, sec:"Initiating Device Circuits (IDC)", q:"On a conventional Class B IDC, supervision against open faults is commonly provided by:", opts:["A radioactive source","An end-of-line resistor (EOLR)","A flame sensor","A pull station handle"], correct:1, re:"A Class B IDC terminates in an end-of-line resistor; the panel pushes a small supervisory current through the loop, and loss of that current indicates an open. Source: NFPA 72 circuit supervision; NTC pathways."},
  {id:87, block:1, sec:"Initiating Device Circuits (IDC)", q:"If a single OPEN (break) occurs on a Class B IDC, the devices located BEYOND the break will:", opts:["Still report alarms normally","Be unable to report to the panel (rendered inoperative)","Switch to Class A automatically","Trigger the notification appliances directly"], correct:1, re:"On a Class B circuit, a single open isolates everything downstream of the break, so those devices cannot signal the panel; the panel shows a trouble. Source: NFPA 72 Class B behavior; NTC pathways."},
  {id:88, block:1, sec:"Initiating Device Circuits (IDC)", q:"A Class A IDC differs from Class B in that, after a single wire break, it:", opts:["Loses all devices","Can still communicate with every device by feeding the loop from both directions","Sounds a continuous alarm","Requires no supervision"], correct:1, re:"A Class A pathway returns to the panel, so a single break is bridged by feeding the loop from both ends and all devices keep reporting. Source: NFPA 72 Class A vs. Class B pathways."},
  {id:89, block:1, sec:"Initiating Device Circuits (IDC)", q:"Conventional initiating devices on a basic IDC operate by:", opts:["Sending a digital address","Switching from a normally-open state to closed (shorting the loop) to signal alarm","Increasing the EOLR value","Cutting building power"], correct:1, re:"Conventional initiating devices are normally-open contacts that close on alarm, dropping a low resistance across the loop that the panel reads as an alarm. Source: NFPA 72 conventional IDC operation."},
  {id:90, block:1, sec:"Initiating Device Circuits (IDC)", q:"On a supervised Class B IDC, an OPEN circuit is normally reported by the panel as a(n):", opts:["Alarm","Trouble (fault) condition","Supervisory CO event","Power-off only"], correct:1, re:"Loss of the supervisory current (an open) on a Class B IDC produces a trouble signal, distinct from the alarm produced by a device closing. Source: NFPA 72 circuit fault indication."},
  {id:91, block:1, sec:"Initiating Device Circuits (IDC)", q:"On a conventional Class B IDC, an alarm is distinguished from a normal/trouble state because the device closing causes the loop resistance to:", opts:["Rise to infinity (open)","Drop low (short across the line)","Stay exactly at the EOLR value","Become negative"], correct:1, re:"A closed initiating device shorts the loop, dropping resistance well below the EOLR value; the panel reads that drop as alarm. An open (infinite) reads as trouble. Source: NFPA 72 conventional IDC operation."},
  {id:92, block:1, sec:"Initiating Device Circuits (IDC)", q:"The purpose of supervising an IDC is to:", opts:["Improve the sound of the horns","Detect wiring faults (opens/shorts/grounds) so they can be repaired before an emergency","Increase the radioactive source life","Reduce the mounting height of devices"], correct:1, re:"Supervision lets the panel annunciate circuit faults so impaired wiring is found and fixed before it disables protection. Source: NFPA 72 circuit-supervision intent."},
  {id:93, block:1, sec:"Initiating Device Circuits (IDC)", q:"In NEC Article 760, fire alarm circuits are divided into two main categories:", opts:["AC and DC","Power-limited (PLFA) and non-power-limited (NPLFA)","Class 2 and Class 3","High voltage and low voltage"], correct:1, re:"NEC Article 760 separates fire alarm circuits into power-limited (PLFA) and non-power-limited (NPLFA) circuits, each with its own wiring rules. Source: NEC Article 760 (NFPA 70)."},
  {id:94, block:1, sec:"Initiating Device Circuits (IDC)", q:"A power-limited fire alarm (PLFA) circuit under NEC 760 must have its voltage and power limited by:", opts:["A listed power source meeting the power-limited requirements","The end-of-line resistor","The longest wire run","The number of detectors"], correct:0, re:"PLFA circuits are powered by a listed power-limited supply (per NEC 760.121), which inherently limits current and reduces shock/fire risk, allowing less stringent wiring. Source: NEC Article 760."},
  {id:95, block:1, sec:"Initiating Device Circuits (IDC)", q:"Compared with PLFA circuits, non-power-limited (NPLFA) fire alarm circuits:", opts:["Can operate at higher voltage/power and have more stringent wiring rules","Are always 24 V and easy to install","Carry no electrical risk","Are not allowed by the NEC"], correct:0, re:"NPLFA circuits (up to 600 V, power not inherently limited) carry greater shock risk and must follow stricter installation rules than PLFA. Source: NEC Article 760 NPLFA requirements."},
  {id:96, block:1, sec:"Initiating Device Circuits (IDC)", q:"Power-limited fire alarm (PLFA) conductors generally must be kept:", opts:["In the same cable as building power conductors","Physically separated from electric light, power, and other higher-energy conductors unless an exception applies","Outdoors only","Energized at 600 V"], correct:1, re:"NEC 760 requires PLFA conductors to be separated from light, power, Class 1, and NPLFA conductors (no common cable/raceway) except where specific exceptions allow. Source: NEC Article 760 separation rules."},
  {id:97, block:1, sec:"Initiating Device Circuits (IDC)", q:"A GROUND fault on an initiating device circuit should be:", opts:["Ignored by the control unit","Indicated as a trouble condition at the control unit","Reported only as an alarm","Used to silence detectors"], correct:1, re:"NFPA 72 requires the control unit to monitor circuit integrity; a ground fault on a monitored circuit results in a trouble indication. Source: NFPA 72 circuit supervision."},
  {id:98, block:1, sec:"Initiating Device Circuits (IDC)", q:"Mixing conventional initiating devices on an IDC means that when one device alarms, the panel can identify:", opts:["The exact individual device","Only that some device on that zone/circuit operated","The wire gauge used","The detector's temperature rating"], correct:1, re:"A conventional IDC reports by zone/circuit, so the panel knows a device on that circuit operated but not which one; addressable systems identify the specific device. Source: NFPA 72 conventional vs. addressable."},
  {id:99, block:1, sec:"Initiating Device Circuits (IDC)", q:"On a basic conventional IDC, what electrical state does the panel consider 'normal' (no alarm, no trouble)?", opts:["A short across the loop","Zero volts on the loop","Supervisory current flowing through the end-of-line resistor","The horns sounding"], correct:2, re:"Normal condition is a small supervisory current flowing through the EOLR; a short reads as alarm and an open reads as trouble. Source: NFPA 72 conventional IDC supervision."},
  {id:100, block:1, sec:"Initiating Device Circuits (IDC)", q:"Why is the end-of-line resistor placed at the FAR (last) device of a Class B IDC rather than at the panel?", opts:["To save wire","So the supervisory current must pass through the entire run, allowing an open anywhere to be detected","To increase notification volume","To convert the circuit to Class A"], correct:1, re:"Putting the EOLR at the end forces the supervisory current through the whole circuit; a break anywhere interrupts that current and is annunciated as trouble. Source: NFPA 72 Class B supervision principle."},
  {id:101, block:2, sec:"Audible Notification & Sound Levels", q:"For public-mode audible notification, NFPA 72 requires the signal to be at least how many dBA above the average ambient sound level?", opts:["15 dBA","10 dBA","5 dBA","20 dBA"], correct:0, re:"NFPA 72 (2022) 18.4.3.1: public-mode audible appliances must produce a sound level at least 15 dBA above average ambient, or 5 dBA above the maximum sound level lasting 60 s, whichever is greater."},
  {id:102, block:2, sec:"Audible Notification & Sound Levels", q:"Public-mode audible signals must also be at least how many dBA above the maximum sound level having a duration of at least 60 seconds?", opts:["10 dBA","5 dBA","15 dBA","25 dBA"], correct:1, re:"NFPA 72 18.4.3.1: the requirement is 15 dBA above average ambient OR 5 dBA above the 60-second maximum, whichever is greater."},
  {id:103, block:2, sec:"Audible Notification & Sound Levels", q:"In sleeping areas, the audible signal at the pillow must be at least which sound level, whichever is greater?", opts:["65 dBA","70 dBA","75 dBA","85 dBA"], correct:2, re:"NFPA 72 18.4.5: in sleeping rooms, the signal must be 15 dBA above ambient, 5 dBA above a 60-second maximum, or at least 75 dBA at the pillow, whichever is greater."},
  {id:104, block:2, sec:"Audible Notification & Sound Levels", q:"Public-mode audible sound levels are measured at what height above the floor in the occupiable area?", opts:["1.0 m (3 ft)","1.2 m (4 ft)","1.8 m (6 ft)","1.5 m (5 ft)"], correct:3, re:"NFPA 72 18.4.3: measurements are taken 1.5 m (5 ft) above the floor in the occupiable area, A-weighted."},
  {id:105, block:2, sec:"Audible Notification & Sound Levels", q:"The total sound pressure level from all audible appliances combined with ambient shall NOT exceed what value at the minimum hearing distance?", opts:["110 dBA","105 dBA","100 dBA","120 dBA"], correct:0, re:"NFPA 72 18.4.4: combined sound pressure shall not exceed 110 dBA at the minimum hearing distance to protect hearing."},
  {id:106, block:2, sec:"Audible Notification & Sound Levels", q:"For private-mode audible notification, the signal must be at least how many dBA above the average ambient sound level?", opts:["15 dBA","10 dBA","5 dBA","20 dBA"], correct:1, re:"NFPA 72 18.4.4 (private mode): at least 10 dBA above average ambient or 5 dBA above the 60-second maximum, whichever is greater."},
  {id:107, block:2, sec:"Audible Notification & Sound Levels", q:"Which weighting scale is specified by NFPA 72 for measuring notification sound levels?", opts:["C-weighted (dBC)","Z-weighted (dBZ)","A-weighted (dBA)","Linear (dB SPL)"], correct:2, re:"NFPA 72 Chapter 18 specifies the A-weighted (dBA) scale, which approximates human hearing sensitivity."},
  {id:108, block:2, sec:"Audible Notification & Sound Levels", q:"To awaken occupants in sleeping areas, NFPA 72 requires the smoke-alarm/notification signal to include what frequency characteristic?", opts:["A high-frequency 5000 Hz tone","A 1000 Hz pure sine tone","An ultrasonic pilot tone","A low-frequency 520 Hz square-wave signal"], correct:3, re:"NFPA 72 18.4.5.3: notification appliances intended to wake sleeping occupants must produce a low-frequency 520 Hz ±10% square-wave signal, which awakens more effectively (including hard-of-hearing persons)."},
  {id:109, block:2, sec:"Audible Notification & Sound Levels", q:"When a door or other barrier exists between the audible appliance and the pillow, how is the sleeping-area sound level determined?", opts:["Measured with the barrier in place (closed)","Measured with the barrier open","Calculated without the barrier","The barrier is ignored entirely"], correct:0, re:"NFPA 72 18.4.5: sound level is measured with intervening barriers (doors, curtains, partitions) in their normal closed position, since that is the worst case."},
  {id:110, block:2, sec:"Audible Notification & Sound Levels", q:"An 'average ambient sound level' under NFPA 72 is the root-mean-square value of all sounds over what minimum period in a 24-hour day?", opts:["1 minute","A sufficient time to characterize the area","24 hours of representative measurement","5 minutes"], correct:1, re:"NFPA 72 definitions: average ambient is the RMS sound level measured over a time sufficient to be representative of the space's normal condition."},
  {id:111, block:2, sec:"Audible Notification & Sound Levels", q:"If a space has an average ambient of 55 dBA, what is the minimum public-mode signal level using only the 15-dBA-above-ambient rule?", opts:["60 dBA","65 dBA","70 dBA","75 dBA"], correct:2, re:"NFPA 72 18.4.3.1: 55 dBA ambient + 15 dBA = 70 dBA minimum (before checking the 60-second maximum rule)."},
  {id:112, block:2, sec:"Audible Notification & Sound Levels", q:"Audible notification appliances are generally NOT required to operate in which of the following areas?", opts:["Corridors and lobbies","Sleeping rooms","Assembly occupancies","Mechanical/electrical rooms where occupants are not expected"], correct:3, re:"NFPA 72 / IBC: notification is provided where occupants must be alerted; unoccupied mechanical/electrical equipment rooms typically do not require occupant notification."},
  {id:113, block:2, sec:"Audible Notification & Sound Levels", q:"What is the primary purpose of the 110 dBA maximum sound pressure limit?", opts:["To prevent hearing damage to occupants","To save battery power","To reduce wiring cost","To improve strobe synchronization"], correct:0, re:"NFPA 72 18.4.4: the 110 dBA cap at the minimum hearing distance protects occupants from hearing injury during evacuation."},
  {id:114, block:2, sec:"Audible Notification & Sound Levels", q:"A horn rated at 90 dBA at 10 ft loses approximately how much sound level each time the distance from it doubles (free field)?", opts:["3 dBA","6 dBA","10 dBA","12 dBA"], correct:1, re:"The inverse-square law gives roughly a 6 dB drop per doubling of distance in a free field; this is fundamental to audibility design under NFPA 72 Annex A."},
  {id:115, block:2, sec:"Audible Notification & Sound Levels", q:"For audibility purposes, which type of appliance produces the loudest output for a given input and is common in industrial areas?", opts:["Chime","Bell","Horn","Speaker at low taps"], correct:2, re:"NFPA 72 Annex/practice: horns provide the highest dBA output and are favored in high-ambient industrial spaces; chimes/bells produce lower levels."},
  {id:116, block:2, sec:"Audible Notification & Sound Levels", q:"Which statement about audible appliance listing is correct?", opts:["Any speaker may be used without listing","Listing applies only to the panel","Listing is only required for strobes","Audible notification appliances must be listed for fire alarm signaling use"], correct:3, re:"NFPA 72 10.3 / 18.3: all notification appliances must be listed for their purpose; manufacturers publish rated dBA at 10 ft (reverberant) for design."},
  {id:117, block:2, sec:"Audible Notification & Sound Levels", q:"Manufacturer audible ratings (dBA at 10 ft) are typically published under which condition for code design use?", opts:["Reverberant (UL 464) conditions","Anechoic (free-field) only","Outdoor open-air only","Underwater"], correct:0, re:"UL 464 / NFPA 72 design: appliances are rated at 10 ft in a reverberant chamber, the values designers use to verify the 15-dBA-above-ambient requirement."},
  {id:118, block:2, sec:"Visible Notification & ADA Candela", q:"What is the minimum candela rating permitted for a strobe in a corridor 20 ft wide or less?", opts:["30 cd","15 cd","75 cd","110 cd"], correct:1, re:"NFPA 72 18.5.5.5: corridor strobes (corridor ≤ 20 ft wide) may be 15 cd, located within 15 ft of each end and not more than 100 ft apart."},
  {id:119, block:2, sec:"Visible Notification & ADA Candela", q:"In a corridor application, strobes shall be located no more than how far from the end of the corridor?", opts:["10 ft","20 ft","15 ft","25 ft"], correct:2, re:"NFPA 72 18.5.5.5: visible appliances must be within 15 ft of the end of the corridor."},
  {id:120, block:2, sec:"Visible Notification & ADA Candela", q:"In a corridor, the maximum spacing permitted between visible notification appliances is:", opts:["50 ft","75 ft","130 ft","100 ft"], correct:3, re:"NFPA 72 18.5.5.5: corridor strobe separation shall not exceed 100 ft between appliances."},
  {id:121, block:2, sec:"Visible Notification & ADA Candela", q:"Per NFPA 72, a corridor wider than 20 ft must be treated for visible-notification spacing as:", opts:["A room (using room spacing rules)","A corridor with 15 cd strobes","An exterior space","A plenum"], correct:0, re:"NFPA 72 18.5.5.5: corridors greater than 20 ft wide are spaced as rooms (Table 18.5.5.4.1), generally requiring higher candela."},
  {id:122, block:2, sec:"Visible Notification & ADA Candela", q:"For a single wall-mounted strobe, what minimum candela is required to cover a 20 ft × 20 ft room?", opts:["30 cd","15 cd","60 cd","75 cd"], correct:1, re:"NFPA 72 Table 18.5.5.4.1(a): one wall-mounted light covering a 20×20 ft room requires 15 cd minimum."},
  {id:123, block:2, sec:"Visible Notification & ADA Candela", q:"Using one wall-mounted strobe, what minimum candela covers a 40 ft × 40 ft room?", opts:["30 cd","95 cd","60 cd","135 cd"], correct:2, re:"NFPA 72 Table 18.5.5.4.1(a): a single wall-mounted strobe for a 40×40 ft room requires 60 cd."},
  {id:124, block:2, sec:"Visible Notification & ADA Candela", q:"Wall-mounted visible notification appliances must be mounted with the entire lens in what height range above the finished floor?", opts:["48 to 72 in.","60 to 80 in.","96 to 120 in.","80 to 96 in."], correct:3, re:"NFPA 72 18.5.5.2: wall-mounted strobes shall have the entire lens between 80 in. and 96 in. above the finished floor (or 6 in. below ceiling if lower)."},
  {id:125, block:2, sec:"Visible Notification & ADA Candela", q:"The maximum mounting height permitted for a ceiling-mounted visible appliance per NFPA 72 spacing tables is:", opts:["30 ft","25 ft","20 ft","40 ft"], correct:0, re:"NFPA 72 18.5.5.4 / Table 18.5.5.4.1(b): ceiling strobe spacing tables extend to a 30 ft mounting height; appliances above 30 ft are suspended at or below 30 ft."},
  {id:126, block:2, sec:"Visible Notification & ADA Candela", q:"For a sleeping room, a wall strobe mounted more than 24 in. below the ceiling must be at least:", opts:["75 cd","110 cd","135 cd","177 cd"], correct:1, re:"NFPA 72 18.5.5.7: sleeping-area strobes require 110 cd when mounted more than 24 in. from the ceiling."},
  {id:127, block:2, sec:"Visible Notification & ADA Candela", q:"For a sleeping room, a strobe mounted less than 24 in. from the ceiling must be at least:", opts:["110 cd","135 cd","177 cd","185 cd"], correct:2, re:"NFPA 72 18.5.5.7: when a sleeping-room strobe is within 24 in. of the ceiling, a 177 cd appliance is required to overcome smoke-layer attenuation."},
  {id:128, block:2, sec:"Visible Notification & ADA Candela", q:"Since the 2010 ADA Standards, visible fire alarm appliances are required to be installed in accordance with:", opts:["Only ICC A117.1","Manufacturer preference only","Only the local fire code","NFPA 72"], correct:3, re:"The 2010 ADA Standards (and ICC A117.1) reference NFPA 72 for visible alarm placement and candela, harmonizing accessibility and fire-alarm rules."},
  {id:129, block:2, sec:"Visible Notification & ADA Candela", q:"Visible appliances are required primarily to alert which occupants?", opts:["People who are deaf or hard of hearing","Only sleeping occupants","Only maintenance staff","Outdoor pedestrians"], correct:0, re:"NFPA 72 / ADA: strobes provide notification to persons who are deaf or hard of hearing, an accessibility requirement in occupiable spaces."},
  {id:130, block:2, sec:"Visible Notification & ADA Candela", q:"Strobe coverage tables in NFPA 72 are based on what room geometry?", opts:["Circular rooms","Square rooms","L-shaped rooms","Triangular rooms"], correct:1, re:"NFPA 72 18.5.5.4: room spacing tables assume square rooms; non-square rooms are subdivided into squares for coverage."},
  {id:131, block:2, sec:"Visible Notification & ADA Candela", q:"For a 50 ft × 50 ft room, what minimum candela is required using one wall-mounted strobe?", opts:["60 cd","75 cd","95 cd","135 cd"], correct:2, re:"NFPA 72 Table 18.5.5.4.1(a): a single wall-mounted strobe covering a 50×50 ft room requires 95 cd."},
  {id:132, block:2, sec:"Visible Notification & ADA Candela", q:"A standard (non-extended-coverage) UL-listed strobe is NOT typically available in which candela rating?", opts:["15 cd","75 cd","110 cd","185 cd"], correct:3, re:"Standard strobes are listed at 15/30/75/95/110 cd; 177 and 185 cd are extended-coverage ratings, not standard-coverage values."},
  {id:133, block:2, sec:"Visible Notification & ADA Candela", q:"If a room requires more than two wall strobes to achieve required coverage, NFPA 72 requires the strobes to be:", opts:["Synchronized","Different colors","Mounted on the ceiling only","Rated at 15 cd"], correct:0, re:"NFPA 72 18.5.5.4.6: when more than two visible appliances are within any field of view, they must flash in synchronization to limit seizure risk."},
  {id:134, block:2, sec:"Visible Notification & ADA Candela", q:"Visible notification appliances must produce flashes that are clear or what color?", opts:["Red","White","Blue","Amber"], correct:1, re:"NFPA 72 18.5.4: fire alarm visible appliances shall be clear or nominal white; other colors (e.g., amber/blue) are reserved for non-fire signaling such as MNS."},
  {id:135, block:2, sec:"Notification Appliance Circuits (NAC)", q:"A Class B notification appliance circuit is supervised for integrity by means of:", opts:["A redundant return path to the panel","A ground-fault detector only","An end-of-line resistor (EOLR)","A second control panel"], correct:2, re:"NFPA 72 12.3 / Annex: a Class B NAC terminates in an end-of-line resistor so a low supervisory current detects opens; a single break disables downstream devices."},
  {id:136, block:2, sec:"Notification Appliance Circuits (NAC)", q:"A key advantage of a Class A NAC over a Class B NAC is that it:", opts:["Uses fewer conductors","Eliminates the need for power","Requires no supervision","Continues to operate appliances after a single open (wire break)"], correct:3, re:"NFPA 72 12.3: a Class A circuit provides a redundant return path, so a single open does not prevent operation of appliances; Class B loses everything downstream of the break."},
  {id:137, block:2, sec:"Notification Appliance Circuits (NAC)", q:"How many conductors (pathways) does a Class A notification appliance circuit use?", opts:["4","2","1","6"], correct:0, re:"NFPA 72 12.3: Class A uses 4 wires (outgoing pair plus a redundant return pair) so the circuit is monitored for integrity and survives a single open."},
  {id:138, block:2, sec:"Notification Appliance Circuits (NAC)", q:"Notification appliance circuits are supervised so that a single open or ground fault results in what?", opts:["Silent failure","A trouble signal at the control unit","An automatic alarm","Immediate evacuation"], correct:1, re:"NFPA 72 10.17 / 12.3: faults on supervised circuits annunciate a trouble signal within the required time so the impairment is known and repaired."},
  {id:139, block:2, sec:"Notification Appliance Circuits (NAC)", q:"Most modern polarized notification appliances are connected to the NAC using:", opts:["Non-polarized AC wiring","Three-phase power","Polarized DC wiring with correct polarity","Coaxial cable"], correct:2, re:"NFPA 72 practice: conventional horns/strobes are polarized DC devices; correct polarity is required for the appliances to activate and for supervision to work."},
  {id:140, block:2, sec:"Notification Appliance Circuits (NAC)", q:"What is the purpose of conducting a voltage-drop calculation on a NAC?", opts:["To set the alarm verification delay","To size the smoke detector spacing","To select the strobe color","To ensure the last appliance receives at least its minimum rated operating voltage"], correct:3, re:"NFPA 72 / design practice: voltage-drop calculations confirm the end-of-line appliance still receives at least its UL-listed minimum voltage so it operates and stays in sync."},
  {id:141, block:2, sec:"Notification Appliance Circuits (NAC)", q:"If the voltage at the last strobe on a NAC drops below the appliance's listed minimum, the most likely result is:", opts:["The appliance may fail to operate or lose synchronization","The strobe flashes brighter","The panel resets","The ambient sound level rises"], correct:0, re:"Design practice per NFPA 72: insufficient voltage at the appliance can prevent activation or cause strobes to drift out of synchronization."},
  {id:142, block:2, sec:"Notification Appliance Circuits (NAC)", q:"A NAC power extender (booster) panel is used primarily to:", opts:["Convert AC to gas","Provide additional regulated power and battery backup for more appliances","Replace the fire alarm control unit","Eliminate the need for EOL supervision"], correct:1, re:"NFPA 72: a listed NAC power extender supplies additional supervised, battery-backed power so large appliance loads exceed the main panel's NAC capacity."},
  {id:143, block:2, sec:"Notification Appliance Circuits (NAC)", q:"Notification appliance circuits must be electrically supervised so faults are detected. This is required by:", opts:["NEC Article 90 only","ASHRAE 90.1","NFPA 72 (monitoring for integrity)","ADA only"], correct:2, re:"NFPA 72 10.17 / 12.3: pathways serving notification appliances must be monitored for integrity (supervised) unless specifically exempted."},
  {id:144, block:2, sec:"Notification Appliance Circuits (NAC)", q:"Which describes a 'releasing' vs 'notification' circuit distinction relevant to NAC design?", opts:["Both are identical","Notification circuits cannot be supervised","A NAC always operates sprinkler valves","A NAC drives audible/visible appliances, not suppression releasing"], correct:3, re:"NFPA 72: notification appliance circuits drive horns/strobes/speakers; releasing functions use separate listed releasing circuits with their own requirements."},
  {id:145, block:2, sec:"Notification Appliance Circuits (NAC)", q:"When appliances are added to an existing NAC, the designer must re-verify which two things?", opts:["Current draw (panel capacity) and end-of-line voltage drop","Paint color and label size","Room temperature and humidity","Smoke detector sensitivity"], correct:0, re:"NFPA 72 design practice: added appliances increase current load, so total draw versus circuit rating and end-of-line voltage must both be rechecked."},
  {id:146, block:2, sec:"Notification Appliance Circuits (NAC)", q:"A Class B NAC differs from a Class A NAC in that a single wire break on Class B will:", opts:["Have no effect","Disable all appliances connected after the break","Increase appliance output","Trigger a general alarm"], correct:1, re:"NFPA 72 12.3: on Class B, devices downstream of an open are lost because there is no redundant return path; only the EOL supervision reports the trouble."},
  {id:147, block:2, sec:"Notification Appliance Circuits (NAC)", q:"Notification appliances on a circuit that must flash together typically require what feature from the panel or sync module?", opts:["A random flash generator","A higher ambient temperature","A synchronization signal/protocol","An amber lens"], correct:2, re:"NFPA 72 18.5.5.4.6: a sync module or compatible panel provides a synchronization signal so all strobes in a field of view flash together."},
  {id:148, block:2, sec:"Notification Appliance Circuits (NAC)", q:"The maximum current a NAC can carry is limited primarily by:", opts:["The strobe lens color","The ambient sound level","The number of pull stations","The panel/booster circuit rating and conductor ampacity/voltage drop"], correct:3, re:"NFPA 72 design: NAC loading is limited by the source's rated output current and by conductor voltage drop, ensuring all appliances stay within listed voltage."},
  {id:149, block:2, sec:"Notification Appliance Circuits (NAC)", q:"Which conductor practice helps minimize voltage drop on a long NAC run?", opts:["Use larger-gauge (lower-resistance) wire","Use smaller-gauge wire","Increase the number of splices","Add more EOL resistors"], correct:0, re:"Basic circuit design per NFPA 72: larger-gauge conductors have lower resistance, reducing voltage drop so end-of-line appliances receive adequate voltage."},
  {id:150, block:2, sec:"Notification Appliance Circuits (NAC)", q:"Why must strobe NAC loads be calculated using the appliance's worst-case (inrush/peak) current?", opts:["Strobes never draw current","Strobes draw a brief high peak each flash that the supply must sustain","Only horns draw current","Current is irrelevant to strobes"], correct:1, re:"Design practice: strobes draw a brief high peak current at each flash; the NAC source must support the peak so output and synchronization are maintained."},
  {id:151, block:2, sec:"Notification Appliance Circuits (NAC)", q:"A 'T-tap' (parallel branch) is generally NOT permitted on which circuit class without losing its rating?", opts:["Class B","Any low-voltage circuit","Class A (would break the redundant loop)","Power-limited only"], correct:2, re:"NFPA 72 12.3: Class A requires a continuous loop back to the panel; a T-tap defeats the redundant return and the Class A integrity benefit."},
  {id:152, block:2, sec:"Voice Evacuation / ECS", q:"Emergency Communications Systems are addressed in which chapter of NFPA 72?", opts:["Chapter 14","Chapter 18","Chapter 29","Chapter 24"], correct:3, re:"NFPA 72 Chapter 24 covers Emergency Communications Systems (ECS), including in-building fire EVAC and mass notification systems (MNS)."},
  {id:153, block:2, sec:"Voice Evacuation / ECS", q:"What is the average Speech Transmission Index (STI) that must be met in each acoustically distinguishable space (ADS) for an intelligible ECS?", opts:["0.50","0.45","0.35","0.70"], correct:0, re:"NFPA 72 Chapter 24 / Annex D: the average STI in each ADS must be at least 0.50, with at least 90% of points at or above 0.45."},
  {id:154, block:2, sec:"Voice Evacuation / ECS", q:"At least 90% of measurement points within an ADS must achieve an STI of not less than:", opts:["0.35","0.45","0.55","0.65"], correct:1, re:"NFPA 72 Annex D: 90% of measured points in each ADS must reach STI ≥ 0.45 (≈0.65 CIS), with the area average ≥ 0.50."},
  {id:155, block:2, sec:"Voice Evacuation / ECS", q:"An 'acoustically distinguishable space' (ADS) is a space distinguished by its:", opts:["Paint and lighting","Number of exits only","Acoustical, environmental, or use characteristics (e.g., reverberation, ambient level)","Ceiling color"], correct:2, re:"NFPA 72 3.3 / 24: an ADS is an area distinguished from others by acoustical, environmental, or use characteristics such as reverberation time and ambient sound pressure."},
  {id:156, block:2, sec:"Voice Evacuation / ECS", q:"In a combination fire alarm / mass notification system, NFPA 72 permits which message to take priority where the risk analysis requires it?", opts:["Always the fire alarm signal","The HVAC control signal","Neither; they cannot coexist","The mass notification (MNS) message"], correct:3, re:"NFPA 72 Chapter 24: although fire historically had highest priority, the risk analysis may give MNS priority over the fire alarm (e.g., active-threat scenarios)."},
  {id:157, block:2, sec:"Voice Evacuation / ECS", q:"A live voice message broadcast through an EVAC system shall be capable of overriding what?", opts:["The automatic (pre-recorded) evacuation message","The building's water supply","The sprinkler system","The elevator recall only"], correct:0, re:"NFPA 72 24.4: a properly authorized live voice announcement must be able to override the automatic prerecorded message for real-time instructions."},
  {id:158, block:2, sec:"Voice Evacuation / ECS", q:"For in-building MNS, the required pathway survivability level is determined by:", opts:["The strobe candela","The risk analysis","The ambient temperature","The number of pull stations"], correct:1, re:"NFPA 72 24.5: pathway survivability for in-building mass notification is established by the documented risk analysis rather than a fixed level."},
  {id:159, block:2, sec:"Voice Evacuation / ECS", q:"Distributed-recipient mass notification (e.g., text/email alerts) under NFPA 72:", opts:["May replace required audible/visible alerting","Is prohibited entirely","Shall not be used instead of required audible and visible alerting","Requires no integration"], correct:2, re:"NFPA 72 24.7: distributed-recipient MNS supplements but shall not replace required in-building audible and visible notification."},
  {id:160, block:2, sec:"Voice Evacuation / ECS", q:"Quantitative STI measurement under NFPA 72 is:", opts:["Always mandatory at every point","Required only for residential alarms","Forbidden","Not mandatory; a listening test may be acceptable, but criteria apply when measured"], correct:3, re:"NFPA 72 Annex D: intelligibility may be verified by a qualified listening test; if quantitative STI/CIS is measured, the 0.45/0.50 criteria apply."},
  {id:161, block:2, sec:"Voice Evacuation / ECS", q:"The main reason voice EVAC systems are used instead of horns alone in high-rises is to:", opts:["Provide intelligible instructions for phased/relocation evacuation","Reduce wiring","Lower the ambient sound level","Avoid strobes"], correct:0, re:"NFPA 72 24.4 / IBC: voice EVAC enables phased evacuation and relocation with clear spoken instructions, which a tone alone cannot convey."},
  {id:162, block:2, sec:"Voice Evacuation / ECS", q:"Before a voice (alert/alarm) tone signal in an ECS, NFPA 72 commonly uses what to gain attention?", opts:["A silent pause only","A preliminary alert/attention signal (e.g., tone) preceding the voice message","A strobe color change only","A sprinkler discharge"], correct:1, re:"NFPA 72 24.4: an alert tone typically precedes the voice message to capture attention before instructions are delivered."},
  {id:163, block:2, sec:"Voice Evacuation / ECS", q:"Speaker appliances in a voice system are usually selected by their power 'tap' setting (e.g., 1/4, 1/2, 1, 2 W) to control:", opts:["Strobe candela","EOL resistor value","Acoustic output (sound level) for the space","Battery chemistry"], correct:2, re:"NFPA 72 / design: speaker tap settings set the wattage and therefore the sound output, allowing audibility and intelligibility to be tuned per space."},
  {id:164, block:2, sec:"Voice Evacuation / ECS", q:"Wide-area mass notification systems (e.g., outdoor giant-voice) under NFPA 72 Chapter 24 are intended primarily to:", opts:["Provide only visible signals","Replace indoor smoke detectors","Operate elevators","Notify people outdoors over large areas"], correct:3, re:"NFPA 72 24.6: wide-area MNS (high-power speaker arrays / giant voice) deliver intelligible messages across large outdoor campus areas."},
  {id:165, block:2, sec:"Voice Evacuation / ECS", q:"In an ECS, the highest priority is generally assigned based on:", opts:["The relative life-safety risk as established by the system design/risk analysis","Whichever device activated first","Alphabetical message order","The lowest current draw"], correct:0, re:"NFPA 72 Chapter 24: message priority is set by life-safety risk per the design/risk analysis so the most critical instruction is broadcast."},
  {id:166, block:2, sec:"Voice Evacuation / ECS", q:"An autonomous control unit (ACU) in a mass notification system functions as:", opts:["The strobe lens","The control point that monitors and controls the MNS","An end-of-line resistor","A pull station only"], correct:1, re:"NFPA 72 24.3: the ACU is the primary control and monitoring point for the mass notification system, often interfaced with the fire alarm system."},
  {id:167, block:2, sec:"Voice Evacuation / ECS", q:"Voice intelligibility is most degraded in spaces with:", opts:["Low reverberation and low ambient noise","No occupants","High reverberation time and high ambient noise","Carpeted floors only"], correct:2, re:"NFPA 72 Annex D: long reverberation times and high background noise reduce STI, making such spaces harder to make intelligible."},
  {id:168, block:2, sec:"Voice Evacuation / ECS", q:"Which document section provides the methodology and guidance for ECS intelligibility?", opts:["ICC A117.1 only","NEC Chapter 9","OSHA 1926","NFPA 72 Annex D"], correct:3, re:"NFPA 72 Annex D contains the informational methodology for evaluating and designing for speech intelligibility in ECS."},
  {id:169, block:2, sec:"Synchronization & Survivability", q:"What is the maximum acceptable strobe flash rate permitted by NFPA 72?", opts:["2 Hz (120 fpm)","1 Hz (60 fpm)","3 Hz (180 fpm)","5 Hz (300 fpm)"], correct:0, re:"NFPA 72 18.5.4.4: visible appliances shall flash at a maximum of 2 Hz (120 flashes/min) to reduce photosensitive-seizure risk."},
  {id:170, block:2, sec:"Synchronization & Survivability", q:"What is the minimum flash rate required for a fire alarm strobe under NFPA 72?", opts:["0.5 Hz","1 Hz","2 Hz","4 Hz"], correct:1, re:"NFPA 72 18.5.4.4: the minimum flash rate is 1 Hz (60 flashes/min) to provide adequate visible notification."},
  {id:171, block:2, sec:"Synchronization & Survivability", q:"Strobe synchronization is required mainly to prevent:", opts:["Excess current draw","Audible feedback","Photosensitive epileptic seizures from cumulative flash rates in a field of view","EOL resistor failure"], correct:2, re:"NFPA 72 18.5.5.4.6 / Annex: synchronizing strobes keeps the composite flash rate in a field of view at or below the rate of two strobes, limiting seizure risk."},
  {id:172, block:2, sec:"Synchronization & Survivability", q:"Synchronization is required when how many visible appliances are within a person's field of view?", opts:["Any number, always 1","More than 5","Exactly 1","More than 2"], correct:3, re:"NFPA 72 18.5.5.4.6: where more than two visible appliances are in any field of view, they shall flash in synchronization."},
  {id:173, block:2, sec:"Synchronization & Survivability", q:"Pathway survivability levels in NFPA 72 are defined primarily in which chapter?", opts:["Chapter 12","Chapter 10","Chapter 18","Chapter 23"], correct:0, re:"NFPA 72 Chapter 12 (Circuits and Pathways) defines pathway survivability Levels 0-3 (Level 4 added in 2022)."},
  {id:174, block:2, sec:"Synchronization & Survivability", q:"For in-building fire EVAC systems serving relocation or partial evacuation, what minimum pathway survivability level is required?", opts:["Level 0","Level 2 (or 3)","Level 1","No survivability needed"], correct:1, re:"NFPA 72 24.3.6 / 12.4: systems using relocation or partial evacuation require Level 2 or Level 3 pathway survivability."},
  {id:175, block:2, sec:"Synchronization & Survivability", q:"Level 2 and Level 3 pathway survivability generally require:", opts:["No special wiring","Only plastic conduit","2-hour fire-rated cable or enclosure","Aluminum wire only"], correct:2, re:"NFPA 72 12.4: Level 2 and Level 3 survivability require 2-hour fire-rated circuit-integrity cable or enclosure; Level 3 also requires a fully sprinklered building."},
  {id:176, block:2, sec:"Synchronization & Survivability", q:"What additional building condition does Level 3 pathway survivability require beyond Level 2?", opts:["A standpipe only","Amber strobes","Two control panels","A fully sprinklered building"], correct:3, re:"NFPA 72 12.4: Level 3 survivability requires 2-hour-rated protection AND a building fully protected by automatic sprinklers."},
  {id:177, block:2, sec:"Synchronization & Survivability", q:"Level 4 pathway survivability, added in the 2022 edition, requires at minimum:", opts:["1-hour fire-rated cable or enclosure","No protection","Only metal raceway","Underground burial"], correct:0, re:"NFPA 72 (2022) 12.4: Level 4 was added requiring 1-hour fire-rated cables or enclosures (an option distinct from the 2-hour Levels 2/3)."},
  {id:178, block:2, sec:"Synchronization & Survivability", q:"Circuit-integrity (CI) cable is used in fire alarm systems specifically to provide:", opts:["Lower installation cost","Continued operation during a fire for a rated time","Better data speed","Color coding only"], correct:1, re:"NFPA 72 12.4: CI / fire-rated cable maintains circuit operation for a listed duration (e.g., 2 hours) under fire exposure, supporting survivability."},
  {id:179, block:2, sec:"Synchronization & Survivability", q:"To remain in synchronization, strobes on a circuit should generally be:", opts:["From any mix of manufacturers","Different candela only","Compatible/listed for synchronization (often same manufacturer/protocol)","Wired with reversed polarity"], correct:2, re:"NFPA 72 / listing: strobes must use a compatible synchronization protocol (commonly same-manufacturer sync) to flash together reliably."},
  {id:180, block:2, sec:"Synchronization & Survivability", q:"Where multiple strobes are visible at the intersection of an L-shaped corridor, synchronization addresses:", opts:["Reduced battery life","Conduit fill","Audible interference","The cumulative (composite) flash rate seen by an observer"], correct:3, re:"NFPA 72 Annex: a person at a corridor cross-point could see several strobes; sync keeps the composite flash rate at/below the two-strobe rate to limit seizure risk."},
  {id:181, block:2, sec:"Synchronization & Survivability", q:"Level 1 pathway survivability typically permits standard fire-rated wire when it is installed in a fully sprinklered building and run in:", opts:["Metal raceway or metal-armored cable","Open air","PVC only","No raceway at all"], correct:0, re:"NFPA 72 12.4: Level 1 allows conventional fire-rated cable in a sprinklered building when installed in metal raceway (conduit) or metal-armored cable."},
  {id:182, block:2, sec:"Synchronization & Survivability", q:"Pathway survivability requirements exist to ensure that, during a fire, notification circuits:", opts:["Use less power","Keep operating long enough to alert and relocate occupants","Flash a different color","Reduce sound output"], correct:1, re:"NFPA 72 12.4 intent: survivability keeps signaling pathways functional during fire exposure so occupants can be notified and moved to safety."},
  {id:183, block:2, sec:"Synchronization & Survivability", q:"Strobes that drift out of synchronization due to low voltage create what hazard NFPA 72 seeks to avoid?", opts:["Excess audibility","Color distortion","An unacceptable composite flash rate that may trigger seizures","Ground faults"], correct:2, re:"NFPA 72 18.5.5.4.6 / Annex: loss of sync raises the perceived composite flash rate in a field of view, the very condition synchronization is meant to prevent."},
  {id:184, block:2, sec:"Synchronization & Survivability", q:"Which is true about pathway survivability Level 0?", opts:["It provides 2-hour protection","It mandates Class A only","It requires sprinklers and 1-hour cable","It provides no specific survivability (no added fire protection of the pathway)"], correct:3, re:"NFPA 72 12.4: Level 0 indicates no pathway survivability is provided; higher levels add increasing fire protection of the circuit."},
  {id:185, block:2, sec:"Occupant Notification Requirements", q:"The standard audible evacuation signal pattern required by NFPA 72 is known as:", opts:["ANSI/Temporal-Three (T-3)","Temporal Code 4 (T-4)","March-time","Continuous tone"], correct:0, re:"NFPA 72 18.4.2: the standard evacuation signal is the ANSI S3.41 Temporal-Three (T-3) pattern."},
  {id:186, block:2, sec:"Occupant Notification Requirements", q:"The Temporal-Three pattern consists of three pulses, each 'on' for approximately:", opts:["0.25 s","0.5 s","1.0 s","1.5 s"], correct:1, re:"NFPA 72 18.4.2 / ANSI S3.41: T-3 is three 0.5 s 'on' pulses separated by 0.5 s 'off' gaps, then a 1.5 s pause, repeated."},
  {id:187, block:2, sec:"Occupant Notification Requirements", q:"After the three pulses, the Temporal-Three pattern includes an off-time (pause) of approximately:", opts:["0.5 s","1.0 s","1.5 s","3.0 s"], correct:2, re:"NFPA 72 / ANSI S3.41: the T-3 cycle ends with a 1.5 s 'off' period before the next set of three pulses begins."},
  {id:188, block:2, sec:"Occupant Notification Requirements", q:"One full Temporal-Three cycle (3 on/off pulses plus the long pause) lasts approximately:", opts:["2 seconds","8 seconds","6 seconds","4 seconds"], correct:3, re:"NFPA 72 / ANSI S3.41: three 0.5 s on + three 0.5 s off (≈3 s, with the last off being the 1.5 s pause) yields a ~4-second total cycle."},
  {id:189, block:2, sec:"Occupant Notification Requirements", q:"For a total evacuation signal, the Temporal-Three pattern must sound continuously for a minimum of:", opts:["180 seconds (3 minutes)","60 seconds","30 seconds","10 minutes"], correct:0, re:"NFPA 72 / ANSI S3.41: the T-3 evacuation signal must be capable of sounding for at least 180 seconds when total evacuation is intended."},
  {id:190, block:2, sec:"Occupant Notification Requirements", q:"Public-mode notification is intended to alert:", opts:["Only trained staff","The general building occupants","Only the monitoring station","Only maintenance personnel"], correct:1, re:"NFPA 72 3.3 / 18.4: public-mode signaling notifies general occupants and has higher sound-level requirements than private mode."},
  {id:191, block:2, sec:"Occupant Notification Requirements", q:"Private-mode notification is intended for:", opts:["The general public","Outdoor pedestrians","Persons directly concerned with implementation/response (e.g., trained staff)","Sleeping guests only"], correct:2, re:"NFPA 72 3.3: private-mode signaling alerts only persons concerned with the system's operation/response and permits lower sound levels (10 dBA above ambient)."},
  {id:192, block:2, sec:"Occupant Notification Requirements", q:"When the objective is full building evacuation, which signal takes precedence over other tones?", opts:["A continuous bell","A single chime","A coded march-time signal","The Temporal-Three evacuation pattern"], correct:3, re:"NFPA 72 18.4.2: the T-3 temporal pattern is the distinctive evacuation signal and takes precedence when total evacuation is intended."},
  {id:193, block:2, sec:"Occupant Notification Requirements", q:"Which pattern is specifically reserved by ANSI/NFPA so it is NOT used for routine, non-evacuation signaling?", opts:["Temporal-Three (T-3)","Continuous tone","Single short beep","Slow on/off at 0.1 Hz"], correct:0, re:"NFPA 72 / ANSI S3.41: the T-3 temporal pattern is reserved as the standard evacuation signal so occupants reliably recognize 'evacuate now'."},
  {id:194, block:2, sec:"Occupant Notification Requirements", q:"NFPA 72 designates the Carbon Monoxide alarm signal as a temporal-four (T-4) pattern to:", opts:["Match the fire signal exactly","Distinguish CO alarms from the fire evacuation (T-3) signal","Indicate a supervisory trouble","Signal end of test"], correct:1, re:"NFPA 72 / NFPA 720 legacy: CO alarms use a distinct Temporal-Four (T-4) pattern so occupants do not confuse a CO alarm with the fire T-3 evacuation signal."},
  {id:195, block:2, sec:"Occupant Notification Requirements", q:"A voice EVAC message that instructs occupants of specific floors to relocate rather than fully evacuate supports what strategy?", opts:["Silent alarm","Immediate total evacuation only","Defend-in-place / phased (relocation) evacuation","No notification"], correct:2, re:"NFPA 72 24.4 / IBC: voice EVAC enables phased/relocation strategies, moving only affected occupants while others shelter, common in high-rise and healthcare."},
  {id:196, block:2, sec:"Occupant Notification Requirements", q:"In occupancies with sleeping areas, occupant notification must additionally satisfy which special requirement?", opts:["Lower sound than public mode","No notification required","Strobes only, no audible","75 dBA at the pillow and a low-frequency signal"], correct:3, re:"NFPA 72 18.4.5: sleeping areas require at least 75 dBA at the pillow and a 520 Hz low-frequency signal for effective awakening."},
  {id:197, block:2, sec:"Occupant Notification Requirements", q:"The purpose of using a single recognizable evacuation signal (T-3) nationwide is to:", opts:["Ensure occupants universally recognize the 'evacuate' meaning","Reduce appliance cost","Limit strobe candela","Replace voice systems"], correct:0, re:"NFPA 72 / ANSI S3.41 intent: a standardized T-3 pattern creates universal recognition so people respond correctly regardless of the building."},
  {id:198, block:2, sec:"Occupant Notification Requirements", q:"Occupant notification appliances must be installed so the signal is:", opts:["Audible/visible only in corridors","Audible (and visible where required) throughout the areas requiring notification","Limited to the lobby","Active only at night"], correct:1, re:"NFPA 72 18.4 / 18.5: notification must reach all areas required to be notified, meeting sound-level and visible-coverage criteria throughout those areas."},
  {id:199, block:2, sec:"Occupant Notification Requirements", q:"Which best describes when private-mode signaling (lower levels) is acceptable instead of public mode?", opts:["Always, in any building","Only in single-family homes","Only where the AHJ/code permits and trained staff respond (e.g., certain healthcare)","Never"], correct:2, re:"NFPA 72 18.4.4: private mode is permitted where codes/AHJ allow and staff are responsible for occupant response, such as some healthcare units."},
  {id:200, block:2, sec:"Occupant Notification Requirements", q:"During an actual emergency, an authorized live voice announcement on the ECS is valuable because it can:", opts:["Lower the building temperature","Increase strobe candela automatically","Disable the sprinklers","Provide real-time, situation-specific instructions overriding the prerecorded message"], correct:3, re:"NFPA 72 24.4: a live voice message gives current, specific guidance and is designed to override the automatic prerecorded evacuation message."},
  {id:201, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"In NFPA 72 terminology, what is the primary role of the fire alarm control unit (FACU/FACP)?", opts:["It monitors initiating inputs and controls system outputs (notification and signaling)","It serves only as the audible notification appliance for the building","It is the off-premises receiver located at the supervising station","It is the manual pull station used to start an evacuation"], correct:0, re:"NFPA 72 Ch. 10/23: the fire alarm control unit is the component that monitors inputs (initiating devices/circuits) and controls outputs such as notification and off-premises signaling — the 'brain' of the system."},
  {id:202, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"NFPA 72 requires the secondary (standby) power supply of a typical fire alarm control unit to support the system in standby for at least how long?", opts:["4 hours","12 hours","24 hours","72 hours"], correct:2, re:"NFPA 72 §10.6 requires secondary power to operate the system for 24 hours of standby followed by the required alarm period."},
  {id:203, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"After 24 hours of standby on secondary power, a basic (non-voice) fire alarm system must then be able to operate in full alarm for at least:", opts:["5 minutes","10 minutes","15 minutes","60 minutes"], correct:0, re:"NFPA 72 §10.6: after 24 h standby, a basic fire alarm system must sound the alarm for 5 minutes; emergency voice/alarm communication (EVACS) systems require 15 minutes."},
  {id:204, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"For an in-building emergency voice/alarm communication system (EVACS), the secondary power alarm-operation period after 24 h standby is:", opts:["15 minutes","5 minutes","30 minutes","2 hours"], correct:0, re:"NFPA 72 §10.6: voice/alarm communication systems require 15 minutes of alarm operation (vs 5 minutes for basic systems) after the 24-hour standby period."},
  {id:205, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"The most common type of battery used as the secondary power source inside a fire alarm control unit is the:", opts:["Nickel-cadmium (NiCd) flooded cell","Lithium-ion pouch cell","Valve-regulated lead-acid (VRLA) battery","Alkaline primary cell"], correct:2, re:"NFPA 72 power-supply guidance: sealed valve-regulated lead-acid (VRLA) batteries are the predominant secondary power source housed in or near the FACU."},
  {id:206, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"Which condition has the HIGHEST priority in the NFPA 72 signal-priority hierarchy at the fire alarm control unit?", opts:["Trouble","Supervisory","Fire alarm","Pre-alarm"], correct:2, re:"NFPA 72 Ch. 10 signal priority: fire alarm signals take precedence over pre-alarm, which take precedence over supervisory, which take precedence over trouble (CO alarm is prioritized per its own provisions)."},
  {id:207, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"Which sequence correctly ranks signal priority at the FACU from highest to lowest (fire signals)?", opts:["Alarm > pre-alarm > supervisory > trouble","Trouble > supervisory > pre-alarm > alarm","Supervisory > alarm > trouble > pre-alarm","Pre-alarm > trouble > alarm > supervisory"], correct:0, re:"NFPA 72 Ch. 10: alarm takes precedence over pre-alarm, pre-alarm over supervisory, and supervisory over trouble."},
  {id:208, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"A closed sprinkler control (gate) valve monitored by a tamper switch produces which type of signal at the FACU?", opts:["Supervisory signal","Alarm signal","Trouble signal","Pre-alarm signal"], correct:0, re:"NFPA 72 Ch. 10/17: a need-for-action condition in equipment being monitored (e.g., a closed valve) is a supervisory signal, distinct from an alarm or a system trouble."},
  {id:209, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"A broken wire (open) on an initiating device circuit causes the FACU to indicate a:", opts:["Trouble signal","Alarm signal","Supervisory signal","Pre-alarm signal"], correct:0, re:"NFPA 72 Ch. 10/12: a fault on system wiring (such as an open conductor) is a trouble condition that must be annunciated as a trouble signal."},
  {id:210, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"NFPA 72 requires that the three core system conditions be distinctly indicated at the control unit. Those three conditions are:", opts:["Alarm, supervisory, and trouble","Standby, test, and reset","Primary, secondary, and tertiary","Local, remote, and proprietary"], correct:0, re:"NFPA 72 Ch. 10: the control unit must distinctively indicate alarm, supervisory, and trouble conditions (each visibly, and audibly for alarm/supervisory/trouble)."},
  {id:211, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"An annunciator located in the building lobby for first-responder use primarily provides:", opts:["Identification of the zone or device in alarm/trouble for responders","The building's primary 120 VAC power feed","Secondary battery charging for the panel","The off-premises communication path"], correct:0, re:"NFPA 72 Ch. 10/18: an annunciator provides status/location information (zone or point in alarm, supervisory, or trouble) to aid responders, separate from power or signaling functions."},
  {id:212, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"When primary (utility) power to the FACU fails, NFPA 72 requires the control unit to:", opts:["Automatically transfer to the secondary power supply and indicate a trouble","Silence all indications until power returns","Send an immediate fire alarm to the fire department","Shut down to protect the batteries"], correct:0, re:"NFPA 72 §10.6: loss of primary power must automatically transfer the load to secondary power, and an AC-power-loss trouble is indicated."},
  {id:213, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"What is the maximum number of overcurrent devices (e.g., the dedicated branch-circuit breaker) that the FACU primary supply circuit serves, and how is it identified per NFPA 72?", opts:["A dedicated branch circuit, mechanically protected and identified (e.g., red, labeled 'FIRE ALARM')","A shared circuit with general lighting, unmarked","Any convenience receptacle in the room","A GFCI-protected circuit shared with HVAC"], correct:0, re:"NFPA 72 §10.6: the primary supply must be a dedicated branch circuit, with the disconnecting means accessible only to authorized personnel, mechanically protected, and clearly identified (commonly red and labeled)."},
  {id:214, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"A trouble signal at the FACU that has been silenced (acknowledged) must, per NFPA 72, do what if the trouble condition is later restored and then recurs?", opts:["Re-sound for each new off-normal (trouble) condition","Remain silenced permanently","Convert automatically into an alarm","Reset the entire panel"], correct:0, re:"NFPA 72 Ch. 10: an audible trouble notification, even if previously silenced, must re-sound for each subsequent off-normal condition, ensuring new faults are not masked."},
  {id:215, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"Which of the following is NOT a function of the fire alarm control unit?", opts:["Supervising the integrity of its circuits","Activating notification appliances on alarm","Physically extinguishing the fire with onboard agent","Transmitting signals to a supervising station"], correct:2, re:"The FACU monitors, supervises, signals, and controls outputs; it does not itself extinguish fire. Suppression is performed by separate systems (sprinklers, clean agent), which the panel may release/monitor."},
  {id:216, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"NFPA 72 requires that a ground-fault condition that could impair operation of the fire alarm system be:", opts:["Indicated by a distinctive trouble signal","Ignored unless two faults occur","Recorded only at the supervising station","Cleared automatically without indication"], correct:0, re:"NFPA 72 Ch. 10/12: a single ground fault that affects required operation must result in a trouble signal indication at the control unit."},
  {id:217, block:3, sec:"Fire Alarm Control Unit (FACU)", q:"The 'listed' marking required on a fire alarm control unit indicates that the unit:", opts:["Has been evaluated to the applicable product standard by a recognized testing laboratory","Is owned by the local fire department","Was installed before 1990","Operates only on 12 VDC"], correct:0, re:"NFPA 72 §10.3 requires equipment to be listed for the purpose; listing means a recognized lab (e.g., UL) has evaluated the product to the applicable standard."},
  {id:218, block:3, sec:"Conventional vs Addressable", q:"In a conventional (zoned) fire alarm system, when a detector activates, the control unit can identify:", opts:["Only the zone (circuit) in which a device activated","The exact device that activated, by serial number","The specific room and device type automatically","Nothing — conventional panels give no location"], correct:0, re:"Conventional systems group devices on initiating device circuits (zones); the panel resolves location only to the zone, not the individual device. (NFPA 72 Ch. 23; industry practice.)"},
  {id:219, block:3, sec:"Conventional vs Addressable", q:"In an addressable fire alarm system, each initiating device:", opts:["Has its own unique address reported to the control unit","Shares one common address with all devices on the loop","Cannot report a specific location","Must be on its own dedicated two-wire circuit"], correct:0, re:"Addressable systems assign each device a unique address on the signaling line circuit, so the panel identifies the specific device and its location. (NFPA 72 Ch. 23; industry practice.)"},
  {id:220, block:3, sec:"Conventional vs Addressable", q:"The circuit type used to connect conventional change-of-state initiating devices (smoke/heat/pull stations) to the panel is the:", opts:["Signaling line circuit (SLC)","Notification appliance circuit (NAC)","Initiating device circuit (IDC)","Data communication bus (DCB)"], correct:2, re:"NFPA 72 Ch. 3/23: an initiating device circuit (IDC) connects conventional initiating devices to the control unit; the panel sees a change in current when a device operates."},
  {id:221, block:3, sec:"Conventional vs Addressable", q:"The circuit that carries addressable, multiplexed communication between the panel and intelligent devices is the:", opts:["Signaling line circuit (SLC)","Initiating device circuit (IDC)","Notification appliance circuit (NAC)","Primary power circuit"], correct:0, re:"NFPA 72 Ch. 3: a signaling line circuit (SLC) carries multiple-input/output signaling between addressable devices and the control unit (a data loop)."},
  {id:222, block:3, sec:"Conventional vs Addressable", q:"Conventional initiating devices on an IDC are typically wired so that, in normal standby, their contacts are:", opts:["Normally closed and open on alarm","Continuously cycling open and closed","Normally open and close on alarm","Disconnected until tested"], correct:2, re:"Conventional fire initiating devices are normally-open change-of-state devices that close on activation; the EOL resistor supervises the circuit for opens/shorts. (Industry standard; NFPA 72 Ch. 17/23.)"},
  {id:223, block:3, sec:"Conventional vs Addressable", q:"A key advantage of an addressable system over a conventional system for maintenance is:", opts:["It needs no secondary power","It eliminates the need for any wiring supervision","Faster pinpointing of the exact device in alarm or trouble","It cannot generate false alarms"], correct:2, re:"Because each point is individually identified, addressable systems let technicians locate the exact device in alarm/trouble, reducing troubleshooting time. (Industry practice; NFPA 72 Ch. 23.)"},
  {id:224, block:3, sec:"Conventional vs Addressable", q:"In a conventional system, if more device-location granularity is needed, the designer typically:", opts:["Adds more zones (more IDCs)","Assigns addresses to each detector","Removes the end-of-line resistors","Converts the NAC into an SLC"], correct:0, re:"Conventional location resolution is per-zone, so finer location requires adding zones/IDCs. Addressing is a feature of addressable (SLC) systems. (Industry practice.)"},
  {id:225, block:3, sec:"Conventional vs Addressable", q:"Which statement about addressable detectors is correct?", opts:["They report only a binary alarm/normal state like conventional units","They cannot be individually disabled at the panel","Many can report analog/sensitivity and maintenance (e.g., 'dirty') data to the panel","They require an end-of-line resistor at each detector"], correct:2, re:"Analog/addressable detectors commonly report sensitivity values and maintenance status (e.g., 'dirty sensor'), enabling features like drift compensation. (NFPA 72 Ch. 17 sensitivity; industry practice.)"},
  {id:226, block:3, sec:"Conventional vs Addressable", q:"The notification appliance circuit (NAC) in BOTH conventional and addressable systems is used to:", opts:["Power and control horns, strobes, and other notification appliances","Carry addressable device data","Provide the building's primary power","Connect to the off-premises supervising station"], correct:0, re:"NFPA 72 Ch. 3: a notification appliance circuit (NAC) connects and powers notification appliances (audible/visible). It exists in both system types."},
  {id:227, block:3, sec:"Conventional vs Addressable", q:"In an addressable system, an addressable module used to connect a conventional device or zone to the SLC is commonly called a(n):", opts:["End-of-line resistor","Power-limited fuse","Monitor (input) module","Annunciator driver"], correct:2, re:"A monitor (input) module places a conventional contact/IDC onto the addressable SLC, giving it an address. Control (relay/output) modules drive outputs. (Industry practice; NFPA 72 Ch. 23.)"},
  {id:228, block:3, sec:"Conventional vs Addressable", q:"Compared with a conventional system, the wiring topology of an addressable SLC loop most often:", opts:["Requires a separate pair of wires to every single device","Cannot be supervised","Uses a single pair routed through all devices (and optionally back to the panel)","Must be coaxial cable"], correct:2, re:"Addressable SLCs use a single communication pair routed through the devices; Class A loops return to the panel. Conventional systems need a circuit per zone. (Industry practice.)"},
  {id:229, block:3, sec:"Conventional vs Addressable", q:"Which is an accurate statement about conventional vs addressable annunciation of a single smoke detector?", opts:["Conventional gives device-level text; addressable gives only zone","Both give identical device-level identification","Addressable can display the specific detector/location; conventional displays the zone","Neither can indicate location"], correct:2, re:"Addressable resolves the specific device/location; conventional resolves to the zone only. (Industry practice; NFPA 72 Ch. 23.)"},
  {id:230, block:3, sec:"Conventional vs Addressable", q:"A 'hybrid' fire alarm panel is one that:", opts:["Uses only addressable devices","Has no secondary power","Supports both conventional IDC/zone modules and addressable SLC loops","Cannot be supervised"], correct:2, re:"Hybrid panels accept conventional zone cards and addressable loop cards, letting designers mix technologies. (Industry practice.)"},
  {id:231, block:3, sec:"Conventional vs Addressable", q:"In a conventional system, two separate detectors wired on the SAME zone (IDC) that both alarm will:", opts:["Be individually distinguished by the panel","Cancel each other out","Both simply indicate that zone is in alarm","Cause a trouble rather than an alarm"], correct:2, re:"Conventional zone circuits cannot distinguish which device on the zone activated; the panel shows the zone in alarm. (Industry practice; NFPA 72 Ch. 23.)"},
  {id:232, block:3, sec:"Conventional vs Addressable", q:"Which circuit type is generally NOT present in a purely conventional (non-addressable) system?", opts:["Initiating device circuit (IDC)","Notification appliance circuit (NAC)","Signaling line circuit (SLC)","Primary power circuit"], correct:2, re:"SLCs carry addressable signaling and are characteristic of addressable systems; purely conventional systems use IDCs and NACs. (NFPA 72 Ch. 3 definitions.)"},
  {id:233, block:3, sec:"Conventional vs Addressable", q:"An advantage often cited for conventional systems over addressable systems is:", opts:["Individual device addressing","Analog sensitivity reporting","Lower cost and simplicity for very small buildings","Built-in central station communication"], correct:2, re:"For very small installations, conventional systems can be lower cost and simpler; addressability's benefits (point ID, analog data) scale with building size. (Industry practice.)"},
  {id:234, block:3, sec:"Conventional vs Addressable", q:"In NFPA 72 terms, an 'addressable device' is one that:", opts:["Has a discrete address recognized individually by the control unit","Cannot communicate its status","Is always a notification appliance","Operates only on the NAC"], correct:0, re:"NFPA 72 Ch. 3: an addressable device has a discrete identification (address) that allows the control unit to identify it individually on the signaling line circuit."},
  {id:235, block:3, sec:"Signaling Line Circuits (SLC)", q:"A signaling line circuit (SLC) is best described as a circuit that:", opts:["Supplies primary 120 VAC power to the panel","Connects only notification appliances","Carries multiple inputs and/or outputs of addressable devices to the control unit","Is never supervised"], correct:2, re:"NFPA 72 Ch. 3: an SLC is a circuit/path between devices and the control unit over which multiple system inputs/outputs are carried — the addressable data loop."},
  {id:236, block:3, sec:"Signaling Line Circuits (SLC)", q:"On a Class B SLC, a single open (break) in the loop will:", opts:["Have no effect on any device","Convert the loop to Class A","Cause loss of communication with devices beyond the break","Cause an immediate building-wide alarm"], correct:2, re:"NFPA 72 Ch. 12: a Class B pathway has no redundant return path, so devices past a single open are lost (and a trouble is annunciated)."},
  {id:237, block:3, sec:"Signaling Line Circuits (SLC)", q:"On a Class A SLC, a single open in the loop results in:", opts:["Loss of all devices on the loop","A permanent alarm condition","Continued communication with all devices via the redundant return path","No trouble indication"], correct:2, re:"NFPA 72 Ch. 12: Class A provides a redundant return path; on a single open the panel feeds both ends, maintaining communication with all devices while annunciating trouble."},
  {id:238, block:3, sec:"Signaling Line Circuits (SLC)", q:"A device installed on an SLC loop that opens the circuit on either side of itself when it detects a short, to protect the rest of the loop, is a(n):", opts:["End-of-line resistor","Control/relay module","Short-circuit isolator (isolation) module","Power supervisory relay"], correct:2, re:"Short-circuit isolator modules segment an SLC: on a short they open to isolate the faulted segment so the remaining devices keep operating. (NFPA 72 Ch. 12 fault isolation; industry practice.)"},
  {id:239, block:3, sec:"Signaling Line Circuits (SLC)", q:"Per the 2016 and later editions of NFPA 72, a single fault on an SLC serving addressable devices shall not cause the loss of devices in more than:", opts:["The entire building","50 buildings","One zone of addressable devices","Three floors"], correct:2, re:"NFPA 72 (2016+) revised the prior '50 device' rule to require that a single SLC fault not disable more than one notification/zone area of addressable devices; isolators are used to meet this."},
  {id:240, block:3, sec:"Signaling Line Circuits (SLC)", q:"Addressable devices most commonly establish their address through:", opts:["Their physical wire color only","The supervising station","The length of cable from the panel","A DIP-switch/rotary setting or electronic (software) addressing"], correct:3, re:"Addresses are set by DIP/rotary switches or assigned electronically by the panel (software/auto-addressing), depending on the manufacturer. (Industry practice.)"},
  {id:241, block:3, sec:"Signaling Line Circuits (SLC)", q:"If two addressable devices on the same SLC are inadvertently set to the SAME address, the typical result is:", opts:["Both work perfectly","The panel renumbers them silently","An automatic alarm","A fault/trouble (address conflict) or one device not reporting"], correct:3, re:"Duplicate addresses cause a reporting conflict; panels typically annunciate a trouble or fail to communicate with one of the devices until corrected. (Industry practice.)"},
  {id:242, block:3, sec:"Signaling Line Circuits (SLC)", q:"The SLC is classified (Class A, B, X, N) based on:", opts:["Its wire gauge only","The color of the conductors","The brand of the panel","Its performance under fault conditions (open, short, ground)"], correct:3, re:"NFPA 72 Ch. 12: pathway class designations describe required performance under specified fault conditions, not the physical wire alone."},
  {id:243, block:3, sec:"Signaling Line Circuits (SLC)", q:"A Class X SLC differs from a Class A SLC in that Class X additionally:", opts:["Requires no return path","Uses only conventional devices","Cannot be supervised","Operates during a single SHORT as well as a single open (with isolation between devices)"], correct:3, re:"NFPA 72 Ch. 12: Class X is a redundant-path circuit that, unlike Class A, must also continue to operate during a single short by isolating faults between elements."},
  {id:244, block:3, sec:"Signaling Line Circuits (SLC)", q:"A control (output) module on an SLC is used to:", opts:["Set the panel's clock","Replace the EOL resistor on the NAC","Provide primary power","Drive an output such as a relay, NAC, or door release from an address"], correct:3, re:"Control/relay modules occupy an SLC address and actuate outputs (relays, conventional NACs, releasing, door functions) under panel command. (Industry practice; NFPA 72 Ch. 23.)"},
  {id:245, block:3, sec:"Signaling Line Circuits (SLC)", q:"A monitor (input) module on an SLC is used to:", opts:["Power notification appliances directly","Communicate with the supervising station","Charge the secondary batteries","Bring a conventional contact or IDC onto the addressable loop with an address"], correct:3, re:"Monitor/input modules provide an address for a dry contact or conventional IDC (e.g., waterflow, supervisory switch) on the SLC. (Industry practice; NFPA 72 Ch. 23.)"},
  {id:246, block:3, sec:"Signaling Line Circuits (SLC)", q:"NFPA 72 requires that the integrity of an SLC be:", opts:["Tested only at installation, never again","Left unsupervised if addressable","Monitored only by the supervising station","Automatically and continuously monitored for fault conditions"], correct:3, re:"NFPA 72 Ch. 12/10: installation conductors and pathways, including SLCs, must be automatically monitored for integrity so faults produce a trouble signal."},
  {id:247, block:3, sec:"Signaling Line Circuits (SLC)", q:"Which fault on a Class B SLC would a properly supervised panel annunciate as a trouble?", opts:["Only a short, never an open","No faults are annunciated on Class B","Only a device-level dirty sensor","A single open OR a single ground fault on the loop"], correct:3, re:"NFPA 72 Ch. 12: a single open or single ground fault on a monitored pathway must be annunciated as a trouble within the required time."},
  {id:248, block:3, sec:"Signaling Line Circuits (SLC)", q:"Using short-circuit isolators on an SLC primarily improves:", opts:["The panel's primary power capacity","The color rendering of strobes","The audibility of horns","Loop survivability by limiting how many devices a single short can disable"], correct:3, re:"Isolators confine a short to one segment so the rest of the loop keeps communicating, improving SLC fault tolerance/survivability. (NFPA 72 Ch. 12; industry practice.)"},
  {id:249, block:3, sec:"Signaling Line Circuits (SLC)", q:"On an SLC, the term 'T-tap' (branch) wiring refers to:", opts:["A redundant return path back to the panel","A short-circuit isolator only","An end-of-line resistor location","A spur/branch off the main loop run"], correct:3, re:"A T-tap is a branch off the SLC trunk; whether T-taps are permitted depends on the pathway class and manufacturer (Class A/X require continuity that limits unsupervised taps). (Industry practice.)"},
  {id:250, block:3, sec:"Signaling Line Circuits (SLC)", q:"In an addressable system, the panel knows a device has been REMOVED from the SLC because:", opts:["The device's address stops responding to polling and a trouble is generated","Removed devices have no effect","The building alarm activates","The supervising station calls back"], correct:0, re:"The panel continuously polls each address; a missing/non-responding address produces a trouble (e.g., 'device missing'). (NFPA 72 Ch. 10/12 supervision; industry practice.)"},
  {id:251, block:3, sec:"Pathway Classes & Survivability", q:"Per NFPA 72 Ch. 12, a Class B pathway is one that:", opts:["Includes a redundant return path to the control unit","Is reserved for network (Ethernet) pathways","Continues operating during both a single open and a single short","Operates without a redundant path; devices past a single open are lost"], correct:3, re:"NFPA 72 Ch. 12: Class B has no redundant path; a single open disables devices downstream of the fault (a trouble is annunciated)."},
  {id:252, block:3, sec:"Pathway Classes & Survivability", q:"Per NFPA 72 Ch. 12, a Class A pathway:", opts:["Has no supervision","Requires fiber optic cable","Cannot detect a ground fault","Includes a redundant path and continues to operate during a single open"], correct:3, re:"NFPA 72 Ch. 12: Class A includes a redundant (return) path so operation continues during a single open; the fault is still annunciated as trouble."},
  {id:253, block:3, sec:"Pathway Classes & Survivability", q:"Per NFPA 72 Ch. 12, a Class X pathway must continue to operate during:", opts:["Only a single open","No faults at all","Only a single ground fault","Both a single open and a single short (with fault isolation)"], correct:3, re:"NFPA 72 Ch. 12: Class X is a redundant-path pathway that continues to operate during a single open AND a single short, providing isolation between devices."},
  {id:254, block:3, sec:"Pathway Classes & Survivability", q:"Per NFPA 72 Ch. 12, a Class N pathway refers to:", opts:["A single non-supervised wire run","A two-way radio frequency link only","A conventional IDC with an EOL resistor","A network pathway with redundancy verified by end-to-end communication"], correct:3, re:"NFPA 72 Ch. 12: Class N is a network (e.g., Ethernet) pathway; where two or more paths exist, operational capability to each device is verified by end-to-end communication and loss is annunciated as trouble."},
  {id:255, block:3, sec:"Pathway Classes & Survivability", q:"On a Class N pathway, a single open, short, or ground fault on one pathway shall:", opts:["Disable the entire network","Trigger a building alarm","Be ignored entirely","Not affect operation of any other (redundant) pathway"], correct:3, re:"NFPA 72 Ch. 12: for Class N, a single fault on one pathway must not affect any other pathway, and loss of intended communication is annunciated as a trouble."},
  {id:256, block:3, sec:"Pathway Classes & Survivability", q:"Which legacy 'Style' designation corresponds to the modern Class A signaling line circuit?", opts:["Style 4","Style 0.5","Style Z","Style 6"], correct:3, re:"NFPA 72 history: the former SLC Style 6 (redundant path, survives a single open) maps to today's Class A; Style 4 maps to Class B; Style 7 maps to Class X."},
  {id:257, block:3, sec:"Pathway Classes & Survivability", q:"Which legacy SLC 'Style' designation corresponds to the modern Class B circuit?", opts:["Style 4","Style 6","Style 7","Style N"], correct:0, re:"NFPA 72 history: SLC Style 4 (no redundant path) maps to Class B; Style 6 to Class A; Style 7 to Class X."},
  {id:258, block:3, sec:"Pathway Classes & Survivability", q:"Which legacy SLC 'Style' designation corresponds to the modern Class X circuit?", opts:["Style 4","Style 6","Style 7","Style B"], correct:2, re:"NFPA 72 history: SLC Style 7 (redundant path that also survives a short, with isolation) maps to Class X."},
  {id:259, block:3, sec:"Pathway Classes & Survivability", q:"NFPA 72 pathway SURVIVABILITY addresses a pathway's ability to:", opts:["Resist electrical noise","Reduce installation cost","Carry higher voltage","Continue to operate for a period during attack by fire"], correct:3, re:"NFPA 72 Ch. 12: pathway survivability concerns whether circuit integrity is maintained during fire exposure, so messages still reach areas not yet notified."},
  {id:260, block:3, sec:"Pathway Classes & Survivability", q:"NFPA 72 pathway survivability Level 0 means the pathway:", opts:["Requires 2-hour fire-rated cable","Requires metal raceway","Must be in a fully sprinklered building","Has no defined survivability requirement"], correct:3, re:"NFPA 72 Ch. 12: Level 0 imposes no survivability requirement on the pathway."},
  {id:261, block:3, sec:"Pathway Classes & Survivability", q:"NFPA 72 pathway survivability Level 1 generally relies on:", opts:["2-hour fire-rated circuit integrity cable","An automatic sprinkler system alone with no raceway","No protection at all","Conductors in metal raceway/armored cable within a fully sprinklered building"], correct:3, re:"NFPA 72 Ch. 12: Level 1 uses pathways in a building fully protected by automatic sprinklers with the conductors in metal raceway or metal-armored cable."},
  {id:262, block:3, sec:"Pathway Classes & Survivability", q:"NFPA 72 pathway survivability Level 2 is achieved by methods such as:", opts:["Ordinary THHN in EMT, no rating","Plenum-rated cable alone","12 VDC operation","2-hour fire-rated circuit integrity (CI) cable, a 2-hour fire-rated cable system, or a 2-hour enclosure"], correct:3, re:"NFPA 72 Ch. 12: Level 2 consists of 2-hour fire-rated CI cable, a listed 2-hour electrical circuit protective system, or a 2-hour fire-rated enclosure/protected area."},
  {id:263, block:3, sec:"Pathway Classes & Survivability", q:"NFPA 72 pathway survivability Level 3 differs from Level 2 in that Level 3 also requires:", opts:["No fire rating at all","A second control unit","Fiber optic cable","The building to be fully protected by an automatic sprinkler system (added to Level 2 methods)"], correct:3, re:"NFPA 72 Ch. 12: Level 3 combines Level 2's 2-hour-rated methods with a fully sprinklered building."},
  {id:264, block:3, sec:"Pathway Classes & Survivability", q:"For an emergency communications system that employs partial evacuation or relocation, NFPA 72 requires a pathway survivability of at least:", opts:["Level 0","Level 1","Level 2 (or Level 3)","No requirement"], correct:2, re:"NFPA 72 Ch. 12/24: systems using relocation or partial evacuation must have Level 2 or Level 3 pathway survivability so messages reach occupants not yet notified."},
  {id:265, block:3, sec:"Pathway Classes & Survivability", q:"An important nuance of NFPA 72 survivability levels is that they are:", opts:["Strictly hierarchical, with higher numbers always superior","Only about notification appliance loudness","Identical to the pathway classes A/B/X/N","A list of different performance methods, not a simple 'higher is better' ranking"], correct:3, re:"NFPA 72 Ch. 12 annex/intent: the levels describe different protection methods/criteria; they are not a strict ranking where a higher number is automatically superior in all respects."},
  {id:266, block:3, sec:"Pathway Classes & Survivability", q:"Pathway survivability requirements generally apply to circuits until they:", opts:["Leave the building","Are powered up","Reach the first device","Enter the notification zone they serve"], correct:3, re:"NFPA 72 Ch. 12/24: survivability is required for circuits passing through other zones; once a circuit is within the notification zone it serves, lower survivability may be acceptable."},
  {id:267, block:3, sec:"Pathway Classes & Survivability", q:"Which statement correctly contrasts pathway CLASS with pathway SURVIVABILITY?", opts:["Class addresses fire exposure; survivability addresses electrical faults","Neither relates to fault tolerance","They are the same requirement","Class addresses electrical fault performance; survivability addresses physical/fire protection of the pathway"], correct:3, re:"NFPA 72 Ch. 12: pathway CLASS (A/B/X/N) defines performance under electrical faults; pathway SURVIVABILITY (Level 0-3) defines physical resistance to fire exposure — two separate concepts."},
  {id:268, block:3, sec:"End-of-Line & Supervision", q:"The primary purpose of an end-of-line resistor (EOLR) on a conventional IDC or NAC is to:", opts:["Increase notification appliance loudness","Set the device address","Provide secondary power","Allow the panel to supervise the wiring for open and short conditions"], correct:3, re:"The EOLR establishes a known supervisory current so the panel can detect an open (loss of current) or short (excess current) on the circuit, generating a trouble. (NFPA 72 Ch. 10/23; industry practice.)"},
  {id:269, block:3, sec:"End-of-Line & Supervision", q:"On a supervised conventional IDC, an OPEN circuit (broken wire) typically appears to the panel as:", opts:["Loss of supervisory current → trouble","Excess current → alarm","Normal","Increased voltage at the device"], correct:0, re:"With the EOLR in place, an open removes the supervisory current path; the panel sees loss of current and annunciates a trouble. (Industry practice; NFPA 72 Ch. 10.)"},
  {id:270, block:3, sec:"End-of-Line & Supervision", q:"On a supervised conventional IDC with normally-open devices, a SHORT across the conductors typically produces:", opts:["A trouble only","An ALARM indication (the short mimics a closed device)","Nothing","A supervisory signal"], correct:1, re:"Because conventional initiating devices alarm by shorting/closing the loop, a wiring short across an IDC generally reads as an alarm. (Industry practice; this is why proper supervision and wiring practices matter.)"},
  {id:271, block:3, sec:"End-of-Line & Supervision", q:"Where must the end-of-line resistor be physically located on a conventional supervised circuit?", opts:["Inside the control panel only","At the panel terminals","At the electrical end of the circuit (after the last device)","At the midpoint of the run"], correct:2, re:"The EOLR must be at the far/electrical end of the circuit so the entire wiring run is within the supervised loop; placing it at the panel would leave field wiring unsupervised. (Industry practice; NFPA 72 Ch. 10.)"},
  {id:272, block:3, sec:"End-of-Line & Supervision", q:"NFPA 72 requires that a single open or ground fault on a circuit be annunciated as a trouble within a maximum of:", opts:["200 seconds","10 minutes","1 hour","24 hours"], correct:0, re:"NFPA 72 Ch. 12/10: a single open or single ground fault must be detected and annunciated as a trouble within 200 seconds."},
  {id:273, block:3, sec:"End-of-Line & Supervision", q:"On a notification appliance circuit (NAC), the end-of-line device also lets the panel verify:", opts:["The address of each strobe","Wiring integrity (open/short) so a break is detected before an alarm is needed","The color temperature of strobes","The building's primary voltage"], correct:1, re:"The NAC EOL device supervises wiring continuity/polarity so a fault is annunciated as trouble, ensuring appliances will operate when called. (NFPA 72 Ch. 10; industry practice.)"},
  {id:274, block:3, sec:"End-of-Line & Supervision", q:"Why are conventional NAC appliances typically polarized (with blocking diodes)?", opts:["To make them louder","So the circuit can be supervised in standby with reverse polarity and energized with normal polarity on alarm","To set their address","To reduce their current draw to zero"], correct:1, re:"Polarized appliances let the panel apply a small reverse-polarity supervisory voltage in standby (appliances off) and normal polarity on alarm (appliances on), enabling supervision. (Industry practice; NFPA 72 Ch. 10.)"},
  {id:275, block:3, sec:"End-of-Line & Supervision", q:"Circuit 'supervision' in NFPA 72 fundamentally means the system:", opts:["Records video of the panel","Automatically monitors the integrity of conductors/pathways and signals faults","Requires a guard to watch the panel","Tests devices only annually"], correct:1, re:"NFPA 72 Ch. 10/12: supervision/monitoring for integrity means the system automatically detects faults (opens, grounds, etc.) in its circuits and indicates a trouble."},
  {id:276, block:3, sec:"End-of-Line & Supervision", q:"A ground fault on fire alarm wiring is a concern because it can:", opts:["Improve circuit reliability","Potentially impair correct operation, so it must be annunciated as trouble","Increase battery life","Set device addresses automatically"], correct:1, re:"NFPA 72 Ch. 10/12: a ground fault that could affect required operation must be detected and annunciated as a trouble within the required time (200 s)."},
  {id:277, block:3, sec:"End-of-Line & Supervision", q:"In an addressable system, the function performed by an EOLR on conventional circuits is instead achieved by:", opts:["A larger battery","Continuous polling/communication supervision of each addressable device","Removing all supervision","A louder horn"], correct:1, re:"Addressable loops supervise by polling each address; loss of response yields a trouble, replacing the EOLR's role on conventional circuits. (Industry practice; NFPA 72 Ch. 10/12.)"},
  {id:278, block:3, sec:"End-of-Line & Supervision", q:"Replacing a required end-of-line resistor with a jumper (shorting it out) on a conventional NAC would:", opts:["Have no effect","Defeat supervision and could mask an open/short fault — a code violation","Make appliances brighter","Add an address to the circuit"], correct:1, re:"Removing/jumpering the EOLR defeats wiring supervision, violating NFPA 72's monitoring-for-integrity requirement and risking undetected faults. (NFPA 72 Ch. 10; industry practice.)"},
  {id:279, block:3, sec:"End-of-Line & Supervision", q:"The value of an end-of-line resistor for a given circuit is determined by:", opts:["The installer's preference","The control panel manufacturer's specifications for that circuit","The supervising station","The length of the building"], correct:1, re:"EOLR value must match the panel's listed circuit design; using the wrong value can prevent proper open/short discrimination. (Manufacturer spec; NFPA 72 Ch. 10.)"},
  {id:280, block:3, sec:"End-of-Line & Supervision", q:"Supervision of the secondary (battery) power is required so that the panel can detect a:", opts:["Dirty smoke detector","Disconnected, low, or failed battery and indicate trouble","Closed sprinkler valve","Loss of strobe synchronization"], correct:1, re:"NFPA 72 §10.6: the system must monitor for the presence/condition of the secondary power source (battery), indicating trouble for a missing or low battery."},
  {id:281, block:3, sec:"End-of-Line & Supervision", q:"A 'class change' from Class B to Class A wiring improves supervision by adding:", opts:["A larger EOLR","A redundant return path so a single open still permits operation","More notification appliances","A second supervising station"], correct:1, re:"Class A routes the circuit back to the panel (redundant path); a single open is then bridged, maintaining operation while still annunciating trouble. (NFPA 72 Ch. 12.)"},
  {id:282, block:3, sec:"End-of-Line & Supervision", q:"NFPA 72 generally requires that a trouble condition on the system be:", opts:["Visible at the control unit and produce an audible trouble notification","Logged only at the supervising station, never shown locally","Indicated only during business hours","Silenced permanently after the first occurrence"], correct:0, re:"NFPA 72 Ch. 10: trouble conditions must be visibly indicated at the control unit and accompanied by an audible trouble signal (which re-sounds for new troubles)."},
  {id:283, block:3, sec:"End-of-Line & Supervision", q:"Which best describes why fire alarm circuits are 'supervised' rather than simply wired?", opts:["To reduce wire cost","So that wiring faults are detected automatically and the system's readiness is continuously verified","To eliminate the need for testing","To make installation faster"], correct:1, re:"Supervision ensures latent wiring faults (opens/grounds/shorts) are found and annunciated before they prevent the system from operating in an emergency. (NFPA 72 Ch. 10/12.)"},
  {id:284, block:3, sec:"End-of-Line & Supervision", q:"On a conventional IDC, the supervisory current that flows through the EOLR in normal standby is:", opts:["Zero amps","A small current too low to activate notification but enough for the panel to sense integrity","The same as full alarm current","Equal to the primary 120 VAC"], correct:1, re:"In standby a small supervisory current flows through the EOLR; the panel senses this to confirm continuity, while it is too small to operate appliances. (Industry practice; NFPA 72 Ch. 10.)"},
  {id:285, block:3, sec:"Off-Premises / Central Station Signaling", q:"NFPA 72 Chapter 26 covers which category of systems?", opts:["Single- and multiple-station household alarms","Supervising station alarm systems (central, proprietary, remote)","Notification appliance spacing","Detector sensitivity testing"], correct:1, re:"NFPA 72 Ch. 26 addresses supervising station alarm systems — central station, proprietary, and remote supervising station service."},
  {id:286, block:3, sec:"Off-Premises / Central Station Signaling", q:"A digital alarm communicator transmitter (DACT) at the protected premises, when transmitting, must:", opts:["Leave the phone line free for outgoing calls","Seize the telephone line (line-seizure) and disconnect any call in progress to send the signal","Wait until business hours","Use only fiber optic cable"], correct:1, re:"NFPA 72 Ch. 26: a DACT must seize the line (go off-hook), disconnecting any existing call, and prevent outgoing calls until the signal is sent — ensuring the alarm gets through."},
  {id:287, block:3, sec:"Off-Premises / Central Station Signaling", q:"The maximum time from initiation of a single alarm signal at the protected premises until it is recorded at the supervising station shall not exceed:", opts:["10 seconds","90 seconds","10 minutes","1 hour"], correct:1, re:"NFPA 72 Ch. 26: the maximum elapsed time from initiation of a single alarm signal to its recording at the supervising station is 90 seconds."},
  {id:288, block:3, sec:"Off-Premises / Central Station Signaling", q:"A traditional DACT arrangement using telephone lines historically required the transmitter to be connected to:", opts:["One unsupervised line only","Two means of transmission (e.g., two phone lines, or one line plus another technology)","Four phone lines","No supervised path"], correct:1, re:"NFPA 72 Ch. 26: legacy DACTs used two telephone lines; later editions allow one line plus another technology (cellular/IP) so a single failure does not block reporting."},
  {id:289, block:3, sec:"Off-Premises / Central Station Signaling", q:"Failure of the supervising station to receive the scheduled test signal from a DACT/communicator is treated as a:", opts:["Alarm signal","Trouble signal","Supervisory signal","Normal event"], correct:1, re:"NFPA 72 Ch. 26: failure to receive an expected test/check-in signal indicates a possible communications loss and is handled as a trouble signal."},
  {id:290, block:3, sec:"Off-Premises / Central Station Signaling", q:"Performance-based communication technologies recognized by NFPA 72 for off-premises fire signaling include:", opts:["Only copper telephone lines","Cellular and Internet Protocol (IP) communicators","Smoke signals","Public address only"], correct:1, re:"NFPA 72 Ch. 26 performance-based technology encompasses IP and cellular communicators, which can serve as single-path technologies when they meet the performance/supervision requirements."},
  {id:291, block:3, sec:"Off-Premises / Central Station Signaling", q:"In NFPA 72 'central station service,' the on-site responsibilities that are part of the service include installation, testing, maintenance, and:", opts:["Manufacturing the panel","Runner (response) service","Writing the building code","Providing primary utility power"], correct:1, re:"NFPA 72 Ch. 26: central station service includes the supervising-station functions (monitoring, retransmission, recordkeeping) plus protected-premises functions of installation, testing, maintenance, and runner service."},
  {id:292, block:3, sec:"Off-Premises / Central Station Signaling", q:"When a condition requires a runner to be dispatched to the protected premises, NFPA 72 central station service requires arrival within:", opts:["15 minutes","30 minutes","2 hours","8 hours"], correct:2, re:"NFPA 72 Ch. 26: where a runner is required (e.g., an unrestored condition), the runner must reach the protected premises within 2 hours of the signal."},
  {id:293, block:3, sec:"Off-Premises / Central Station Signaling", q:"A proprietary supervising station differs from a central station in that the proprietary station is:", opts:["Operated by a third-party company for many owners","Owned and operated by the property owner, monitoring property under that single ownership","Located inside the fire department only","Never staffed"], correct:1, re:"NFPA 72 Ch. 26: a proprietary supervising station is owned/operated by the protected property's owner and serves contiguous/related properties under that ownership, with trained personnel in attendance."},
  {id:294, block:3, sec:"Off-Premises / Central Station Signaling", q:"A remote supervising station alarm system is characterized by:", opts:["Serving multiple unrelated owners, often with signals received at a remote location such as a fire/communications center","Being located at the protected premises only","Requiring no monitoring personnel","Using only manual telephone reporting"], correct:0, re:"NFPA 72 Ch. 26: remote supervising station service receives signals at a location remote from the protected premises (e.g., a fire department or contracted facility) for properties under various ownerships."},
  {id:295, block:3, sec:"Off-Premises / Central Station Signaling", q:"The secondary power supply for transmitters/equipment at the protected premises needed for off-premises signaling must provide a minimum of:", opts:["2 hours","8 hours","24 hours","7 days"], correct:2, re:"NFPA 72 Ch. 26: secondary power for the transmission equipment at the protected premises must be a minimum of 24 hours."},
  {id:296, block:3, sec:"Off-Premises / Central Station Signaling", q:"A DACR (digital alarm communicator receiver) is located:", opts:["At the protected premises","At the supervising station, where it receives signals from DACTs","Inside each smoke detector","On the notification appliance circuit"], correct:1, re:"NFPA 72 Ch. 26: the DACR is the receiving equipment at the supervising station that accepts and acknowledges signals transmitted by DACTs at protected premises."},
  {id:297, block:3, sec:"Off-Premises / Central Station Signaling", q:"For a DACT, the time from going off-hook to on-hook for a transmission attempt shall not exceed:", opts:["5 seconds","90 seconds","5 minutes","30 minutes"], correct:1, re:"NFPA 72 Ch. 26: a DACT transmission attempt (off-hook to on-hook) shall not exceed 90 seconds per attempt."},
  {id:298, block:3, sec:"Off-Premises / Central Station Signaling", q:"The chief life-safety benefit of off-premises (supervising station) signaling is that:", opts:["It silences the building horns","Qualified personnel are notified and the fire service can be dispatched even if no one is on site","It eliminates the need for a control unit","It replaces sprinkler systems"], correct:1, re:"NFPA 72 Ch. 26 intent: supervising station service ensures alarm, supervisory, and trouble signals reach attended personnel for response/dispatch regardless of building occupancy."},
  {id:299, block:3, sec:"Off-Premises / Central Station Signaling", q:"Which signals are typically transmitted off-premises to the supervising station?", opts:["Only fire alarm signals","Alarm, supervisory, and trouble signals","Only trouble signals","Only the building's power usage"], correct:1, re:"NFPA 72 Ch. 26: the off-premises connection conveys alarm, supervisory, and trouble signals so each condition can be acted upon appropriately."},
  {id:300, block:3, sec:"Off-Premises / Central Station Signaling", q:"When a single communications technology (e.g., one IP or cellular path) is used for off-premises signaling, NFPA 72 requires that a failure of that path be:", opts:["Never reported","Annunciated/recorded at the supervising station within the code's required supervision interval","Reported only at the next annual test","Allowed to go undetected for a week"], correct:1, re:"NFPA 72 Ch. 26: single-technology paths must be supervised so a communications failure is annunciated at the supervising station within the prescribed interval (e.g., 60 minutes in recent editions). (Exact interval is edition-dependent.)"},
  {id:301, block:4, sec:"Primary & Secondary Power", q:"Per NFPA 72, the primary power supply for a fire alarm system is most commonly which of the following?", opts:["The commercial light and power utility branch circuit","The standby storage battery set","An automatic-starting engine-driven generator","An uninterruptible power supply (UPS) used alone"], correct:0, re:"NFPA 72 Ch.10 identifies the primary (main) source as the light and power service, typically a dedicated branch circuit from the commercial utility. (NFPA 72-2022, 10.6.5)"},
  {id:302, block:4, sec:"Primary & Secondary Power", q:"What is the MINIMUM standby (quiescent) period the secondary power supply of a protected-premises fire alarm system must support before any alarm load is applied?", opts:["24 hours","12 hours","48 hours","60 hours"], correct:0, re:"NFPA 72 requires the secondary supply to carry the quiescent load for at least 24 hours. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:303, block:4, sec:"Primary & Secondary Power", q:"After the required standby period, a non-voice fire alarm system's secondary power must operate all evacuation notification appliances for at least how long?", opts:["10 minutes","5 minutes","15 minutes","30 minutes"], correct:1, re:"NFPA 72 requires 5 minutes of full alarm operation after 24 h standby for a standard (non-voice) system. (NFPA 72-2022, 10.6.7.2)"},
  {id:304, block:4, sec:"Primary & Secondary Power", q:"For an in-building fire emergency voice/alarm communication system (EVACS), the secondary-power alarm duration after standby increases from 5 minutes to what value?", opts:["15 minutes","10 minutes","20 minutes","60 minutes"], correct:0, re:"Where the system includes in-building voice/alarm communications, the post-standby alarm operating time is 15 minutes. (NFPA 72-2022, 10.6.7.2.2)"},
  {id:305, block:4, sec:"Primary & Secondary Power", q:"NFPA 72 permits the secondary power source of a protected-premises system to be which of the following?", opts:["Only a storage battery in every case","Only a generator in every case","A capacitor bank sized for 24 hours","A storage battery, OR an automatic-starting engine-driven generator"], correct:3, re:"Acceptable secondary sources are a storage battery or an automatic-starting engine-driven generator. (NFPA 72-2022, 10.6.7)"},
  {id:306, block:4, sec:"Primary & Secondary Power", q:"When an engine-driven generator is used as the secondary power source, NFPA 72 still requires storage batteries sized for at least how many hours so the system runs if the generator fails to start?", opts:["1 hour","4 hours","2 hours","24 hours"], correct:1, re:"A generator used as secondary power must be backed by batteries providing at least 4 hours of operation in case it does not start. (NFPA 72-2022, 10.6.7.2)"},
  {id:307, block:4, sec:"Primary & Secondary Power", q:"Loss of the primary (AC) power source to a fire alarm control unit must be indicated as which type of signal at the control unit?", opts:["A trouble signal","An alarm signal","A pre-alarm signal","No indication is required"], correct:0, re:"Loss of primary power is a fault condition; NFPA 72 requires it be annunciated as a trouble signal. (NFPA 72-2022, 10.6 / 10.15)"},
  {id:308, block:4, sec:"Primary & Secondary Power", q:"The dedicated branch circuit supplying a fire alarm control unit's primary power must have its disconnecting means identified. The marking typically reads:", opts:["\"DO NOT TOUCH\" in yellow","\"FIRE ALARM CIRCUIT CONTROL\" in red","\"GENERAL LIGHTING\" in black","No marking is required"], correct:1, re:"NFPA 72 / NEC 760.41 require the branch-circuit disconnect be identified in red as the fire alarm circuit control, with a lock/tag means. (NFPA 72-2022, 10.6.6; NEC 760.41)"},
  {id:309, block:4, sec:"Primary & Secondary Power", q:"A UPS or stored-electrical-energy system used as the secondary power source for a fire alarm system should be built and maintained in accordance with which standard?", opts:["NFPA 13","NFPA 111 (with engine generators per NFPA 110)","NFPA 25","NFPA 1221 only"], correct:1, re:"NFPA 72 references stored-energy/UPS systems per NFPA 111 and engine generators per NFPA 110. (NFPA 72-2022, 10.6.9)"},
  {id:310, block:4, sec:"Primary & Secondary Power", q:"The fire alarm control unit must be able to fully recharge a fully discharged secondary battery within what maximum time?", opts:["24 hours","72 hours","96 hours","48 hours"], correct:3, re:"NFPA 72 requires the battery be capable of full recharge by the control unit within 48 hours after full discharge. (NFPA 72-2022, 10.6.10.3.2)"},
  {id:311, block:4, sec:"Primary & Secondary Power", q:"Which document governs the wiring methods and circuit classifications (power-limited vs. non-power-limited) for the conductors of a fire alarm system?", opts:["NEC (NFPA 70) Article 760","NFPA 13","NFPA 101 Chapter 7","ASME A17.1"], correct:0, re:"NEC Article 760 covers installation of fire alarm circuit wiring, including PLFA and NPLFA classifications. (NEC-2020, Art. 760)"},
  {id:312, block:4, sec:"Primary & Secondary Power", q:"A power-limited fire alarm (PLFA) circuit has its voltage and power limited by what device?", opts:["An ordinary 20 A branch breaker","A listed power supply complying with NEC 760.121","A relay coil","The notification appliance itself"], correct:1, re:"PLFA circuits are limited by a listed power supply per NEC 760.121; output is typically 24 VDC or less. (NEC-2020, 760.121)"},
  {id:313, block:4, sec:"Primary & Secondary Power", q:"What is the typical nominal output voltage of a power-limited fire alarm circuit power supply used for initiating and notification circuits?", opts:["120 VAC","240 VAC","24 VDC or less","600 VDC"], correct:2, re:"PLFA listed supplies for most fire alarm circuits operate at 24 VDC nominal or less. (NEC-2020, 760.121; NFPA 72 Ch.10)"},
  {id:314, block:4, sec:"Primary & Secondary Power", q:"NEC 760.136 requires which of the following between power-limited fire alarm conductors and electric light, power, and Class 1 conductors?", opts:["Sharing the same raceway is required","Identical insulation color","Physical separation (not in the same raceway/enclosure except as permitted)","Only a common grounding screw"], correct:2, re:"NEC 760.136 requires PLFA conductors be separated from light, power, Class 1, and NPLFA conductors. (NEC-2020, 760.136)"},
  {id:315, block:4, sec:"Primary & Secondary Power", q:"Sealed lead-acid (SLA) batteries are the most common secondary power storage for fire alarm panels primarily because they are:", opts:["The lightest battery chemistry available","Capable of unlimited recharge cycles","Maintenance-free, rechargeable, and available in standardized cabinet sizes","Completely immune to temperature effects"], correct:2, re:"SLA batteries are the FACU industry standard: sealed, maintenance-free, rechargeable, in standard sizes such as 12 V 7 Ah / 12 V 12 Ah. (NFPA 72 Ch.10; industry practice)"},
  {id:316, block:4, sec:"Primary & Secondary Power", q:"A standard 12-volt sealed lead-acid battery is internally constructed of how many 2-volt cells in series?", opts:["3 cells","12 cells","24 cells","6 cells"], correct:3, re:"Each lead-acid cell is nominally 2 V, so six cells in series produce a 12 V battery. (Battery fundamentals)"},
  {id:317, block:4, sec:"Primary & Secondary Power", q:"NFPA 72 requires the transfer from primary to secondary power to be:", opts:["Manual, performed by an on-site operator","Delayed by a fixed 5-minute timer","Performed only after 24 hours","Automatic, without loss of signals or system function"], correct:3, re:"Changeover to secondary power must be automatic and not impair operation, so protection is uninterrupted. (NFPA 72-2022, 10.6.8)"},
  {id:318, block:4, sec:"Battery Capacity Calculations", q:"In a fire alarm standby battery calculation, the standby (quiescent) current is multiplied by how many hours?", opts:["5 hours","12 hours","48 hours","24 hours"], correct:3, re:"Standby energy = standby current x 24 hours, the minimum quiescent period. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:319, block:4, sec:"Battery Capacity Calculations", q:"For a standard (non-voice) system, the alarm current in a battery calculation is multiplied by what time, expressed in hours?", opts:["15 minutes = 0.25 hour","30 minutes = 0.5 hour","60 minutes = 1.0 hour","5 minutes = 0.083 hour"], correct:3, re:"Five minutes equals 5/60 = 0.0833 hour for the alarm portion of a standard system. (NFPA 72-2022, 10.6.7.2)"},
  {id:320, block:4, sec:"Battery Capacity Calculations", q:"The 2022 edition of NFPA 72 requires what derating/safety multiplier be applied to the calculated amp-hour battery capacity to account for aging and temperature?", opts:["1.10","1.25","1.20","2.00"], correct:1, re:"The 2022 edition raised the correction factor to 1.25 (a 25% safety factor). (NFPA 72-2022, 10.6.7.2.14)"},
  {id:321, block:4, sec:"Battery Capacity Calculations", q:"A system draws 0.5 A standby and 2.0 A in alarm. Using 24 h standby, 5 min alarm, and a 1.25 factor, the minimum battery capacity is closest to:", opts:["15.2 Ah","12.2 Ah","13.5 Ah","18.0 Ah"], correct:0, re:"(0.5x24)+(2x0.0833)=12.0+0.167=12.167 Ah; x1.25=15.21 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:322, block:4, sec:"Battery Capacity Calculations", q:"A system draws 0.25 A standby and 1.5 A in alarm. With 24 h standby, 5 min alarm, and the 1.25 factor, the minimum capacity is closest to:", opts:["6.1 Ah","9.0 Ah","7.7 Ah","11.0 Ah"], correct:2, re:"(0.25x24)+(1.5x0.0833)=6.0+0.125=6.125 Ah; x1.25=7.66 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:323, block:4, sec:"Battery Capacity Calculations", q:"A voice (EVACS) system draws 0.3 A standby and 3.0 A in alarm. Using 24 h standby, 15 min alarm, and the 1.25 factor, the minimum capacity is closest to:", opts:["9.9 Ah","7.2 Ah","8.5 Ah","12.0 Ah"], correct:0, re:"(0.3x24)+(3x0.25)=7.2+0.75=7.95 Ah; x1.25=9.94 Ah. Voice uses 15 min = 0.25 h. (NFPA 72-2022, 10.6.7.2.2)"},
  {id:324, block:4, sec:"Battery Capacity Calculations", q:"What is the standby energy (amp-hours) contributed by a 0.4 A quiescent load over the required 24-hour standby period?", opts:["4.8 Ah","12.0 Ah","9.6 Ah","19.2 Ah"], correct:2, re:"0.4 A x 24 h = 9.6 Ah of standby energy before adding alarm load and the 1.25 factor. (NFPA 72-2022, 10.6.7.2.1)"},
  {id:325, block:4, sec:"Battery Capacity Calculations", q:"A system has 0.4 A standby and 2.5 A alarm (24 h / 5 min / 1.25). The minimum battery capacity is closest to:", opts:["12.3 Ah","10.0 Ah","11.0 Ah","14.0 Ah"], correct:0, re:"(0.4x24)+(2.5x0.0833)=9.6+0.208=9.808 Ah; x1.25=12.26 Ah. (NFPA 72-2022, 10.6.7.2)"},
  {id:326, block:4, sec:"Battery Capacity Calculations", q:"How is the TOTAL standby current of a system determined before the calculation?", opts:["Use only the panel's standby current","Use the largest single device's standby current","Use the alarm current divided by 2","Multiply each device's standby current by its quantity and sum all devices plus the panel"], correct:3, re:"Total standby current = sum of (each device's standby current x quantity), including the control unit. (NFPA 72 Ch.10; standard worksheet)"},
  {id:327, block:4, sec:"Battery Capacity Calculations", q:"In the alarm column of a battery worksheet, notification appliances are counted at their:", opts:["Standby current","Half of alarm current","Zero, because the panel powers them","Full alarm (active) current"], correct:3, re:"Notification appliances draw their rated alarm current when active; that value populates the alarm column. (Standard NFPA 72 worksheet)"},
  {id:328, block:4, sec:"Battery Capacity Calculations", q:"After computing the required amp-hours, the installer selects a battery whose rated capacity is:", opts:["Exactly equal to the calculated value","Equal to or greater than the calculated value","At least 50% below the calculated value","Any value, since panels self-adjust"], correct:1, re:"The installed battery's Ah rating must equal or exceed the calculated minimum; undersizing is a code violation. (NFPA 72 Ch.10)"},
  {id:329, block:4, sec:"Battery Capacity Calculations", q:"Why does NFPA 72 apply a safety/derating factor to the calculated battery capacity?", opts:["To account for battery aging and temperature-related capacity loss over service life","To pay for installation labor","To reduce the standby time below 24 hours","Because panels routinely overcharge batteries"], correct:0, re:"The 1.25 factor compensates for capacity loss from aging and temperature so the battery still meets duty at end of life. (NFPA 72-2022, 10.6.7.2.14)"},
  {id:330, block:4, sec:"Battery Capacity Calculations", q:"If a system requires 15.2 Ah, which single standard SLA battery rating is the smallest acceptable choice?", opts:["12 V 7 Ah","12 V 18 Ah","12 V 12 Ah","12 V 5 Ah"], correct:1, re:"18 Ah is the smallest listed standard size that meets or exceeds 15.2 Ah. (NFPA 72 Ch.10 sizing principle)"},
  {id:331, block:4, sec:"Battery Capacity Calculations", q:"Two 12 V batteries (each 12 V 7 Ah) connected in SERIES to feed a 24 V panel provide what system voltage and capacity?", opts:["12 V, 14 Ah","24 V, 14 Ah","24 V, 7 Ah","12 V, 7 Ah"], correct:2, re:"Series connection adds voltage (12+12=24 V) but capacity stays the same (7 Ah). (Battery fundamentals)"},
  {id:332, block:4, sec:"Battery Capacity Calculations", q:"Two 12 V 7 Ah batteries connected in PARALLEL provide:", opts:["12 V, 14 Ah","24 V, 7 Ah","24 V, 14 Ah","6 V, 7 Ah"], correct:0, re:"Parallel connection keeps voltage (12 V) but adds capacity (7+7=14 Ah). (Battery fundamentals)"},
  {id:333, block:4, sec:"Battery Capacity Calculations", q:"Adding a bank of magnetic door holders to a system most directly increases which value in the battery calculation?", opts:["Only the alarm current","The standby current (and thus standby Ah)","Neither current","The recharge time only"], correct:1, re:"Door holders are energized continuously to hold doors open, so they add to the quiescent/standby current and grow battery size. (NFPA 72 Ch.10; industry practice)"},
  {id:334, block:4, sec:"Battery Capacity Calculations", q:"When loads make the required capacity exceed a single panel's rechargeable battery limit, the correct solution is to:", opts:["Oversize the internal battery beyond the panel's charging limit","Reduce the standby time to 12 hours","Add a listed remote power supply / NAC extender with its own monitored batteries","Remove notification appliances from the design"], correct:2, re:"Large loads are supported by listed auxiliary/booster power supplies (NAC extenders) with their own monitored secondary batteries. (NFPA 72 Ch.10; NEC 760)"},
  {id:335, block:4, sec:"Relays & Control Functions", q:"In NFPA 72, the building functions the fire alarm system activates (fan shutdown, elevator recall, door release, smoke control) are collectively called:", opts:["Supervisory bypasses","Trouble outputs","Quiescent loads","Emergency control functions"], correct:3, re:"Chapter 21 governs emergency control functions (ECF) and their interfaces. (NFPA 72-2022, Ch. 21)"},
  {id:336, block:4, sec:"Relays & Control Functions", q:"NFPA 72 Chapter 21 permits the interconnection between an emergency control function interface device and the controlled equipment to use which method?", opts:["Listed electrical contacts for the connected load, or a dedicated/shared signaling line circuit","Only pneumatic tubing","Only fiber optics","Only wireless radio"], correct:0, re:"Chapter 21 allows listed electrical contacts for the connected load or data communications over an SLC. (NFPA 72-2022, 21.2)"},
  {id:337, block:4, sec:"Relays & Control Functions", q:"A relay or interface device used to perform an emergency control function must be located:", opts:["Anywhere convenient; monitoring is optional","At least 100 ft from the controlled component","Within 3 ft (1 m) of the controlled component, OR the wiring must be monitored for integrity","Outdoors only"], correct:2, re:"Chapter 21 requires the interface relay be within 3 ft of the controlled equipment, or the connecting conductors be monitored for integrity. (NFPA 72-2022, 21.2.4)"},
  {id:338, block:4, sec:"Relays & Control Functions", q:"A 'Form C' relay contact provided on a fire alarm control unit gives the installer which contact arrangement?", opts:["Normally open only","Normally closed only","One common with both a normally open and a normally closed contact (SPDT)","A latching contact with no common"], correct:2, re:"A Form C contact is single-pole double-throw: a common terminal with both NO and NC contacts for flexible interfacing. (Relay/contact conventions)"},
  {id:339, block:4, sec:"Relays & Control Functions", q:"To control a load drawing more current or higher voltage than a panel's onboard relay can switch, the technician should use:", opts:["A listed control (interposing) relay rated for the load, driven by the panel","A larger fuse only","A longer wire run","The notification circuit directly"], correct:0, re:"An interposing/control relay listed and rated for the load isolates and switches it while the panel drives the relay coil. (NFPA 72 Ch.21; NEC 760)"},
  {id:340, block:4, sec:"Relays & Control Functions", q:"When the fire alarm system actuates the HVAC system for smoke control purposes, NFPA 72 requires that the initiating zones be:", opts:["Ignored during alarm","Coordinated with the smoke-control zones they actuate","Wired to the notification circuit","Disabled to prevent nuisance alarms"], correct:1, re:"Where the FACU actuates HVAC for smoke control, alarm-initiating zones must be coordinated with the smoke-control zones they actuate. (NFPA 72-2022, 21.7)"},
  {id:341, block:4, sec:"Relays & Control Functions", q:"A control relay that releases a magnetic door holder upon alarm must, upon loss of power or a system fault, cause the door to:", opts:["Remain held open","Lock electrically","Sound a local horn only","Release and close (fail-safe)"], correct:3, re:"Hold-open devices are fail-safe: loss of power releases the magnet so the door closes, maintaining the fire/smoke barrier. (NFPA 72 Ch.21; NFPA 80)"},
  {id:342, block:4, sec:"Relays & Control Functions", q:"Conductors that carry an emergency control function but are NOT monitored for integrity by the fire alarm system must, at minimum:", opts:["Be unmonitored with no length limit","Use 600 V insulation regardless of voltage","Be installed in a separate building","Have the interface relay located within 3 ft (1 m) of the controlled appliance"], correct:3, re:"Unmonitored ECF wiring is limited by keeping the relay within 3 ft of the controlled equipment per Chapter 21. (NFPA 72-2022, 21.2.4)"},
  {id:343, block:4, sec:"Relays & Control Functions", q:"An 'addressable relay (control) module' on a signaling line circuit is used primarily to:", opts:["Increase notification appliance volume","Replace the system battery","Measure ground faults","Provide a controllable dry/relay contact at a remote point on the SLC for control functions"], correct:3, re:"Addressable relay modules give the panel a remotely located, individually addressable contact to drive control functions over the SLC. (NFPA 72 Ch.10/23 device functions)"},
  {id:344, block:4, sec:"Relays & Control Functions", q:"Which of the following is an example of a fire-safety control function as opposed to a notification function?", opts:["Sounding a horn/strobe in a corridor","Flashing a strobe in a restroom","Recalling an elevator to the designated level","Announcing a voice evacuation message"], correct:2, re:"Elevator recall is an emergency control (fire-safety) function under Chapter 21; horns, strobes, and voice messages are notification. (NFPA 72-2022, Ch.21 vs Ch.18)"},
  {id:345, block:4, sec:"Relays & Control Functions", q:"For an emergency control function, NFPA 72 requires that a fault between the FACU and a monitored interface device results in:", opts:["No indication","An immediate general alarm","A trouble signal at the control unit","Automatic activation of the function"], correct:2, re:"A fault on a monitored ECF interface circuit must produce a trouble signal at the FACU. (NFPA 72-2022, 21.2.5)"},
  {id:346, block:4, sec:"Relays & Control Functions", q:"A relay module used to shut down fans on alarm is wired so the fan stops when the relay:", opts:["Is activated by the FACU on alarm, opening/changing the fan control circuit","Coil is simply de-energized at all times","Is removed from the panel","Reaches 24 hours of runtime"], correct:0, re:"On alarm the FACU activates the interface relay, which opens/changes the fan control circuit to command shutdown. (NFPA 72-2022, 21.7; NFPA 90A)"},
  {id:347, block:4, sec:"Relays & Control Functions", q:"The priority of signals at a fire alarm control unit places which signal type highest?", opts:["Trouble signals","Supervisory signals","Quiescent signals","Alarm signals"], correct:3, re:"NFPA 72 establishes alarm signals as highest priority, above supervisory, then trouble. (NFPA 72-2022, signal priority)"},
  {id:348, block:4, sec:"Relays & Control Functions", q:"A 'releasing' control function (e.g., to discharge a clean-agent suppression system) requires the releasing circuit to be:", opts:["Unsupervised and unmonitored","Supervised/monitored, using releasing-service-listed equipment","Wired to the door-holder circuit","Powered only by the door holders"], correct:1, re:"Releasing service uses listed releasing panels/circuits that are supervised; integrity faults are annunciated. (NFPA 72-2022 Ch.23; NFPA 12/2001 interface)"},
  {id:349, block:4, sec:"Relays & Control Functions", q:"When a single addressable module provides BOTH monitoring of a device and control of a function, the wiring must still ensure that:", opts:["Control and monitoring share one unsupervised wire","The module ignores ground faults","Loss of integrity is detected and reported as trouble","The function activates on any trouble"], correct:2, re:"Regardless of combined function, the interface integrity must be supervised and faults reported as trouble. (NFPA 72-2022, 21.2.5)"},
  {id:350, block:4, sec:"Relays & Control Functions", q:"A control function that must continue to operate during a fire (e.g., stair pressurization fans for smoke control) is typically powered and wired as:", opts:["A standard non-survivable branch circuit","A door-holder circuit","A trouble-only circuit","A survivable / protected circuit per the smoke-control and Chapter 21/24 requirements"], correct:3, re:"Smoke-control equipment that must run during fire requires survivable circuit integrity and standby power per the applicable provisions. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:351, block:4, sec:"Elevator Recall & Shutdown", q:"Phase I Emergency Recall Operation of an elevator, initiated by the fire alarm system, causes the car to:", opts:["Automatically return to a designated recall level and be removed from normal service","Stop immediately between floors","Speed up to the top floor","Open all hoistway doors"], correct:0, re:"Phase I recall returns the car to the designated landing and removes it from normal service per ASME A17.1 firefighters' emergency operation. (NFPA 72-2022, 21.3; ASME A17.1)"},
  {id:352, block:4, sec:"Elevator Recall & Shutdown", q:"Which standard defines the actual elevator behavior (Firefighters' Emergency Operation, Phase I and Phase II) that the fire alarm system interfaces with?", opts:["NFPA 13","ASME A17.1 / CSA B44","NFPA 25","NEC Article 700"], correct:1, re:"ASME A17.1/CSA B44 defines FEO Phase I/II; NFPA 72 Ch.21 defines how the fire alarm interfaces to it. (NFPA 72-2022, 21.3; ASME A17.1 2.27)"},
  {id:353, block:4, sec:"Elevator Recall & Shutdown", q:"Activation of which device normally initiates elevator Phase I recall to the DESIGNATED (primary) level?", opts:["A smoke detector in an elevator lobby (other than the designated level), machine room, or hoistway","A manual pull station in a corridor","A waterflow switch on the third floor","A duct detector in the lobby HVAC"], correct:0, re:"Lobby, machine-room, and hoistway smoke detectors (except at the designated level) recall the car to the designated level. (NFPA 72-2022, 21.3.5; ASME A17.1)"},
  {id:354, block:4, sec:"Elevator Recall & Shutdown", q:"When the smoke detector at the DESIGNATED recall level activates, the elevator is recalled to:", opts:["The same designated level","The top floor","The basement only, in all cases","An alternate (secondary) recall level"], correct:3, re:"If the designated-level detector activates, recall is sent to the alternate level so the car does not open into the smoky designated lobby. (NFPA 72-2022, 21.3.6; ASME A17.1)"},
  {id:355, block:4, sec:"Elevator Recall & Shutdown", q:"Smoke detectors used solely for elevator recall must initiate recall and also:", opts:["Be hidden from view","Be powered only by the elevator controller","Sound only a local buzzer","Cause the building fire alarm system to indicate alarm (they connect to the FACU)"], correct:3, re:"Recall detectors are connected to and monitored by the building FACU and initiate an alarm/recall, not just a local function. (NFPA 72-2022, 21.3 / 21.2)"},
  {id:356, block:4, sec:"Elevator Recall & Shutdown", q:"NFPA 72 requires that SEPARATE outputs from the fire alarm control unit be provided to implement which elevator functions?", opts:["Only the alarm horn","Phase I recall AND any required power shutdown (shunt trip), as distinct dedicated outputs","Only the elevator music system","Only the elevator cab lighting"], correct:1, re:"Chapter 21 requires separate, dedicated outputs for Phase I recall and for power shutdown (shunt trip). (NFPA 72-2022, 21.3 / 21.4)"},
  {id:357, block:4, sec:"Elevator Recall & Shutdown", q:"Elevator power 'shunt trip' (automatic disconnection of elevator power) is provided where sprinklers are installed in the machine room or hoistway so that power is removed:", opts:["Long after water discharge","Prior to sprinkler water discharge onto energized elevator equipment","Only during routine testing","Never, because shunt trip is prohibited"], correct:1, re:"Shunt trip removes elevator power before sprinkler discharge to prevent uncontrolled movement and shock hazards. (NFPA 72-2022, 21.4; ASME A17.1)"},
  {id:358, block:4, sec:"Elevator Recall & Shutdown", q:"To trigger shunt trip BEFORE the sprinkler operates, a heat detector is installed near each affected sprinkler. NFPA 72 requires that detector to be:", opts:["Higher-temperature and slower than the sprinkler","Within 2 ft (0.6 m) of each sprinkler, responding ahead of the sprinkler","Located 25 ft away from the sprinkler","A smoke detector only"], correct:1, re:"A heat detector within 2 ft of each sprinkler, with appropriate temperature/response, actuates shunt trip ahead of sprinkler operation. (NFPA 72-2022, 21.4.2; ASME A17.1)"},
  {id:359, block:4, sec:"Elevator Recall & Shutdown", q:"Why must elevator recall use smoke detection (not heat) in lobbies, machine rooms, and hoistways for the recall function?", opts:["To recall cars early, before smoke endangers occupants using or exiting the elevator","Because heat detectors are cheaper","Because smoke detectors never false-alarm","Because code prohibits heat anywhere near elevators"], correct:0, re:"Smoke detection provides early recall so occupants are not trapped by smoke; heat is reserved for the shunt-trip function. (NFPA 72-2022, 21.3 vs 21.4)"},
  {id:360, block:4, sec:"Elevator Recall & Shutdown", q:"A dedicated visual signal (the illuminated 'firefighters' hat' indicator) inside the elevator car tells occupants that:", opts:["Firefighters' emergency operation (recall) is in effect","The car needs maintenance","The battery is low","The doors are mechanically blocked"], correct:0, re:"The illuminated hat/visual signal indicates Phase I recall/FEO is active per ASME A17.1; the fire alarm provides the initiating signal. (ASME A17.1; NFPA 72-2022, 21.3)"},
  {id:361, block:4, sec:"Elevator Recall & Shutdown", q:"Which initiating device should NOT be used to initiate elevator Phase I recall?", opts:["An elevator lobby smoke detector","A manual fire alarm box (pull station)","An elevator machine-room smoke detector","An elevator hoistway smoke detector"], correct:1, re:"Recall is initiated by smoke detectors in lobbies, machine rooms, and hoistways, not by manual pull stations. (NFPA 72-2022, 21.3.5)"},
  {id:362, block:4, sec:"Elevator Recall & Shutdown", q:"In a building with multiple elevators in a common hoistway or grouped together, activation of a recall-initiating device generally recalls:", opts:["Only one randomly chosen car","All elevators served by that lobby/group, per the design and ASME A17.1","No elevators","Only freight elevators"], correct:1, re:"Recall affects the elevators served by the activated zone/group as coordinated with the elevator design and ASME A17.1. (NFPA 72-2022, 21.3; ASME A17.1)"},
  {id:363, block:4, sec:"Elevator Recall & Shutdown", q:"The interface between the fire alarm system and the elevator controller for recall is typically made through:", opts:["The notification appliance circuit","The door-holder circuit","Dedicated relay outputs/contacts listed for the elevator interface","The sprinkler waterflow switch"], correct:2, re:"Recall and shutdown signals are delivered via dedicated, monitored relay outputs to the elevator controller. (NFPA 72-2022, 21.3 / 21.2)"},
  {id:364, block:4, sec:"Elevator Recall & Shutdown", q:"Smoke detectors installed in elevator lobbies for recall are spaced according to:", opts:["A fixed 100 ft spacing regardless of geometry","Only one per building","Standard spot smoke detector spacing rules, with at least one in each lobby","The sprinkler head spacing"], correct:2, re:"Lobby recall detectors follow standard smoke detector spacing/placement, with coverage of each elevator lobby. (NFPA 72-2022, 17.7; 21.3)"},
  {id:365, block:4, sec:"Elevator Recall & Shutdown", q:"If an elevator machine room has both a smoke detector and (where sprinklered) a heat detector, their functions are:", opts:["Identical: both recall the car","Both immediately shut off power","Neither connects to the FACU","Smoke detector recalls the car; heat detector initiates shunt-trip power shutdown"], correct:3, re:"Machine-room smoke recalls (Phase I); the heat detector near the sprinkler handles shunt trip. (NFPA 72-2022, 21.3 / 21.4)"},
  {id:366, block:4, sec:"Elevator Recall & Shutdown", q:"After Phase I recall returns the car to the recall level, the car doors:", opts:["Remain closed and the car stays in service","Cycle open and closed continuously","Open and remain open, and the car is taken out of normal automatic service","Lock occupants inside the car"], correct:2, re:"At the recall level the doors open and the car is removed from normal service, available only for Phase II firefighter operation. (ASME A17.1; NFPA 72-2022, 21.3)"},
  {id:367, block:4, sec:"Elevator Recall & Shutdown", q:"Combining elevator recall detection and shunt trip on the SAME device is prohibited because:", opts:["Recall (early, smoke) and shutdown (heat, just before water) serve different goals and timings and need separate outputs","It saves too much money","Heat detectors cannot be monitored","Smoke detectors are not allowed in machine rooms"], correct:0, re:"NFPA 72 requires separate outputs: recall (early, smoke) versus shutdown (heat, immediately before sprinkler discharge). (NFPA 72-2022, 21.3 / 21.4)"},
  {id:368, block:4, sec:"HVAC, Dampers & Door Holders", q:"A duct smoke detector's primary code-required purpose under NFPA 90A is to:", opts:["Replace area (open-area) smoke detection","Sound the building evacuation alarm by itself","Stop the air-handling fan to prevent smoke distribution through ducts","Hold open fire doors"], correct:2, re:"Per NFPA 90A, duct smoke detectors shut down the supply fan to stop recirculation/spread of smoke; they do not replace area detection. (NFPA 90A; NFPA 72-2022, 17.7.5)"},
  {id:369, block:4, sec:"HVAC, Dampers & Door Holders", q:"NFPA 90A requires duct smoke detectors in air-handling systems with a supply-side capacity greater than what airflow value?", opts:["500 cfm","1,000 cfm","2,000 cfm","5,000 cfm"], correct:2, re:"NFPA 90A requires duct smoke detection on supply systems exceeding 2,000 cfm. (NFPA 90A)"},
  {id:370, block:4, sec:"HVAC, Dampers & Door Holders", q:"A supply-side duct smoke detector is required to be installed:", opts:["Downstream of the filters and ahead of any branch connections","At the very end of the longest branch duct","Inside the occupied space ceiling only","On the building exterior"], correct:0, re:"NFPA 90A locates the supply duct detector downstream of the filters and upstream of any branch takeoffs. (NFPA 90A)"},
  {id:371, block:4, sec:"HVAC, Dampers & Door Holders", q:"Duct smoke detectors are listed to operate within a specified duct air velocity range, commonly given as approximately:", opts:["0 to 50 fpm","5,000 to 10,000 fpm","100 to 4,000 fpm (verify each unit's listing)","No velocity limits apply"], correct:2, re:"Listed duct detectors operate over a rated velocity band (commonly ~100-4,000 fpm); the unit must be applied within its listing. (Listings; NFPA 72-2022, 17.7.5)"},
  {id:372, block:4, sec:"HVAC, Dampers & Door Holders", q:"When a duct smoke detector's ONLY function is fan shutdown, NFPA 90A permits which of the following regarding backup power?", opts:["It must always have 24 h standby like the FACU","It may be without secondary (battery) power where its sole function is HVAC fan shutdown","It must run for 15 minutes in alarm","It must be powered from the elevator controller"], correct:1, re:"NFPA 90A allows a duct detector lacking backup power only where its sole function is fan shutdown. (NFPA 90A)"},
  {id:373, block:4, sec:"HVAC, Dampers & Door Holders", q:"A magnetic door holder retains a self-closing fire/smoke door open. In normal (no-alarm) condition the holder is:", opts:["De-energized","Pulsed once per hour","Powered only during testing","Continuously energized to hold the door open"], correct:3, re:"Door holders are energized continuously to retain doors open; on alarm or power loss they de-energize and the door closes. (NFPA 72 Ch.21; NFPA 80)"},
  {id:374, block:4, sec:"HVAC, Dampers & Door Holders", q:"A combination fire/smoke damper controlled by the fire alarm system, upon alarm, will:", opts:["Open fully to increase airflow","Stay in its last position","Vibrate to clear debris","Close to block the passage of smoke/fire through the duct penetration"], correct:3, re:"On alarm the FACU signals the damper to close, maintaining the rated barrier at the duct penetration. (NFPA 72-2022, 21.6; NFPA 90A; NFPA 80/105)"},
  {id:375, block:4, sec:"HVAC, Dampers & Door Holders", q:"Activation of a duct smoke detector must produce what response, per NFPA 72 and NFPA 90A?", opts:["At minimum an annunciated signal at the FACU (supervisory, or alarm where required) and fan shutdown","No indication is required","Only a green 'normal' light","A door-holder release only"], correct:0, re:"Duct detector activation is annunciated (commonly supervisory, or alarm where the code/AHJ requires) and initiates fan shutdown. (NFPA 72-2022, 17.7.5; 21.7)"},
  {id:376, block:4, sec:"HVAC, Dampers & Door Holders", q:"Why are duct smoke detectors NOT a substitute for open-area (spot) smoke detection?", opts:["Smoke may not reach the duct and the fan may be off, so a room fire can go undetected","They are far more sensitive than spot detectors","They cost more to install","They cannot be electrically monitored"], correct:0, re:"Duct detectors only sample moving duct air; with the fan off or smoke not entering the return, a room fire can go undetected. (NFPA 72-2022, 17.7.5.1; NFPA 90A)"},
  {id:377, block:4, sec:"HVAC, Dampers & Door Holders", q:"When the fire alarm system shuts down an air handler on alarm, the goal is to:", opts:["Stop the mechanical movement/distribution of smoke through the building","Increase the fresh-air intake","Cool the fire","Pressurize the fire room"], correct:0, re:"Fan shutdown halts duct-borne smoke spread to other areas. (NFPA 90A; NFPA 72-2022, 21.7)"},
  {id:378, block:4, sec:"HVAC, Dampers & Door Holders", q:"A remote test station / accessory for a duct smoke detector typically provides:", opts:["A way to recharge the system battery","Extra notification volume","Power to actuate dampers","Remote alarm/trouble LEDs and a key-operated reset/test for the in-duct sensor"], correct:3, re:"Remote test stations expose status LEDs and test/reset for a duct detector mounted in an inaccessible duct. (Listings; NFPA 72-2022, 17.7.5)"},
  {id:379, block:4, sec:"HVAC, Dampers & Door Holders", q:"For engineered smoke-control systems, NFPA 72 coordinates with which standard that defines smoke-control design and operation?", opts:["NFPA 13","NFPA 25","NFPA 92","NFPA 1221"], correct:2, re:"NFPA 92 (Smoke Control Systems) defines design/operation; NFPA 72 Ch.21 covers the fire alarm interface and monitoring. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:380, block:4, sec:"HVAC, Dampers & Door Holders", q:"A magnetic door holder/closer system that is part of the fire alarm system must release the doors upon:", opts:["Only a manual command from the panel","Activation of the fire alarm system (e.g., area smoke detection) or loss of power","Only a sprinkler waterflow signal","Only an elevator recall signal"], correct:1, re:"Hold-open devices release on fire alarm actuation (commonly local smoke detection) and on power loss, allowing doors to self-close. (NFPA 72 Ch.21; NFPA 80)"},
  {id:381, block:4, sec:"HVAC, Dampers & Door Holders", q:"Dedicated smoke detectors that release door-hold-open devices are an example of detection used for:", opts:["A fire-safety (control) function - door release - integrated with the FACU","General building evacuation only","Energy management","Replacing duct detectors"], correct:0, re:"Door-release detection is a control function under Chapter 21, monitored by the FACU. (NFPA 72-2022, Ch.21; NFPA 80)"},
  {id:382, block:4, sec:"HVAC, Dampers & Door Holders", q:"In an engineered smoke-control system, the fire alarm system's actuation of HVAC equipment must be coordinated so that:", opts:["All fans simply turn off","The correct zones pressurize/exhaust per the smoke-control sequence (which may keep some fans ON)","Doors lock occupants in","Elevators speed up"], correct:1, re:"Engineered smoke control may keep fans running for pressurization/exhaust; the alarm zones must match the smoke-control sequence. (NFPA 72-2022, 21.7; NFPA 92)"},
  {id:383, block:4, sec:"HVAC, Dampers & Door Holders", q:"The interconnecting wiring from the FACU to a smoke damper actuator is treated as which type of circuit?", opts:["A notification appliance circuit","An emergency control function circuit (monitored per Ch.21, or relay within 3 ft)","A door-holder branch circuit only","A sprinkler supervisory circuit"], correct:1, re:"Damper control is an emergency control function; its interface follows Chapter 21 integrity rules. (NFPA 72-2022, 21.2 / 21.6)"},
  {id:384, block:4, sec:"HVAC, Dampers & Door Holders", q:"If a duct smoke detector also serves to initiate building evacuation (not just fan shutdown), it then requires:", opts:["No backup power at all","Only a local sounder","Secondary (standby) power, like other alarm-initiating devices","Connection to the elevator controller"], correct:2, re:"Once a duct detector performs an alarm-initiating role beyond fan shutdown, it must have secondary power per NFPA 72. (NFPA 72-2022, 10.6; NFPA 90A)"},
  {id:385, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A waterflow switch on a wet-pipe sprinkler system that detects flow generates which signal at the fire alarm control unit?", opts:["An alarm signal","A supervisory signal","A trouble signal only","No signal"], correct:0, re:"Waterflow indicates a sprinkler is operating (a fire condition), so it is an alarm signal. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:386, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A control (gate) valve tamper/supervisory switch that detects a closed valve generates which signal?", opts:["A supervisory signal","An alarm signal","A trouble signal","A pre-alarm signal"], correct:0, re:"Valve tamper (off-normal position of a valve) is a supervisory signal warning the system may be impaired. (NFPA 72-2022, 17.16; 17.12)"},
  {id:387, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A vane-type waterflow switch incorporates a built-in retard (delay) primarily to:", opts:["Slow the alarm so people can evacuate","Save battery power","Allow the control valve to close","Prevent false alarms from pressure surges/water hammer in the supply"], correct:3, re:"The retard absorbs momentary surges so only sustained flow trips the alarm, reducing nuisance alarms. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:388, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A sprinkler control valve supervisory switch must initiate a signal when the valve has moved off its fully open position by no more than:", opts:["One-half of its travel","Only when fully closed","One-fifth (about 20%) of the way from fully open","75% closed"], correct:2, re:"NFPA 72 requires the supervisory signal within two revolutions or one-fifth (about 20%) of the valve's travel from fully open. (NFPA 72-2022, 17.16.4)"},
  {id:389, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A waterflow initiating device must indicate flow within how many seconds of a flow equal to that of a single smallest sprinkler?", opts:["30 seconds","60 seconds","90 seconds","120 seconds"], correct:2, re:"NFPA 13/72 allow the waterflow device to operate within 90 seconds of such flow. (NFPA 72-2022, 17.12; NFPA 13)"},
  {id:390, block:4, sec:"Sprinkler & Suppression Monitoring", q:"After the waterflow initiating device activates, notification appliances must operate within how many additional seconds?", opts:["30 seconds","60 seconds","10 seconds","90 seconds"], correct:2, re:"Notification must follow within 10 seconds of the initiating device, so the total can approach ~100 seconds. (NFPA 72-2022 / NFPA 13)"},
  {id:391, block:4, sec:"Sprinkler & Suppression Monitoring", q:"On a DRY-pipe sprinkler system, low air pressure that could cause an unwanted valve trip is monitored and reported as which signal?", opts:["An alarm signal","A trouble signal","No signal is required","A supervisory signal"], correct:3, re:"Off-normal air/water pressure on a dry/pre-action system is a supervisory condition. (NFPA 72-2022, 17.16; NFPA 13)"},
  {id:392, block:4, sec:"Sprinkler & Suppression Monitoring", q:"Low temperature in a space containing wet-pipe sprinkler piping (risk of freezing) is monitored and reported as:", opts:["An alarm signal","A trouble signal","A supervisory signal","A notification signal"], correct:2, re:"Room low-temperature supervision protecting against freeze-up is a supervisory signal under NFPA 72. (NFPA 72-2022, 17.16)"},
  {id:393, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A pressure-type waterflow switch on an alarm check valve detects flow by sensing:", opts:["A drop in battery voltage","Duct air velocity","Door position","Water pressure change/surge in the alarm line when the valve operates"], correct:3, re:"Pressure switches sense the pressure rise/flow in the alarm line when the alarm check valve clappers open. (NFPA 13; NFPA 72-2022, 17.12)"},
  {id:394, block:4, sec:"Sprinkler & Suppression Monitoring", q:"Per NFPA 72, valves controlling water supply, pump power, tank levels, and air pressure for sprinkler systems must be:", opts:["Left unmonitored","Monitored only during business hours","Checked annually instead of supervised","Electrically supervised by a listed fire alarm control unit"], correct:3, re:"NFPA 72/13 require electrical supervision of such valves and conditions by a listed FACU. (NFPA 72-2022, 17.16; NFPA 13)"},
  {id:395, block:4, sec:"Sprinkler & Suppression Monitoring", q:"Conditions such as a fire pump running and its power-source status are monitored and reported (where required) as which signal?", opts:["A trouble signal only","A supervisory signal","A notification signal","No monitoring is permitted"], correct:1, re:"Fire pump conditions such as pump-running and power-source status are supervisory signals. (NFPA 72-2022, 17.16; NFPA 20)"},
  {id:396, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A clean-agent or CO2 suppression system's actuation (agent released) is reported to the fire alarm system as:", opts:["A supervisory signal","An alarm signal (releasing/discharge alarm)","A trouble signal","No signal"], correct:1, re:"Discharge/release of a suppression agent is an alarm condition; the releasing system interfaces with the FACU. (NFPA 72-2022 Ch.23; NFPA 2001/12)"},
  {id:397, block:4, sec:"Sprinkler & Suppression Monitoring", q:"Loss of monitoring integrity (an open or ground fault) on a sprinkler supervisory circuit results in:", opts:["An alarm signal","A supervisory signal","A trouble signal","Activation of the sprinklers"], correct:2, re:"A wiring/integrity fault is a trouble signal, distinct from the supervisory (valve/pressure) signal itself. (NFPA 72-2022, 10.15; 17.16)"},
  {id:398, block:4, sec:"Sprinkler & Suppression Monitoring", q:"Which of the following correctly pairs the sprinkler-related event with its NFPA 72 signal type?", opts:["Waterflow = supervisory; valve closed = alarm","Waterflow = alarm; valve closed = supervisory","Both waterflow and valve closure = trouble","Both waterflow and valve closure = supervisory"], correct:1, re:"Waterflow is an alarm (water flowing = fire); a closed/tampered valve is supervisory (system possibly impaired). (NFPA 72-2022, 17.12 / 17.16)"},
  {id:399, block:4, sec:"Sprinkler & Suppression Monitoring", q:"A pre-action sprinkler system is typically actuated by:", opts:["Waterflow only","A tamper switch","A door holder","Independent fire detection (smoke/heat) opening the pre-action valve, then sprinkler heads control water"], correct:3, re:"Pre-action systems use FACU detection to open the valve, charging the piping; heads then release water. The detection interfaces with the FACU. (NFPA 72-2022 Ch.23; NFPA 13)"},
  {id:400, block:4, sec:"Sprinkler & Suppression Monitoring", q:"The fundamental reason valve tamper is supervisory while waterflow is alarm is that:", opts:["Tamper is more dangerous than a fire","A closed valve only warns of a possible impairment, whereas waterflow indicates an actual fire/discharge requiring evacuation","Both should sound evacuation equally","Waterflow is less urgent than tamper"], correct:1, re:"Supervisory warns staff of a condition affecting reliability (valve shut); alarm signals an actual fire event (flow). (NFPA 72-2022, definitions; 17.12/17.16)"},
  {id:401, block:5, sec:"NFPA 72 General Requirements", q:"What is the official title of NFPA 72?", opts:["National Fire Alarm and Signaling Code","National Electrical Code","Life Safety Code","Standard for Portable Fire Extinguishers"], correct:0, re:"NFPA 72 is the National Fire Alarm and Signaling Code; it governs application, installation, location, performance, inspection, testing and maintenance of fire alarm and signaling systems. Source: NFPA 72 title page."},
  {id:402, block:5, sec:"NFPA 72 General Requirements", q:"Under NFPA 72, who has the authority to grant equivalencies and approve alternative arrangements not specifically described in the Code?", opts:["The authority having jurisdiction (AHJ)","The system installer","The equipment manufacturer","The building owner"], correct:0, re:"NFPA 72 Chapter 1 assigns approval of equipment, materials, and alternative/equivalent arrangements to the authority having jurisdiction (AHJ). Source: NFPA 72, Chapter 1 administration (Approved / Equivalency provisions)."},
  {id:403, block:5, sec:"NFPA 72 General Requirements", q:"In NFPA 72, the term 'shall' indicates what?", opts:["A mandatory requirement","A recommendation only","A permissive option","An explanatory note"], correct:0, re:"Per NFPA's Manual of Style adopted in NFPA 72, 'shall' denotes a mandatory requirement, while 'should' indicates a recommendation. Source: NFPA 72 mandatory/advisory language convention."},
  {id:404, block:5, sec:"NFPA 72 General Requirements", q:"Material in an Annex of NFPA 72 (such as Annex A) is which of the following?", opts:["Explanatory/informational, not part of the requirements","Mandatory and enforceable","A separate standard","Applicable only to residential systems"], correct:0, re:"Annexes in NFPA documents are not part of the enforceable requirements; they are informational/explanatory unless specifically adopted. Source: NFPA 72 annex material designation."},
  {id:405, block:5, sec:"NFPA 72 General Requirements", q:"NFPA 72 defines what type of system as one installed within or on a structure to protect the structure and its occupants?", opts:["Protected premises (local) fire alarm system","Public emergency alarm reporting system","Wide-area mass notification system","Releasing service system"], correct:0, re:"A protected premises (local) fire alarm system is installed at the protected property to provide detection, notification, and control for that property. Source: NFPA 72 definitions / Chapter on protected premises systems."},
  {id:406, block:5, sec:"NFPA 72 General Requirements", q:"Which document does NFPA 72 reference for the symbols to be used on fire alarm shop drawings, unless other symbols are acceptable to the AHJ?", opts:["NFPA 170","NFPA 13","NFPA 101","NEC Article 760"], correct:0, re:"NFPA 72 requires fire alarm drawings to use the symbols of NFPA 170, Standard for Fire Safety and Emergency Symbols, unless other symbols are acceptable to the AHJ. Source: NFPA 170 referenced by NFPA 72."},
  {id:407, block:5, sec:"NFPA 72 General Requirements", q:"Per NFPA 72, the maximum response time for an off-premises alarm signal transmission to a supervising station is generally how many seconds?", opts:["10 seconds","30 seconds","90 seconds","180 seconds"], correct:2, re:"NFPA 72 limits the time from initiation to receipt of an alarm at the supervising station to 90 seconds. Source: NFPA 72 supervising station communications timing requirements."},
  {id:408, block:5, sec:"NFPA 72 General Requirements", q:"Secondary (standby) power for a protected premises fire alarm system must be capable of operating the system under normal load for at least how long?", opts:["4 hours","12 hours","24 hours","72 hours"], correct:2, re:"NFPA 72 requires the secondary power supply to support the system in normal (quiescent) condition for 24 hours, then sound the required notification load (typically 5 or 15 minutes). Source: NFPA 72 power supply requirements."},
  {id:409, block:5, sec:"NFPA 72 General Requirements", q:"After 24 hours on secondary power, a fire alarm system in a typical protected premises must be able to operate the alarm notification load for at least how long?", opts:["5 minutes","15 minutes","30 minutes","60 minutes"], correct:0, re:"NFPA 72 requires the secondary supply to carry the alarm notification load for 5 minutes after the 24-hour standby period (in-building mass notification uses 15 minutes). Source: NFPA 72 secondary power capacity."},
  {id:410, block:5, sec:"NFPA 72 General Requirements", q:"A trouble signal on a fire alarm system indicates which condition?", opts:["A confirmed fire","Activation of a sprinkler waterflow switch","A fault such as an open or ground in monitored wiring","A normal supervisory condition"], correct:2, re:"A trouble signal indicates a fault (open, ground, loss of power, etc.) in the system that could impair operation; it is distinct from alarm and supervisory signals. Source: NFPA 72 signal definitions."},
  {id:411, block:5, sec:"NFPA 72 General Requirements", q:"A supervisory signal on a fire alarm system most commonly indicates what?", opts:["A fire condition requiring evacuation","An open circuit in initiating-device wiring","An off-normal condition of a fire protection system or its components (e.g., a closed valve)","A depleted standby battery"], correct:2, re:"A supervisory signal indicates an off-normal condition of a guard's tour, fire suppression system, or other protective feature being monitored (e.g., a tamper switch on a control valve). Source: NFPA 72 signal definitions."},
  {id:412, block:5, sec:"NFPA 72 General Requirements", q:"Per NFPA 72, the audibility level of a public-mode evacuation signal must be at least how many dBA above average ambient sound level?", opts:["5 dBA","10 dBA","15 dBA","20 dBA"], correct:2, re:"Public-mode audible appliances must produce at least 15 dBA above average ambient sound level, or 5 dBA above the maximum sound level lasting 60 seconds, whichever is greater. Source: NFPA 72 audibility requirements."},
  {id:413, block:5, sec:"NFPA 72 General Requirements", q:"The standard temporal pattern used for fire evacuation signals per NFPA 72 is called what?", opts:["Temporal Code 3 (Temporal-Three)","Continuous tone","March time","Coded pulse"], correct:0, re:"NFPA 72 specifies the Temporal-Three (Temporal Code 3) audible pattern for fire evacuation: three pulses followed by a pause, repeated. Source: NFPA 72 evacuation signal pattern."},
  {id:414, block:5, sec:"NFPA 72 General Requirements", q:"Which signal type must take priority and override all other signals on a fire alarm control unit?", opts:["Supervisory signal","Trouble signal","Alarm signal","Test signal"], correct:2, re:"NFPA 72 establishes that alarm signals receive the highest priority; the control unit must give precedence to the fire alarm signal over supervisory and trouble. Source: NFPA 72 signal priority requirements."},
  {id:415, block:5, sec:"NFPA 72 General Requirements", q:"Per NFPA 72, qualified fire alarm system personnel must be able to demonstrate competence by which means?", opts:["Verbal claim of experience only","Membership in a trade union","Recognized certification, licensing, registration, or factory training acceptable to the AHJ","Ownership of test equipment"], correct:2, re:"NFPA 72 requires service personnel to be qualified, evidenced by certification (e.g., NICET), licensing/registration, or manufacturer training acceptable to the AHJ. Source: NFPA 72 personnel qualification requirements."},
  {id:416, block:5, sec:"NFPA 72 General Requirements", q:"When new fire alarm equipment is added to an existing system, NFPA 72 requires what kind of test of affected functions?", opts:["No test if the panel is unchanged","A full replacement of the system","A reacceptance test of the modified portions and affected interfaces","Only a visual inspection"], correct:2, re:"NFPA 72 requires reacceptance testing whenever a system is modified, to verify the changes and that other portions/interfaces are not adversely affected. Source: NFPA 72 Chapter 14 reacceptance testing."},
  {id:417, block:5, sec:"NFPA 72 General Requirements", q:"NFPA 72 requires the audible private-mode signal level to be at least how many dBA above average ambient sound level at the location of the listening party?", opts:["6 dBA","10 dBA","15 dBA","20 dBA"], correct:0, re:"Private-mode audible appliances must provide at least 6 dBA above average ambient or 5 dBA above maximum sound level lasting 60 seconds, whichever is greater. Source: NFPA 72 private-mode audibility requirements."},
  {id:418, block:5, sec:"Detector Spacing & Placement", q:"On a smooth ceiling, the nominal (maximum) spacing between spot-type smoke detectors per NFPA 72 is which value?", opts:["20 ft","40 ft","30 ft","50 ft"], correct:2, re:"NFPA 72 establishes a nominal 30 ft (9.1 m) spacing for spot-type smoke detectors on smooth ceilings, with detectors within one-half that spacing from walls. Source: NFPA 72 Ch. 17 smoke detector spacing."},
  {id:419, block:5, sec:"Detector Spacing & Placement", q:"On a smooth ceiling, a spot-type smoke detector must be located within what distance, measured at right angles from all walls or partitions?", opts:["One-quarter the nominal spacing","The full nominal spacing","One-half the nominal spacing","Twice the nominal spacing"], correct:2, re:"NFPA 72 requires detectors within one-half the nominal spacing (i.e., within 15 ft for the 30 ft nominal) from walls, measured at right angles. Source: NFPA 72 Ch. 17 smooth-ceiling spacing."},
  {id:420, block:5, sec:"Detector Spacing & Placement", q:"The 'Point 7 rule' for detector layout requires that all points on the ceiling be within what distance of a detector?", opts:["0.5 times the listed/nominal spacing","1.0 times the listed/nominal spacing","0.9 times the listed/nominal spacing","0.7 times the listed/nominal spacing"], correct:3, re:"The 0.7S rule requires every point on the ceiling to be within 0.7 times the nominal/listed spacing of a detector when using non-standard (e.g., irregular) layouts. Source: NFPA 72 Ch. 17 (0.7S spacing method)."},
  {id:421, block:5, sec:"Detector Spacing & Placement", q:"For a ceiling-mounted spot smoke detector, NFPA 72 requires the minimum clearance from any wall to be at least how much?", opts:["1 inch","36 inches","12 inches","4 inches"], correct:3, re:"NFPA 72 requires ceiling-mounted spot smoke detectors to be located a minimum of 4 in. (100 mm) from any wall to avoid the dead-air space at the ceiling-wall junction. Source: NFPA 72 Ch. 17 placement."},
  {id:422, block:5, sec:"Detector Spacing & Placement", q:"A wall- (sidewall-) mounted spot smoke detector must have its top located within what zone measured down from the ceiling?", opts:["Within the top 4 in.","Anywhere on the wall","Between 12 in. and 24 in. down","Between 4 in. and 12 in. down"], correct:3, re:"NFPA 72 permits sidewall-mounted smoke detectors with the top of the detector between 4 in. and 12 in. (100 mm to 300 mm) down from the ceiling. Source: NFPA 72 Ch. 17 placement."},
  {id:423, block:5, sec:"Detector Spacing & Placement", q:"Does ceiling height by itself require a reduction in SMOKE detector spacing under NFPA 72?", opts:["Yes, the same table as heat detectors applies","Yes, spacing doubles above 20 ft","Yes, spacing halves above 10 ft","No, smoke detector nominal spacing is not reduced solely for ceiling height (within listed limits)"], correct:3, re:"Unlike heat detectors, NFPA 72 does not require a smoke detector spacing reduction based solely on increased ceiling height (other factors like beams, airflow, and stratification still apply). Source: NFPA 72 Ch. 17."},
  {id:424, block:5, sec:"Detector Spacing & Placement", q:"For HEAT detectors, as ceiling height increases NFPA 72 requires spacing to be adjusted using which method?", opts:["No adjustment is ever required","Using smoke detector spacing instead","Doubling the listed spacing","A height-correction factor (multiplier) from the heat-detector spacing table"], correct:3, re:"NFPA 72 requires heat detector listed spacing to be multiplied by a reduction factor that decreases as ceiling height increases (per the heat-detector ceiling-height table). Source: NFPA 72 Ch. 17 heat detector spacing table."},
  {id:425, block:5, sec:"Detector Spacing & Placement", q:"A beam's depth becomes a factor in smoke detector spacing on a level ceiling when the beam depth exceeds what fraction of the ceiling height?", opts:["5% (0.05H)","40% (0.40H)","25% (0.25H)","10% (0.10H)"], correct:3, re:"When beam depth is 10% or more of ceiling height (>0.1H), beams affect spacing; beams shallower than 10% of ceiling height allow smooth-ceiling spacing. Source: NFPA 72 Ch. 17 beam ceiling rules."},
  {id:426, block:5, sec:"Detector Spacing & Placement", q:"For a beamed ceiling where beam depth is at least 10% of ceiling height AND beam spacing is at least 40% of ceiling height, NFPA 72 requires smoke detectors to be located where?", opts:["Only on the bottom of beams","Spaced at the full 30 ft nominal","At the center of the room only","In each beam pocket"], correct:3, re:"When beams are deep (>=0.1H) and widely spaced (>=0.4H), each beam pocket is treated as a separate area, so a detector is required in each beam pocket. Source: NFPA 72 Ch. 17 beam ceiling rules."},
  {id:427, block:5, sec:"Detector Spacing & Placement", q:"For a beamed ceiling where beam depth is at least 10% of ceiling height but beam spacing is LESS than 40% of ceiling height, smoke detector spacing perpendicular to the beams is reduced to what?", opts:["No reduction","Twice the smooth-ceiling spacing","One-quarter the smooth-ceiling spacing","One-half the smooth-ceiling spacing"], correct:3, re:"When beams are deep but closely spaced (<0.4H), spacing measured perpendicular (at right angles) to the beams is reduced to one-half the smooth-ceiling value. Source: NFPA 72 Ch. 17 beam ceiling rules."},
  {id:428, block:5, sec:"Detector Spacing & Placement", q:"On a sloped (peaked) ceiling with rise greater than 1 in 8, the first row of detectors must be located where?", opts:["At the lowest point of the slope","Only at the eaves","Centered on each wall","At or within 36 in. of the peak (high point)"], correct:3, re:"NFPA 72 requires a row of detectors at or within 36 in. (910 mm) of the peak of a sloped/peaked ceiling, measured horizontally from the peak. Source: NFPA 72 Ch. 17 sloped ceiling placement."},
  {id:429, block:5, sec:"Detector Spacing & Placement", q:"NFPA 72 (Annex A guidance) recommends that spot smoke detectors not be located closer than what distance to an air supply diffuser?", opts:["12 in.","24 in.","36 in.","60 in."], correct:2, re:"NFPA 72 Annex A recommends keeping spot smoke detectors out of direct airflow and not closer than 36 in. (910 mm) from an air supply diffuser to avoid diluting smoke. Source: NFPA 72 Annex A.17.7.4."},
  {id:430, block:5, sec:"Detector Spacing & Placement", q:"A rate-of-rise heat detector is designed to alarm when the air temperature rises faster than approximately which rate?", opts:["5 deg F per minute","10 deg F per minute","15 deg F per minute","50 deg F per minute"], correct:2, re:"Rate-of-rise heat detectors typically respond when temperature increases about 15 deg F (8.3 deg C) or more per minute. Source: NFPA 72 Ch. 17 heat detector descriptions / detector listings."},
  {id:431, block:5, sec:"Detector Spacing & Placement", q:"A combination fixed-temperature/rate-of-rise heat detector provides the benefit of which behavior?", opts:["It ignores slow temperature rises entirely","It detects smoke, not heat","It works only above 200 deg F","It responds to fast temperature rise AND to a fixed maximum temperature"], correct:3, re:"Combination detectors trip on a rapid rate of rise and also on reaching a fixed set-point temperature, covering both fast and slow-developing fires. Source: NFPA 72 Ch. 17 heat detector types."},
  {id:432, block:5, sec:"Detector Spacing & Placement", q:"For a level ceiling 12 ft high or less, a beam projecting less than 4 in. (less than 10% of ceiling height) is treated how for smoke detector spacing?", opts:["Requires detectors in every pocket","Prohibits ceiling-mounted detectors","Requires one-quarter spacing","As a smooth ceiling (no spacing reduction)"], correct:3, re:"A shallow beam (<10% of ceiling height, e.g., <~4 in. on a 12 ft ceiling) has no effect on smoke detector spacing; the ceiling is treated as smooth. Source: NFPA 72 Ch. 17 beam ceiling rules."},
  {id:433, block:5, sec:"Detector Spacing & Placement", q:"What is the primary purpose of a duct smoke detector installed in an HVAC system?", opts:["To serve as the building's primary area smoke detection","To replace area heat detectors","To measure air temperature only","To detect smoke in the airstream and shut down the air handler to limit smoke spread"], correct:3, re:"NFPA 72 / NFPA 90A duct smoke detectors detect smoke in supply/return air and initiate fan shutdown or damper control; they do not substitute for required area (open-area) detection. Source: NFPA 72 Ch. 17 and NFPA 90A."},
  {id:434, block:5, sec:"Detector Spacing & Placement", q:"When using the heat-detector ceiling-height correction, NFPA 72 generally limits the reduced spacing so it is not less than what fraction of the ceiling height?", opts:["0.2 times the ceiling height","1.0 times the ceiling height","0.7 times the ceiling height","0.4 times the ceiling height"], correct:3, re:"After applying height correction, heat detector spacing need not be reduced below 0.4 times the ceiling height per NFPA 72 guidance. Source: NFPA 72 Ch. 17 heat detector height-correction provisions."},
  {id:435, block:5, sec:"Plans, Symbols & Documentation", q:"A fire alarm riser diagram primarily shows which of the following?", opts:["The exact physical floor location of every device","The architectural reflected ceiling plan","Only the electrical panel schedule","The system's vertical arrangement and interconnection of circuits/devices floor to floor"], correct:3, re:"A riser diagram is a schematic showing the system's vertical layout: control unit, circuits, devices, and interconnections across floors/areas (not exact physical placement). Source: NFPA 72 documentation / shop drawing requirements."},
  {id:436, block:5, sec:"Plans, Symbols & Documentation", q:"Which document is completed and provided at the time of system acceptance to certify the installation meets the approved plans and NFPA 72?", opts:["Record of Completion","Building permit","Architectural floor plan","Manufacturer data sheet"], correct:0, re:"The NFPA 72 Record of Completion is executed at acceptance to document that the system was installed and tested per the approved design and the Code. Source: NFPA 72 Ch. 7 documentation."},
  {id:437, block:5, sec:"Plans, Symbols & Documentation", q:"The 'sequence of operation' (input/output) matrix in fire alarm documentation describes what?", opts:["The wire colors used","The conduit fill schedule","The battery calculation only","The cause-and-effect relationship between inputs (initiating events) and outputs (system responses)"], correct:3, re:"The sequence of operation (cause-and-effect / input-output matrix) defines what each input does and which outputs result, and is required documentation for design and testing. Source: NFPA 72 Ch. 7 documentation."},
  {id:438, block:5, sec:"Plans, Symbols & Documentation", q:"'As-built' (record) drawings provided after installation must reflect what?", opts:["The original design intent only","The manufacturer's generic catalog layout","Future expansion only","The system as actually installed, including field changes"], correct:3, re:"As-built/record drawings document the system as actually installed, incorporating all field modifications, and are required to be provided to the owner. Source: NFPA 72 Ch. 7 documentation requirements."},
  {id:439, block:5, sec:"Plans, Symbols & Documentation", q:"Battery (standby power) calculations submitted with fire alarm plans are used to verify what?", opts:["The conduit size","The detector spacing","The audibility in dBA","That the secondary supply can carry standby load for the required hours plus alarm load"], correct:3, re:"Battery calculations demonstrate the secondary power source can support quiescent load for the required standby period (e.g., 24 h) and then the alarm load (e.g., 5 min). Source: NFPA 72 power supply / documentation."},
  {id:440, block:5, sec:"Plans, Symbols & Documentation", q:"Voltage-drop calculations for a notification appliance circuit ensure what?", opts:["That detectors are spaced 30 ft apart","That the cable is plenum-rated","That the panel has a battery","That the last appliance on the circuit still receives at least its listed minimum operating voltage"], correct:3, re:"Voltage-drop calculations confirm the end-of-line appliance receives at least its UL-listed minimum operating voltage under worst-case conditions. Source: NFPA 72 NAC design / documentation practice."},
  {id:441, block:5, sec:"Plans, Symbols & Documentation", q:"On fire alarm drawings, a solid triangle or similar standardized symbol set is drawn from which reference?", opts:["NFPA 13 sprinkler symbols","ASHRAE ductwork symbols","NEC raceway symbols","NFPA 170 fire safety symbols"], correct:3, re:"Fire alarm device symbols on plans follow NFPA 170, Standard for Fire Safety and Emergency Symbols, unless other symbols are accepted by the AHJ. Source: NFPA 170 referenced by NFPA 72."},
  {id:442, block:5, sec:"Plans, Symbols & Documentation", q:"Which item is NOT typically part of a complete fire alarm shop drawing submittal?", opts:["Floor plans showing device locations","Riser diagram","Sequence of operation","The building's property tax assessment"], correct:3, re:"Submittals include floor plans, riser diagram, sequence of operation, point-to-point wiring, battery/voltage-drop calcs and cut sheets; a tax assessment is unrelated. Source: NFPA 72 Ch. 7 documentation."},
  {id:443, block:5, sec:"Plans, Symbols & Documentation", q:"A point-to-point wiring diagram is used primarily to show what?", opts:["The exact terminal connections and field wiring between devices and the control unit","The architectural elevations","The HVAC duct routing","The fire pump curve"], correct:0, re:"Point-to-point wiring diagrams show terminal-by-terminal connections of conductors between the control unit, modules, and field devices, supporting installation and troubleshooting. Source: NFPA 72 Ch. 7 documentation."},
  {id:444, block:5, sec:"Plans, Symbols & Documentation", q:"Per NFPA 72, the owner must keep a permanent copy of record documentation in what location?", opts:["Only at the contractor's office","Only with the manufacturer","Only with the AHJ","At the protected premises (e.g., in a documentation cabinet) or other approved location"], correct:3, re:"NFPA 72 requires record (as-built) documentation be maintained for the life of the system at the protected premises or an approved location, often in a documentation cabinet at the FACU. Source: NFPA 72 Ch. 7."},
  {id:445, block:5, sec:"Plans, Symbols & Documentation", q:"Before acceptance testing, NFPA 72 requires the installing contractor to provide what assurance about the installation?", opts:["A verbal confirmation only","Only the warranty card","A copy of the city ordinance","Completed/executed documentation including a pre-test certification that 100% of the system was installed and pre-tested"], correct:3, re:"The installer provides completed documentation and a statement that the system was installed and 100% tested by the installer before the acceptance (AHJ) test. Source: NFPA 72 Ch. 14 / Ch. 7 acceptance documentation."},
  {id:446, block:5, sec:"Plans, Symbols & Documentation", q:"A 'matrix of operations' must be verified against what during acceptance testing?", opts:["The actual programmed system response for each input","The architect's color scheme","The conduit paint color","The fire extinguisher locations"], correct:0, re:"Acceptance testing confirms the installed/programmed cause-and-effect matches the approved sequence of operation (matrix). Source: NFPA 72 Ch. 14 acceptance testing."},
  {id:447, block:5, sec:"Plans, Symbols & Documentation", q:"Which color is required by NFPA/NEC for identifying the dedicated branch-circuit disconnect that powers a fire alarm control unit?", opts:["Blue","Green","Red","Yellow"], correct:2, re:"NEC 760.121/695-style identification requires the fire alarm branch-circuit overcurrent device/disconnect be marked in red and labeled 'FIRE ALARM CIRCUIT.' Source: NEC Article 760 power source marking."},
  {id:448, block:5, sec:"Plans, Symbols & Documentation", q:"What does a 'zone' represent on a conventional fire alarm system plan?", opts:["A single device address","The conduit run only","The battery compartment","A defined area served by a circuit, used to annunciate the general location of an event"], correct:3, re:"A zone is a defined building area (often a circuit) used to indicate the general origin of an alarm/supervisory/trouble condition at the annunciator. Source: NFPA 72 zoning/annunciation requirements."},
  {id:449, block:5, sec:"Plans, Symbols & Documentation", q:"For an addressable system, each device's identity on the plan corresponds to what?", opts:["A unique address/point reported individually to the control unit","A shared zone with no individual identity","A hard-wired bell only","A battery terminal"], correct:0, re:"Addressable devices each report a unique address/point, so the control unit and plans identify the specific device location rather than just a zone. Source: NFPA 72 addressable system operation."},
  {id:450, block:5, sec:"Plans, Symbols & Documentation", q:"The fire alarm 'record of completion' must be signed by which parties?", opts:["Only the building owner","Only the architect","Only the equipment supplier","Representatives of the installing contractor and the system owner/AHJ as applicable"], correct:3, re:"The Record of Completion is signed by the installing contractor's representative and the owner's representative (and the AHJ when required) to certify proper installation. Source: NFPA 72 Ch. 7 Record of Completion."},
  {id:451, block:5, sec:"Plans, Symbols & Documentation", q:"Operation and maintenance (O&M) manuals turned over to the owner should include what?", opts:["Only the sales invoice","Manufacturer data, programming/configuration records, and ITM instructions for the installed equipment","The architect's resume","The HVAC balancing report"], correct:1, re:"O&M turnover includes manufacturer literature, as-programmed configuration/software records, and inspection-testing-maintenance instructions so the owner can maintain the system. Source: NFPA 72 Ch. 7 owner documentation."},
  {id:452, block:5, sec:"Acceptance Testing", q:"An acceptance test of a new fire alarm system verifies what?", opts:["Only that the panel powers on","That the entire installed system operates per the approved design and NFPA 72 before being placed in service","Only the battery voltage","The building's occupancy load"], correct:1, re:"Acceptance (initial) testing confirms 100% of the installed system functions in accordance with the approved drawings, sequence of operation, and NFPA 72 prior to being placed in service. Source: NFPA 72 Ch. 14 acceptance testing."},
  {id:453, block:5, sec:"Acceptance Testing", q:"During acceptance testing of initiating devices, what percentage of devices must be tested?", opts:["10%","25%","50%","100%"], correct:3, re:"At initial acceptance, 100% of initiating devices, notification appliances, and functions must be tested. Source: NFPA 72 Ch. 14 acceptance testing scope."},
  {id:454, block:5, sec:"Acceptance Testing", q:"Acceptance testing of a spot-type smoke detector must confirm smoke entry by using what?", opts:["A magnet only","Smoke or an aerosol listed/approved for the detector that enters the sensing chamber","A multimeter reading","Visual inspection only"], correct:1, re:"Smoke detectors must be tested with smoke or a listed aerosol that actually enters the sensing chamber to verify response, not merely a magnet (which only tests the alarm circuit/relay). Source: NFPA 72 Ch. 14 detector test methods."},
  {id:455, block:5, sec:"Acceptance Testing", q:"Using a test magnet on an addressable smoke detector during acceptance testing primarily verifies what?", opts:["That smoke actually enters the chamber","The detector's electronics/alarm signaling and addressing, but NOT smoke entry","The detector's sensitivity drift","The ceiling height"], correct:1, re:"A magnet test checks alarm signaling/addressing (functional response) but does not confirm smoke can enter the chamber; smoke/aerosol entry must also be verified. Source: NFPA 72 Ch. 14 test methods."},
  {id:456, block:5, sec:"Acceptance Testing", q:"During acceptance, audible notification appliance coverage is verified by measuring what?", opts:["Frequency in hertz only","Sound pressure level (dBA) to confirm required audibility above ambient","Battery amp-hours","Conductor resistance"], correct:1, re:"Audibility is verified by measuring sound pressure level (dBA) to confirm the required margin above ambient (e.g., 15 dBA public mode). Source: NFPA 72 Ch. 14 / audibility requirements."},
  {id:457, block:5, sec:"Acceptance Testing", q:"Acceptance testing of strobes (visible notification) verifies conformance with what listing parameter?", opts:["Candela (cd) rating and synchronization where required","Decibel rating","Battery chemistry","Smoke obscuration"], correct:0, re:"Visible appliances are verified for proper candela output/placement and, where required, synchronization to prevent seizure-inducing flash rates. Source: NFPA 72 Ch. 14 and visible signaling requirements."},
  {id:458, block:5, sec:"Acceptance Testing", q:"As part of acceptance testing, monitored circuit integrity is checked by doing what?", opts:["Painting the conduit","Introducing faults (open, ground) and confirming the panel reports the correct trouble condition","Disconnecting the battery permanently","Removing all detectors"], correct:1, re:"Circuit supervision is verified by introducing open/ground faults and confirming proper trouble annunciation, demonstrating monitoring for integrity. Source: NFPA 72 Ch. 14 acceptance testing of wiring."},
  {id:459, block:5, sec:"Acceptance Testing", q:"During acceptance testing, the secondary power supply is tested by doing what?", opts:["Measuring ambient light","Disconnecting primary (AC) power and verifying the system operates on standby power for the required duration","Replacing the panel","Counting the detectors"], correct:1, re:"Secondary power is verified by removing primary power and confirming the system operates on battery for the standby period and then carries alarm load. Source: NFPA 72 Ch. 14 power supply testing."},
  {id:460, block:5, sec:"Acceptance Testing", q:"Acceptance testing must verify off-premises signal transmission by confirming what?", opts:["The supervising station receives alarm, supervisory, and trouble signals correctly","The bell is red","The battery is charged to 12 V","The detector is 30 ft from the wall"], correct:0, re:"Where a system transmits off-premises, acceptance testing confirms the supervising station correctly receives and identifies alarm, supervisory, and trouble signals. Source: NFPA 72 Ch. 14 / supervising station testing."},
  {id:461, block:5, sec:"Acceptance Testing", q:"During acceptance testing of an emergency voice/alarm communication system (EVACS), intelligibility is evaluated to ensure what?", opts:["The message volume exceeds 120 dBA everywhere","Voice messages are understandable in the acoustically distinguishable spaces","The strobes flash faster","The battery lasts 72 hours"], correct:1, re:"EVACS acceptance includes verifying speech intelligibility in required acoustically distinguishable spaces, not merely loudness. Source: NFPA 72 Ch. 14 and Ch. 18 intelligibility requirements."},
  {id:462, block:5, sec:"Acceptance Testing", q:"Who typically witnesses the final acceptance test of a fire alarm system?", opts:["The authority having jurisdiction (AHJ) and owner's representative","The HVAC contractor only","The landscaper","No one is required"], correct:0, re:"The AHJ (and the owner's representative) typically witnesses acceptance testing to confirm code compliance before the system is approved for service. Source: NFPA 72 Ch. 14 acceptance process."},
  {id:463, block:5, sec:"Acceptance Testing", q:"When fire alarm initiation causes HVAC fan shutdown, acceptance testing must verify what?", opts:["The fans actually shut down (or perform the programmed action) on the correct input","The duct color","The thermostat setpoint","The filter size"], correct:0, re:"Interface functions such as fan shutdown, damper closure, door release, and elevator recall must be verified to operate per the sequence of operation during acceptance. Source: NFPA 72 Ch. 14 interface testing."},
  {id:464, block:5, sec:"Acceptance Testing", q:"For fire alarm initiation of elevator recall (Phase I), acceptance testing must confirm what?", opts:["Elevators recall to the designated/alternate level on the correct detector activation","The elevator cab is repainted","The hoistway smoke detector is removed","The car capacity increases"], correct:0, re:"Acceptance testing verifies elevator Phase I recall to the designated or alternate level upon activation of the proper lobby/machine room/hoistway detector per NFPA 72 and ASME A17.1. Source: NFPA 72 Ch. 21 / Ch. 14 interface testing."},
  {id:465, block:5, sec:"Acceptance Testing", q:"Acceptance testing of waterflow alarm initiation from a sprinkler system verifies what?", opts:["The waterflow switch initiates an alarm within the allowed retard time","The sprinkler pipe color","The water pressure exceeds 300 psi","The detector spacing is 30 ft"], correct:0, re:"Waterflow switches must initiate an alarm not more than 90 seconds after flow begins (within retard limits); acceptance verifies correct initiation and annunciation. Source: NFPA 72 Ch. 14 / NFPA 13 interface."},
  {id:466, block:5, sec:"Acceptance Testing", q:"If an acceptance test reveals a deficiency, what is the proper action under NFPA 72?", opts:["Place the system in service anyway","Document the deficiency, correct it, and retest the affected function before final approval","Ignore minor deficiencies","Remove the affected devices permanently"], correct:1, re:"Deficiencies found during testing must be documented, corrected, and the affected functions retested before the system can be accepted/placed in service. Source: NFPA 72 Ch. 14 acceptance/deficiency handling."},
  {id:467, block:5, sec:"Acceptance Testing", q:"A reacceptance test is required after which event?", opts:["Routine annual inspection with no changes","Adding, relocating, or modifying initiating devices, notification appliances, or programming","Cleaning the exterior of the panel","Changing the wall paint near a device"], correct:1, re:"Reacceptance testing is required when devices/appliances are added, deleted, relocated, or when software/programming affecting operation changes, to confirm correct operation and no adverse impact. Source: NFPA 72 Ch. 14 reacceptance."},
  {id:468, block:5, sec:"Acceptance Testing", q:"During acceptance, manual fire alarm boxes (pull stations) are tested by doing what?", opts:["Measuring their height only","Operating each station and confirming the correct alarm signal and identification","Painting them red","Removing the cover only"], correct:1, re:"Each manual pull station is operated to verify it initiates the correct alarm and is properly identified/annunciated. Source: NFPA 72 Ch. 14 acceptance testing of manual stations."},
  {id:469, block:5, sec:"Inspection, Testing & Maintenance", q:"Per NFPA 72 Chapter 14, spot-type smoke detectors must be functionally tested at what minimum frequency?", opts:["Monthly","Quarterly","Annually","Every 5 years"], correct:2, re:"NFPA 72 Ch. 14 requires functional testing of smoke detectors at least annually (in addition to semiannual visual inspection). Source: NFPA 72 Table 14.4.3.2."},
  {id:470, block:5, sec:"Inspection, Testing & Maintenance", q:"Smoke detector SENSITIVITY must first be tested within what time after installation, then at an alternate-year interval?", opts:["Within 6 months","Within 1 year","Within 2 years","Within 5 years"], correct:1, re:"NFPA 72 requires smoke detector sensitivity be tested within 1 year of installation, then every alternate year; intervals may be extended to 5 years if results stay in range. Source: NFPA 72 Ch. 14 sensitivity testing."},
  {id:471, block:5, sec:"Inspection, Testing & Maintenance", q:"After two successful smoke detector sensitivity tests showing readings within the listed range, the interval may be extended to a maximum of how long?", opts:["1 year","2 years","5 years","10 years"], correct:2, re:"If two consecutive sensitivity tests are within the listed/marked range, NFPA 72 allows extending the test interval to a maximum of 5 years. Source: NFPA 72 Ch. 14 sensitivity testing."},
  {id:472, block:5, sec:"Inspection, Testing & Maintenance", q:"A single- or multiple-station smoke ALARM must be replaced no later than how many years from its date of manufacture (unless the manufacturer states otherwise)?", opts:["5 years","10 years","15 years","20 years"], correct:1, re:"NFPA 72 requires smoke alarms be replaced within 10 years of the date of manufacture unless the manufacturer's instructions specify otherwise. Source: NFPA 72 Ch. 14 smoke alarm replacement."},
  {id:473, block:5, sec:"Inspection, Testing & Maintenance", q:"Sealed lead-acid (SLA) standby batteries used in fire alarm systems should be replaced at intervals not exceeding approximately how long?", opts:["1 year","4 years","10 years","15 years"], correct:1, re:"NFPA 72 indicates sealed lead-acid batteries be replaced when at about 80% of marked capacity, generally within ~4 years; manufacturers often recommend ~5 years. Source: NFPA 72 Ch. 14 battery maintenance."},
  {id:474, block:5, sec:"Inspection, Testing & Maintenance", q:"NFPA 72 requires a load (discharge) test of the secondary battery at what minimum frequency?", opts:["Weekly","Monthly","Annually","Every 5 years"], correct:2, re:"NFPA 72 Ch. 14 requires the battery to be load/discharge tested at least annually to confirm it can support system operation. Source: NFPA 72 Table 14.4.3.2 (storage batteries)."},
  {id:475, block:5, sec:"Inspection, Testing & Maintenance", q:"Initiating devices and notification appliances generally require VISUAL inspection at what minimum frequency under NFPA 72?", opts:["Weekly","Monthly","Semiannually","Every 5 years"], correct:2, re:"NFPA 72 Table 14.3.1 lists semiannual visual inspection for most initiating devices and notification appliances (physical condition/mounting). Source: NFPA 72 Table 14.3.1."},
  {id:476, block:5, sec:"Inspection, Testing & Maintenance", q:"Waterflow devices (e.g., waterflow switches) must be functionally tested at what minimum frequency per NFPA 72?", opts:["Annually","Semiannually","Quarterly","Every 5 years"], correct:2, re:"NFPA 72 requires functional testing of waterflow devices semiannually (and the supervisory/valve tamper devices semiannually as well). Source: NFPA 72 Ch. 14 (waterflow and supervisory device testing)."},
  {id:477, block:5, sec:"Inspection, Testing & Maintenance", q:"A heat detector that is restorable (non-destructive type) is functionally tested at what minimum frequency?", opts:["Monthly","Quarterly","Annually","Every 10 years"], correct:2, re:"Restorable heat detectors are functionally heat-tested at least annually; non-restorable types are not heat-tested but are checked/replaced per program. Source: NFPA 72 Table 14.4.3.2 (heat detectors)."},
  {id:478, block:5, sec:"Inspection, Testing & Maintenance", q:"Which heat detector type must NOT be tested by applying heat (to avoid destroying it)?", opts:["Rate-of-rise pneumatic","Restorable fixed-temperature electronic","Non-restorable fixed-temperature (fusible/eutectic) type","Combination electronic detector"], correct:2, re:"Non-restorable fixed-temperature detectors (e.g., fusible-link/eutectic) are destroyed if operated, so they are not heat-tested; alternative methods or replacement on a schedule are used. Source: NFPA 72 Ch. 14 heat detector testing."},
  {id:479, block:5, sec:"Inspection, Testing & Maintenance", q:"Control unit trouble signals must be tested at what minimum frequency under NFPA 72?", opts:["Annually","Every 5 years","Only at acceptance","Every 10 years"], correct:0, re:"NFPA 72 requires control unit functions, including trouble signals, to be tested at least annually. Source: NFPA 72 Table 14.4.3.2 (control equipment)."},
  {id:480, block:5, sec:"Inspection, Testing & Maintenance", q:"Duct smoke detectors must be tested to verify what in addition to alarm response?", opts:["Air sampling/airflow is adequate so smoke can reach the sensing chamber","The duct is painted","The fan is the correct brand","The filter is new"], correct:0, re:"Duct detector testing verifies the sampling tube/airflow allows smoke to enter the sensing chamber and that the unit alarms and performs its control function (e.g., fan shutdown). Source: NFPA 72 Ch. 14 duct detector testing."},
  {id:481, block:5, sec:"Inspection, Testing & Maintenance", q:"Records of inspection, testing, and maintenance must be retained for at least how long per NFPA 72?", opts:["6 months","1 year (until the next test) or as required by the AHJ","Indefinitely with no minimum","Only until the next day"], correct:1, re:"NFPA 72 requires ITM records be retained at least until the next test/inspection and for a period acceptable to the AHJ (commonly one test cycle or longer). Source: NFPA 72 Ch. 14 records retention."},
  {id:482, block:5, sec:"Inspection, Testing & Maintenance", q:"Before disabling part of a fire alarm system for service (an 'impairment'), NFPA 72 best practice requires what?", opts:["Notifying the AHJ/owner and providing a fire watch or other approved measures as needed","Nothing; just disable it","Removing all batteries","Cutting power to the building"], correct:0, re:"Out-of-service/impairment procedures require notifying the owner/AHJ and monitoring/fire-watch or other approved measures while protection is impaired. Source: NFPA 72 Ch. 10/14 impairment provisions."},
  {id:483, block:5, sec:"Inspection, Testing & Maintenance", q:"Manual fire alarm boxes (pull stations) must be functionally tested at what minimum frequency?", opts:["Weekly","Monthly","Annually","Every 10 years"], correct:2, re:"NFPA 72 Table 14.4.3.2 requires manual pull stations to be functionally tested at least annually. Source: NFPA 72 Ch. 14 manual station testing."},
  {id:484, block:5, sec:"Inspection, Testing & Maintenance", q:"Audible and visible notification appliances must be functionally tested at what minimum frequency?", opts:["Annually","Every 5 years","Only at acceptance","Every 10 years"], correct:0, re:"NFPA 72 requires notification appliances (horns, strobes, speakers) to be functionally tested at least annually. Source: NFPA 72 Table 14.4.3.2 (notification appliances)."},
  {id:485, block:5, sec:"Inspection, Testing & Maintenance", q:"A primary purpose of routine maintenance (e.g., cleaning) of smoke detectors is to do what?", opts:["Change the device color","Keep the detector within its listed sensitivity range and reduce unwanted alarms","Increase the candela output","Lengthen the conduit"], correct:1, re:"Cleaning/maintenance keeps detectors operating within their listed sensitivity range, preserving response and minimizing nuisance alarms from dust contamination. Source: NFPA 72 Ch. 14 maintenance provisions."},
  {id:486, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Which NEC article specifically covers the installation of fire alarm system wiring?", opts:["Article 250","Article 700","Article 760","Article 800"], correct:2, re:"NEC Article 760 covers the installation of wiring and equipment of fire alarm systems, including power-limited (PLFA) and non-power-limited (NPLFA) circuits. Source: NEC Article 760 scope (760.1)."},
  {id:487, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"In NEC Article 760, the cable designation 'FPL' refers to what?", opts:["Power-limited fire alarm cable, general purpose","Riser-rated power-limited cable","Plenum-rated power-limited cable","Non-power-limited fire alarm cable"], correct:0, re:"FPL is power-limited fire alarm general-purpose cable; the family is FPLP (plenum), FPLR (riser), and FPL (general). Source: NEC 760.179 / Table 760.154 cable types."},
  {id:488, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Which power-limited fire alarm cable is required for installation in ducts, plenums, and other spaces used for environmental air?", opts:["FPL","FPLR","FPLP","CL2"], correct:2, re:"Type FPLP (plenum) is required in ducts, plenums, and environmental air-handling spaces because it meets the stringent flame-spread/low-smoke (plenum) test. Source: NEC 760.154 / 760.179 plenum cable."},
  {id:489, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Which power-limited fire alarm cable is required for vertical runs in a shaft or from floor to floor (riser)?", opts:["FPL","FPLR","CL2X","NPLF"], correct:1, re:"Type FPLR (riser) is required for runs penetrating more than one floor or in vertical shafts; FPLP may be substituted. Source: NEC 760.154 / 760.179 riser cable."},
  {id:490, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"In the NEC 760 power-limited cable substitution hierarchy, which substitution is PERMITTED?", opts:["FPL used in place of FPLP","FPLR used in place of FPLP in a plenum","FPLP used in place of FPLR or FPL","FPL used in place of FPLR in a riser"], correct:2, re:"The higher-rated cable may substitute for lower: FPLP may replace FPLR and FPL; FPLR may replace FPL; the reverse is not permitted. Source: NEC Table 760.154 cable substitutions."},
  {id:491, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"What does 'NPLFA' designate in NEC Article 760?", opts:["Non-power-limited fire alarm circuit","Power-limited fire alarm circuit","Plenum communications cable","A grounding electrode conductor"], correct:0, re:"NPLFA is a non-power-limited fire alarm circuit; its power output is not inherently limited and it may operate at higher voltage (up to 600 V). Source: NEC Article 760 Part III (NPLFA)."},
  {id:492, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"A power-limited fire alarm (PLFA) circuit derives its power-limited characteristic from what?", opts:["The conductor color","A listed power supply that limits voltage and current per the Code","The conduit material","The number of detectors"], correct:1, re:"PLFA circuits are supplied by a listed power source that limits voltage and current (e.g., per the power-source tables), allowing reduced wiring methods. Source: NEC 760.121 / Part III PLFA power source."},
  {id:493, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Where not in a raceway or otherwise separated, power-limited fire alarm conductors must be separated from electric light, power, and Class 1 conductors by at least what distance?", opts:["1/2 in.","1 in.","2 in.","6 in."], correct:2, re:"NEC 760.136 generally requires at least 2 in. (50 mm) separation between PLFA conductors and conductors of light, power, Class 1, or NPLFA circuits unless separated by a barrier or in a raceway. Source: NEC 760.136."},
  {id:494, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"NEC 760.124 requires fire alarm circuits and equipment to be identified how, to prevent accidental interference during servicing?", opts:["With no marking","Durably marked/identified at terminal and junction locations as fire alarm circuits","Only by memory of the installer","With a fire extinguisher symbol"], correct:1, re:"NEC 760.124 requires fire alarm circuits be identified at terminal and junction locations with a label/marking to prevent unintentional interference during testing/servicing. Source: NEC 760.124."},
  {id:495, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"The dedicated branch circuit supplying a fire alarm control unit must have its overcurrent device identified how?", opts:["Painted blue and unlabeled","Marked in red and labeled 'FIRE ALARM CIRCUIT,' accessible only to qualified personnel","Left unmarked","Labeled 'SPARE'"], correct:1, re:"NEC 760.121(B) requires the fire alarm branch-circuit overcurrent device to be marked in red, labeled 'FIRE ALARM CIRCUIT,' and accessible only to qualified personnel. Source: NEC 760.121(B)."},
  {id:496, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Power-limited fire alarm circuit conductors are permitted to be smaller than the typical minimum only under what NEC condition?", opts:["Never under any condition","26 AWG is permitted where terminated/spliced on listed equipment suitable for that size","Only if painted red","Only above 600 V"], correct:1, re:"NEC 760.142/760.179 permit 26 AWG PLFA conductors only where spliced/terminated with connectors or equipment listed as suitable for 26 AWG (otherwise 24 AWG minimum). Source: NEC 760.179 conductor sizing."},
  {id:497, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Within a single enclosure, PLFA conductors are permitted to be in the same raceway/enclosure with power conductors only if which condition is met?", opts:["They are the same color","A barrier separates them, or the power conductors connect solely to the same fire alarm equipment","They use larger wire","The voltage is over 600 V"], correct:1, re:"NEC 760.136 allows PLFA with power conductors in the same enclosure only when separated by a barrier, or where the electric light/power conductors are introduced solely to connect to the same fire alarm equipment. Source: NEC 760.136(C)/(D)."},
  {id:498, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Abandoned fire alarm cable (not terminated at equipment and not identified for future use) must be handled how under the NEC?", opts:["Left in place permanently","Removed (the accessible portion)","Painted over","Energized continuously"], correct:1, re:"NEC requires the accessible portion of abandoned fire alarm cable to be removed to reduce fire/smoke fuel load, unless tagged for future use. Source: NEC 760.25 abandoned cable removal."},
  {id:499, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Non-power-limited fire alarm (NPLFA) circuit conductors generally have what minimum size requirement under the NEC?", opts:["26 AWG","18 AWG (with 16 AWG and larger also permitted)","10 AWG","4 AWG"], correct:1, re:"NEC 760.49 specifies NPLFA conductors of 18 AWG and 16 AWG are permitted for limited currents, with larger sizes per ampacity; PLFA differs. Source: NEC 760.49 NPLFA conductor sizing."},
  {id:500, block:5, sec:"NEC Article 760 & Circuit Wiring", q:"Which statement about NEC 760 cable listings is correct?", opts:["A general-purpose FPL cable may always be used in a plenum","Substitutions only go from higher-rated to lower-rated applications (plenum > riser > general)","Riser cable (FPLR) may be used in a plenum","Cable type does not matter indoors"], correct:1, re:"NEC Table 760.154 permits substituting only a higher-rated cable for a lower-rated use (plenum FPLP for riser/general; riser FPLR for general); lower-rated cable cannot be used in a more demanding location. Source: NEC Table 760.154."}
];
